INSERT INTO exercises (name_es, name_en, muscle_group_id, measurement_type, equipment, instructions, is_system)
VALUES
    ('Press de banca con barra', 'Barbell Bench Press', 3, 'weight_reps', 'barbell', '{"es":{"setup":"Acuéstate en el banco con los ojos debajo de la barra. Agarra la barra algo más ancho que los hombros, pies firmes en el suelo y escápulas retraídas.","execution":"Desenganchá la barra y bajala controladamente hasta el pecho medio. Empujá hacia arriba y ligeramente hacia atrás hasta bloquear los codos.","cues":["Apretá las escápulas contra el banco","Codos a 45° del torso","Empujá el suelo con los pies"],"mistakes":["Rebotar la barra en el pecho","Levantar el trasero del banco","Codos abiertos a 90°"]},"en":{"setup":"Lie on the bench with eyes under the bar. Grip slightly wider than shoulder width, feet flat on the floor, shoulder blades retracted and pinched.","execution":"Unrack the bar and lower it under control to mid-chest. Press up and slightly back until elbows lock out.","cues":["Squeeze shoulder blades into the bench","Elbows at 45° from torso","Drive feet into the floor"],"mistakes":["Bouncing the bar off chest","Lifting hips off the bench","Flaring elbows to 90°"]}}'::jsonb, true),
    ('Press de banca inclinado con barra', 'Incline Barbell Bench Press', 3, 'weight_reps', 'barbell', '{"es":{"setup":"Ajustá el banco a 30-45°. Acuéstate con los pies firmes, escápulas retraídas y agarre algo más ancho que los hombros.","execution":"Desenganchá la barra y bajala hasta la parte alta del pecho (clavículas). Empujá hacia arriba hasta extender los brazos completamente.","cues":["Pecho hacia arriba, arco en la espalda alta","Bajá hasta las clavículas","No dejes que los codos se abran demasiado"],"mistakes":["Usar demasiada inclinación (>45° se vuelve press de hombros)","Dejar caer la barra sin control","Perder la retracción escapular"]},"en":{"setup":"Set the bench to 30-45°. Lie back with feet flat, shoulder blades retracted, grip slightly wider than shoulders.","execution":"Unrack and lower the bar to upper chest (collarbone level). Press up until arms are fully extended.","cues":["Chest up, arch in upper back","Lower to collarbone area","Keep elbows at roughly 45°"],"mistakes":["Too steep incline (>45° becomes shoulder press)","Dropping the bar without control","Losing shoulder blade retraction"]}}'::jsonb, true),
    ('Press de banca declinado con barra', 'Decline Barbell Bench Press', 3, 'weight_reps', 'barbell', '{"es":{"setup":"Ajustá el banco en declive (-15 a -30°). Asegurá las piernas en los soportes. Agarre algo más ancho que los hombros.","execution":"Desenganchá la barra y bajala hasta la parte baja del pecho. Empujá hacia arriba hasta bloquear los codos.","cues":["Escápulas juntas y abajo","Bajá hacia la parte baja del esternón","Movimiento controlado en todo momento"],"mistakes":["Usar demasiado decline (riesgo de congestión en la cabeza)","Dejar que la barra se desvíe hacia la cara","No asegurar bien las piernas"]},"en":{"setup":"Set bench to decline (-15 to -30°). Secure legs under pads. Grip slightly wider than shoulders.","execution":"Unrack and lower the bar to lower chest. Press up until elbows lock out.","cues":["Shoulder blades pinched and depressed","Lower to lower sternum","Controlled tempo throughout"],"mistakes":["Too steep a decline (blood rush to head)","Letting the bar drift toward face","Not securing legs properly"]}}'::jsonb, true),
    ('Press de banca con mancuernas', 'Dumbbell Bench Press', 3, 'weight_reps', 'dumbbell', '{"es":{"setup":"Sentate en el banco con una mancuerna en cada muslo. Acuéstate llevando las mancuernas al pecho con las rodillas. Pies firmes, escápulas retraídas.","execution":"Empujá las mancuernas hacia arriba hasta que los brazos estén extendidos. Bajá controladamente hasta que los codos queden a la altura del pecho o ligeramente por debajo.","cues":["Que las mancuernas no choquen arriba","Codos a 45°, no dejarlos caer","Apretá el pecho arriba"],"mistakes":["Bajar demasiado y forzar el hombro","No controlar la bajada","Arquear excesivamente la espalda baja"]},"en":{"setup":"Sit with a dumbbell on each thigh. Lie back, using knees to kick them into position at chest level. Feet flat, shoulder blades retracted.","execution":"Press dumbbells up until arms are extended. Lower under control until elbows are at chest height or slightly below.","cues":["Don''t clank dumbbells at the top","Elbows at 45°, don''t let them drop","Squeeze chest at the top"],"mistakes":["Going too deep and stressing shoulders","Losing control on the descent","Excessive lower back arch"]}}'::jsonb, true),
    ('Press inclinado con mancuernas', 'Incline Dumbbell Press', 3, 'weight_reps', 'dumbbell', '{"es":{"setup":"Banco a 30-45°. Llevá las mancuernas a posición con ayuda de las rodillas. Escápulas retraídas, pies firmes en el suelo.","execution":"Empujá las mancuernas hacia arriba y ligeramente hacia adentro. Bajá controladamente hasta sentir un estiramiento en el pecho alto.","cues":["Pecho bien abierto","Codos apuntando al suelo, no hacia atrás","Sentí el estiramiento abajo"],"mistakes":["Demasiada inclinación del banco","Mancuernas chocan agresivamente arriba","Perder tensión en el pecho al bajar"]},"en":{"setup":"Bench at 30-45°. Kick dumbbells into position with knees. Shoulder blades retracted, feet planted.","execution":"Press dumbbells up and slightly inward. Lower under control until you feel a stretch in the upper chest.","cues":["Keep chest open and proud","Elbows pointing down, not back","Feel the stretch at the bottom"],"mistakes":["Bench angle too steep","Aggressively clanking dumbbells at top","Losing chest tension on the way down"]}}'::jsonb, true),
    ('Press declinado con mancuernas', 'Decline Dumbbell Press', 3, 'weight_reps', 'dumbbell', '{"es":{"setup":"Banco en declive, piernas aseguradas. Llevá las mancuernas al pecho desde los muslos. Escápulas retraídas.","execution":"Empujá las mancuernas hacia arriba hasta extender los brazos. Bajá hasta que los codos estén a la altura del torso.","cues":["Controlá todo el recorrido","Apretá el pecho abajo del esternón","Codos a 45°"],"mistakes":["Dejar caer las mancuernas sin control","No asegurar bien las piernas","Usar impulso en lugar de fuerza"]},"en":{"setup":"Decline bench with legs secured. Bring dumbbells to chest from thighs. Shoulder blades retracted.","execution":"Press dumbbells up until arms are extended. Lower until elbows are at torso height.","cues":["Control the full range of motion","Squeeze lower chest","Elbows at 45°"],"mistakes":["Dropping dumbbells without control","Legs not properly secured","Using momentum instead of muscle"]}}'::jsonb, true),
    ('Press de banca con agarre cerrado', 'Close-Grip Bench Press', 3, 'weight_reps', 'barbell', '{"es":{"setup":"Acuéstate en el banco con agarre al ancho de los hombros o ligeramente más cerrado. Escápulas retraídas, pies firmes.","execution":"Desenganchá la barra y bajala hasta la parte baja del pecho manteniendo los codos pegados al torso. Empujá hacia arriba hasta bloquear.","cues":["Codos pegados al cuerpo","Bajá hacia el esternón bajo","No cerrar tanto que duelan las muñecas"],"mistakes":["Agarre demasiado cerrado (daña muñecas)","Abrir los codos como en press normal","Rebotar la barra en el pecho"]},"en":{"setup":"Lie on the bench with hands at shoulder width or slightly narrower. Shoulder blades retracted, feet flat.","execution":"Unrack and lower the bar to lower chest keeping elbows tucked close to your body. Press up to lockout.","cues":["Keep elbows tucked","Lower to lower sternum","Don''t go so narrow it hurts wrists"],"mistakes":["Grip too narrow (wrist strain)","Flaring elbows like a regular bench","Bouncing off chest"]}}'::jsonb, true),
    ('Press de banca en máquina Smith', 'Smith Machine Bench Press', 3, 'weight_reps', 'smith_machine', '{"es":{"setup":"Posicioná el banco plano dentro de la Smith con la barra alineada al pecho medio. Escápulas retraídas, pies firmes.","execution":"Desenganchá la barra, bajá controladamente hasta el pecho. Empujá hasta extender los brazos y girá para enganchar.","cues":["Alineá bien el banco antes de empezar","Mismo patrón de codos a 45°","Controlá la bajada, la máquina no frena por vos"],"mistakes":["Mala alineación del banco con la barra","Confiar demasiado en la guía y perder la técnica","No bloquear bien la barra al terminar"]},"en":{"setup":"Position a flat bench inside the Smith machine with the bar aligned to mid-chest. Shoulder blades retracted, feet flat.","execution":"Unrack the bar, lower under control to chest. Press up to full extension and twist to re-rack.","cues":["Align the bench properly before starting","Same 45° elbow angle as free bench","Control the descent—the machine won''t brake for you"],"mistakes":["Poor bench alignment with the bar path","Over-relying on the guided path and losing form","Not locking the bar properly when done"]}}'::jsonb, true),
    ('Press inclinado en máquina Smith', 'Smith Machine Incline Press', 3, 'weight_reps', 'smith_machine', '{"es":{"setup":"Banco a 30-45° dentro de la Smith, barra alineada con la parte alta del pecho. Escápulas retraídas, pies firmes.","execution":"Desenganchá y bajá la barra a las clavículas. Empujá hasta extender completamente.","cues":["Pecho arriba, buen arco torácico","Bajá a la zona de las clavículas","Movimiento fluido y controlado"],"mistakes":["Banco mal posicionado bajo la barra","Inclinación demasiado alta","Dejar que la barra caiga sin control"]},"en":{"setup":"Bench at 30-45° inside the Smith machine, bar aligned with upper chest. Shoulder blades retracted, feet flat.","execution":"Unrack and lower the bar to collarbone area. Press to full lockout.","cues":["Chest up, good thoracic arch","Lower to collarbone zone","Smooth, controlled movement"],"mistakes":["Bench poorly positioned under the bar","Incline too steep","Letting the bar drop without control"]}}'::jsonb, true),
    ('Press de pecho en máquina', 'Machine Chest Press', 3, 'weight_reps', 'machine', '{"es":{"setup":"Ajustá el asiento para que las manijas queden a la altura del pecho medio. Espalda apoyada, pies firmes en el suelo.","execution":"Empujá las manijas hacia adelante hasta extender los brazos sin bloquear violentamente. Volvé controladamente sintiendo el estiramiento.","cues":["Pecho abierto, hombros atrás","No bloquees violentamente los codos","Apretá el pecho en la contracción"],"mistakes":["Asiento demasiado alto o bajo","Despegar la espalda del respaldo","Usar impulso con el torso"]},"en":{"setup":"Adjust the seat so handles are at mid-chest height. Back flat against pad, feet planted on the floor.","execution":"Push handles forward until arms are extended without violent lockout. Return under control, feeling the stretch.","cues":["Chest open, shoulders back","Don''t slam into lockout","Squeeze the chest on contraction"],"mistakes":["Seat too high or low","Back coming off the pad","Using torso momentum"]}}'::jsonb, true),
    ('Press de pecho en máquina convergente', 'Converging Machine Chest Press', 3, 'weight_reps', 'machine', '{"es":{"setup":"Ajustá el asiento para que las manijas estén a la altura del pecho. Espalda apoyada, pies firmes.","execution":"Empujá las manijas hacia adelante y adentro (convergen). Volvé controladamente hasta sentir un buen estiramiento en el pecho.","cues":["Aprovechá la convergencia para apretar el pecho al final","Escápulas contra el respaldo","Fase excéntrica lenta"],"mistakes":["No aprovechar el recorrido convergente","Despegar la espalda al empujar","Ir demasiado rápido en la vuelta"]},"en":{"setup":"Adjust seat so handles are at chest height. Back against pad, feet flat.","execution":"Push handles forward and inward (they converge). Return under control until you feel a good chest stretch.","cues":["Use the converging path to squeeze at the top","Shoulder blades against the pad","Slow eccentric phase"],"mistakes":["Not taking advantage of the converging motion","Back lifting off the pad","Rushing the return phase"]}}'::jsonb, true),
    ('Aperturas con mancuernas', 'Dumbbell Fly', 3, 'weight_reps', 'dumbbell', '{"es":{"setup":"Acuéstate en banco plano con una mancuerna en cada mano, brazos extendidos arriba con los codos ligeramente flexionados.","execution":"Abrí los brazos en arco hasta sentir un estiramiento en el pecho. Volvé al centro apretando el pecho, como si abrazaras un árbol.","cues":["Codos ligeramente flexionados siempre","Movimiento en arco, no de press","Apretá el pecho arriba"],"mistakes":["Extender los codos completamente (riesgo de lesión)","Bajar demasiado y forzar el hombro","Convertirlo en un press (flexionar mucho los codos)"]},"en":{"setup":"Lie on a flat bench holding dumbbells above you with arms extended and elbows slightly bent.","execution":"Open arms in an arc until you feel a chest stretch. Bring them back together squeezing the chest, like hugging a tree.","cues":["Keep a slight bend in elbows throughout","Arc motion, not a press","Squeeze chest at the top"],"mistakes":["Fully extending elbows (injury risk)","Going too deep and straining shoulders","Turning it into a press (bending elbows too much)"]}}'::jsonb, true),
    ('Aperturas inclinadas con mancuernas', 'Incline Dumbbell Fly', 3, 'weight_reps', 'dumbbell', '{"es":{"setup":"Banco a 30-45°. Mancuernas arriba con codos ligeramente flexionados, palmas enfrentadas.","execution":"Abrí los brazos en arco bajando hasta sentir estiramiento en el pecho superior. Volvé apretando el pecho.","cues":["Mantené la flexión de codos constante","Sentí el estiramiento en el pecho alto","Movimiento lento y controlado"],"mistakes":["Dejar caer los brazos sin control","Cambiar el ángulo de los codos durante el movimiento","Peso excesivo que impide buen rango"]},"en":{"setup":"Bench at 30-45°. Dumbbells above with slightly bent elbows, palms facing each other.","execution":"Open arms in an arc until you feel a stretch in the upper chest. Return by squeezing the chest.","cues":["Maintain constant elbow bend","Feel the stretch in upper chest","Slow, controlled movement"],"mistakes":["Letting arms drop without control","Changing elbow angle during the movement","Too heavy—sacrificing range of motion"]}}'::jsonb, true),
    ('Aperturas declinadas con mancuernas', 'Decline Dumbbell Fly', 3, 'weight_reps', 'dumbbell', '{"es":{"setup":"Banco en declive con piernas aseguradas. Mancuernas arriba, codos ligeramente flexionados, palmas enfrentadas.","execution":"Abrí los brazos en arco hasta sentir estiramiento en la parte baja del pecho. Volvé juntando las mancuernas arriba.","cues":["Codos con flexión fija","Apretá la parte baja del pecho al cerrar","No dejes que la gravedad te gane"],"mistakes":["Perder el control en la fase excéntrica","Piernas mal aseguradas","Usar demasiado peso para este ejercicio de aislamiento"]},"en":{"setup":"Decline bench with legs secured. Dumbbells above, elbows slightly bent, palms facing.","execution":"Open arms in an arc until you feel a stretch in the lower chest. Return by bringing dumbbells together at top.","cues":["Fixed elbow bend throughout","Squeeze the lower chest when closing","Don''t let gravity win"],"mistakes":["Losing control on the eccentric","Legs not secured properly","Too heavy for an isolation exercise"]}}'::jsonb, true),
    ('Cruce de poleas alto', 'High Cable Crossover', 3, 'weight_reps', 'cable', '{"es":{"setup":"Poleas en posición alta. Parate al centro, un paso adelante, torso ligeramente inclinado. Agarra una manija con cada mano.","execution":"Con los codos ligeramente flexionados, llevá las manos hacia abajo y al centro en un arco. Apretá el pecho abajo y volvé controladamente.","cues":["Incliná el torso un poco hacia adelante","Cruzá las manos ligeramente abajo","Sentí el estiramiento al abrir"],"mistakes":["Usar los brazos en lugar del pecho","Cuerpo demasiado erguido","Mover el torso para generar impulso"]},"en":{"setup":"Cables set high. Stand centered, one step forward, torso slightly leaned forward. Grab a handle in each hand.","execution":"With slightly bent elbows, bring hands down and together in an arc. Squeeze the chest at the bottom and return under control.","cues":["Lean torso slightly forward","Cross hands slightly at the bottom","Feel the stretch when opening"],"mistakes":["Using arms instead of chest","Standing too upright","Swinging torso for momentum"]}}'::jsonb, true),
    ('Cruce de poleas bajo', 'Low Cable Crossover', 3, 'weight_reps', 'cable', '{"es":{"setup":"Poleas en posición baja. Parate al centro, un paso adelante. Agarra las manijas con palmas hacia arriba/adelante.","execution":"Llevá las manos hacia arriba y al centro en un arco, como si hicieras doble bíceps. Apretá el pecho arriba y bajá controladamente.","cues":["Sentí la contracción en el pecho superior","Codos fijos con ligera flexión","Fase excéntrica lenta"],"mistakes":["Tirar con los bíceps","Encoger los hombros","Usar demasiado peso y perder la técnica"]},"en":{"setup":"Cables set low. Stand centered, one step forward. Grab handles with palms facing up/forward.","execution":"Bring hands up and together in an arc, like a double bicep pose. Squeeze upper chest at top and lower under control.","cues":["Feel the contraction in upper chest","Fixed elbows with slight bend","Slow eccentric phase"],"mistakes":["Pulling with biceps","Shrugging shoulders","Too heavy, losing form"]}}'::jsonb, true),
    ('Cruce de poleas medio', 'Mid Cable Crossover', 3, 'weight_reps', 'cable', '{"es":{"setup":"Poleas a la altura del pecho. Parate al centro, un paso adelante, torso recto o ligeramente inclinado.","execution":"Llevá las manos hacia adelante y al centro a la altura del pecho. Apretá el pecho y volvé controladamente.","cues":["Las manos se juntan al frente a la altura del esternón","Movimiento de abrazo","Mantené la tensión constante"],"mistakes":["Flexionar demasiado los codos (se convierte en press)","No mantener la misma altura durante el recorrido","Balancearse para mover el peso"]},"en":{"setup":"Cables at chest height. Stand centered, one step forward, torso straight or slightly leaned.","execution":"Bring hands forward and together at chest height. Squeeze chest and return under control.","cues":["Hands meet at sternum height","Hugging motion","Keep constant tension"],"mistakes":["Bending elbows too much (turns into a press)","Not maintaining the same height throughout","Swaying to move the weight"]}}'::jsonb, true),
    ('Aperturas en máquina pec deck', 'Pec Deck Machine Fly', 3, 'weight_reps', 'machine', '{"es":{"setup":"Ajustá el asiento para que los brazos queden a la altura del pecho. Espalda contra el respaldo, pies firmes. Agarra las manijas o apoyá los antebrazos en las almohadillas.","execution":"Juntá los brazos al frente apretando el pecho. Volvé controladamente hasta sentir un buen estiramiento sin forzar el hombro.","cues":["Apretá fuerte al juntar","No dejes que el peso te abra de golpe","Espalda siempre contra el respaldo"],"mistakes":["Asiento mal ajustado","Abrir demasiado y forzar los hombros","Usar impulso del torso"]},"en":{"setup":"Adjust seat so arms are at chest height. Back against pad, feet flat. Grab handles or rest forearms on pads.","execution":"Bring arms together in front squeezing the chest. Return under control to a comfortable stretch without forcing shoulders.","cues":["Squeeze hard when arms meet","Don''t let the weight snap you open","Back always against the pad"],"mistakes":["Seat improperly adjusted","Opening too far and straining shoulders","Using torso momentum"]}}'::jsonb, true),
    ('Pullover con mancuerna', 'Dumbbell Pullover', 3, 'weight_reps', 'dumbbell', '{"es":{"setup":"Acuéstate en un banco plano. Sostené una mancuerna con ambas manos por un extremo, brazos extendidos sobre el pecho.","execution":"Bajá la mancuerna por detrás de la cabeza en arco manteniendo los codos ligeramente flexionados. Cuando sientas el estiramiento, volvé a la posición inicial apretando pecho y dorsales.","cues":["Codos fijos, el movimiento es del hombro","Sentí el estiramiento en pecho y dorsales","No bajes más de lo que tu movilidad permita"],"mistakes":["Flexionar los codos y convertirlo en press francés","Bajar demasiado y forzar el hombro","Arquear excesivamente la espalda baja"]},"en":{"setup":"Lie on a flat bench. Hold one dumbbell with both hands by one end, arms extended over chest.","execution":"Lower the dumbbell behind your head in an arc with slightly bent elbows. When you feel the stretch, return to start by engaging chest and lats.","cues":["Fixed elbows—movement is from the shoulder","Feel stretch in chest and lats","Don''t go beyond your mobility"],"mistakes":["Bending elbows and turning it into a skull crusher","Going too deep and straining shoulders","Excessive lower back arch"]}}'::jsonb, true),
    ('Pullover en polea', 'Cable Pullover', 3, 'weight_reps', 'cable', '{"es":{"setup":"Polea alta con barra recta o cuerda. Parate de frente a la polea, un paso atrás, torso inclinado. Brazos extendidos agarrando el accesorio arriba.","execution":"Con los codos casi bloqueados, tirá el accesorio hacia abajo en arco hasta los muslos. Volvé arriba controladamente.","cues":["Brazos casi rectos todo el tiempo","Sentí la contracción en pecho y dorsales","Movimiento desde el hombro, no el codo"],"mistakes":["Flexionar los codos y tirar con tríceps","Estar demasiado cerca de la polea","Usar el peso del cuerpo para tirar"]},"en":{"setup":"High cable with straight bar or rope. Face the cable, step back, lean torso forward. Arms extended gripping the attachment above.","execution":"With nearly locked elbows, pull the attachment down in an arc to your thighs. Return up under control.","cues":["Arms almost straight throughout","Feel contraction in chest and lats","Movement from the shoulder, not the elbow"],"mistakes":["Bending elbows and pulling with triceps","Standing too close to the cable","Using body weight to pull"]}}'::jsonb, true),
    ('Pullover en máquina', 'Machine Pullover', 3, 'weight_reps', 'machine', '{"es":{"setup":"Ajustá el asiento para que los hombros queden alineados con el eje de la máquina. Espalda contra el respaldo, pies firmes. Apoyá los codos/antebrazos en las almohadillas.","execution":"Empujá las almohadillas hacia abajo en arco hasta la zona del abdomen. Volvé arriba controladamente sin dejar que el peso te lleve.","cues":["Sentí pecho y dorsales trabajando","No dejes que el peso te estire de golpe","Movimiento fluido"],"mistakes":["Asiento mal ajustado (hombros desalineados del eje)","Usar impulso","Rango de movimiento excesivo"]},"en":{"setup":"Adjust seat so shoulders align with the machine''s pivot point. Back against pad, feet flat. Rest elbows/forearms on pads.","execution":"Push pads down in an arc toward your abdomen. Return up under control without letting the weight pull you.","cues":["Feel chest and lats working together","Don''t let the weight snap you back","Smooth, fluid movement"],"mistakes":["Seat poorly adjusted (shoulders misaligned with pivot)","Using momentum","Excessive range of motion"]}}'::jsonb, true),
    ('Fondos en paralelas', 'Parallel Bar Dips', 6, 'weight_reps', 'bodyweight', '{"es":{"setup":"Agarra las barras paralelas con los brazos extendidos. Incliná el torso hacia adelante para enfatizar pecho. Cruzá los pies atrás.","execution":"Bajá flexionando los codos hasta que el brazo quede paralelo al suelo o sientas un buen estiramiento. Empujá hacia arriba hasta extender los brazos.","cues":["Inclinación hacia adelante para pecho","Bajá hasta 90° en los codos mínimo","Codos ligeramente abiertos"],"mistakes":["Torso muy erguido (trabaja más tríceps que pecho)","Bajar demasiado sin movilidad suficiente","Balancearse o usar impulso"]},"en":{"setup":"Grip parallel bars with arms extended. Lean torso forward to emphasize chest. Cross feet behind you.","execution":"Lower by bending elbows until upper arm is parallel to the floor or you feel a good stretch. Push up to full extension.","cues":["Lean forward for chest emphasis","Lower to at least 90° elbow bend","Elbows slightly flared"],"mistakes":["Too upright (shifts work to triceps)","Going too deep without sufficient mobility","Swinging or using momentum"]}}'::jsonb, true),
    ('Fondos en paralelas con peso', 'Weighted Parallel Bar Dips', 6, 'weight_reps', 'bodyweight', '{"es":{"setup":"Colocá el cinturón de lastre con el peso elegido. Agarra las barras con brazos extendidos, torso inclinado hacia adelante.","execution":"Bajá controladamente hasta que el brazo quede paralelo al suelo. Empujá hacia arriba de forma explosiva pero controlada.","cues":["El peso cuelga quieto, sin balanceo","Misma inclinación que fondos sin peso","Controlá especialmente la bajada"],"mistakes":["Balancear el peso con el cuerpo","Reducir el rango de movimiento por el peso extra","Agregar peso antes de dominar el peso corporal"]},"en":{"setup":"Attach dip belt with chosen weight. Grip bars with arms extended, torso leaning forward.","execution":"Lower under control until upper arm is parallel to the floor. Push up explosively but controlled.","cues":["Weight hangs still, no swinging","Same forward lean as bodyweight dips","Control the descent especially"],"mistakes":["Swinging the weight with your body","Reducing range of motion due to extra weight","Adding weight before mastering bodyweight"]}}'::jsonb, true),
    ('Flexiones', 'Push-Ups', 3, 'reps_only', 'bodyweight', '{"es":{"setup":"Manos en el suelo algo más anchas que los hombros. Cuerpo recto de cabeza a talones, abdomen activado.","execution":"Bajá el pecho hasta casi tocar el suelo flexionando los codos. Empujá hacia arriba hasta extender los brazos completamente.","cues":["Cuerpo recto como una tabla","Codos a 45°, no abiertos","Apretá el abdomen todo el tiempo"],"mistakes":["Cadera caída o levantada","Rango de movimiento incompleto","Cabeza colgando hacia abajo"]},"en":{"setup":"Hands on the floor slightly wider than shoulders. Body in a straight line from head to heels, core braced.","execution":"Lower your chest to nearly touch the floor by bending elbows. Push up until arms are fully extended.","cues":["Body straight like a plank","Elbows at 45°, not flared","Brace core throughout"],"mistakes":["Hips sagging or piking up","Incomplete range of motion","Head drooping down"]}}'::jsonb, true),
    ('Flexiones con peso', 'Weighted Push-Ups', 3, 'weight_reps', 'bodyweight', '{"es":{"setup":"Colocá un disco o chaleco con peso en la espalda alta. Posición de flexión estándar con cuerpo recto.","execution":"Bajá el pecho al suelo manteniendo el cuerpo rígido. Empujá hacia arriba con fuerza.","cues":["El peso debe quedar centrado en la espalda alta","Mismo estándar que flexiones normales","Abdomen extra apretado por el peso"],"mistakes":["Peso mal colocado que se resbala","Compensar con la cadera","Reducir el rango por el peso extra"]},"en":{"setup":"Place a plate or weighted vest on your upper back. Standard push-up position with body straight.","execution":"Lower chest to the floor keeping body rigid. Push up powerfully.","cues":["Weight centered on upper back","Same standard as regular push-ups","Extra core bracing due to weight"],"mistakes":["Weight poorly positioned and sliding","Compensating with the hips","Reducing range due to extra weight"]}}'::jsonb, true),
    ('Flexiones inclinadas', 'Incline Push-Ups', 3, 'reps_only', 'bodyweight', '{"es":{"setup":"Manos en una superficie elevada (banco, cajón). Cuerpo recto, pies en el suelo.","execution":"Bajá el pecho hacia la superficie elevada y empujá hacia arriba. Más fácil que flexiones normales, trabaja más pecho bajo.","cues":["Cuerpo recto, no doblar la cadera","Pecho toca o casi toca la superficie","Codos a 45°"],"mistakes":["Cadera caída","No bajar lo suficiente","Superficie inestable"]},"en":{"setup":"Hands on an elevated surface (bench, box). Body straight, feet on the floor.","execution":"Lower chest toward the elevated surface and push back up. Easier than standard push-ups, emphasizes lower chest.","cues":["Body straight, don''t bend at hips","Chest touches or nearly touches surface","Elbows at 45°"],"mistakes":["Sagging hips","Not going low enough","Unstable surface"]}}'::jsonb, true),
    ('Flexiones declinadas', 'Decline Push-Ups', 3, 'reps_only', 'bodyweight', '{"es":{"setup":"Pies elevados en un banco o cajón, manos en el suelo algo más anchas que los hombros. Cuerpo recto.","execution":"Bajá el pecho al suelo y empujá hacia arriba. Más difícil que flexiones normales, trabaja más pecho superior.","cues":["Cuanto más alto los pies, más trabaja el pecho alto","Cuerpo recto de pies a cabeza","Cabeza en posición neutra"],"mistakes":["Cadera levantada en forma de V","Mirar hacia arriba y forzar el cuello","Superficie inestable para los pies"]},"en":{"setup":"Feet elevated on a bench or box, hands on the floor slightly wider than shoulders. Body straight.","execution":"Lower chest to the floor and push up. Harder than standard push-ups, emphasizes upper chest.","cues":["Higher feet = more upper chest work","Straight body from feet to head","Neutral head position"],"mistakes":["Hips piked up in a V-shape","Looking up and straining neck","Unstable foot surface"]}}'::jsonb, true),
    ('Flexiones diamante', 'Diamond Push-Ups', 3, 'reps_only', 'bodyweight', '{"es":{"setup":"Manos juntas debajo del pecho formando un diamante con los pulgares e índices. Cuerpo recto, abdomen activado.","execution":"Bajá el pecho hasta las manos y empujá hacia arriba. El rango de movimiento es menor, el énfasis en tríceps es alto.","cues":["Codos pegados al cuerpo","Bajá hasta tocar las manos con el pecho","Abdomen muy apretado"],"mistakes":["Abrir los codos como en flexión normal","Cuerpo no recto","No completar el rango de movimiento"]},"en":{"setup":"Hands together under chest forming a diamond with thumbs and index fingers. Body straight, core braced.","execution":"Lower chest to your hands and push back up. Shorter range of motion, high tricep emphasis.","cues":["Elbows tucked close to body","Lower until chest touches hands","Core very tight"],"mistakes":["Flaring elbows like a regular push-up","Body not straight","Incomplete range of motion"]}}'::jsonb, true),
    ('Press de suelo con mancuernas', 'Dumbbell Floor Press', 3, 'weight_reps', 'dumbbell', '{"es":{"setup":"Acuéstate en el suelo con rodillas flexionadas. Llevá las mancuernas a posición de press. Los codos tocarán el suelo abajo.","execution":"Empujá las mancuernas hacia arriba hasta extender los brazos. Bajá hasta que los codos toquen suavemente el suelo y repetí sin rebotar.","cues":["Los codos tocan el suelo, no rebotan","Buena pausa abajo para eliminar impulso","Codos a 45°"],"mistakes":["Rebotar los codos en el suelo","No pausar abajo","Codos demasiado abiertos"]},"en":{"setup":"Lie on the floor with knees bent. Bring dumbbells to press position. Elbows will touch the floor at bottom.","execution":"Press dumbbells up until arms are extended. Lower until elbows gently touch the floor and repeat without bouncing.","cues":["Elbows touch the floor, no bounce","Good pause at bottom to kill momentum","Elbows at 45°"],"mistakes":["Bouncing elbows off the floor","Not pausing at the bottom","Elbows flared too wide"]}}'::jsonb, true),
    ('Hex press con mancuernas', 'Dumbbell Hex Press', 3, 'weight_reps', 'dumbbell', '{"es":{"setup":"Acuéstate en banco plano. Juntá las mancuernas con las caras planas tocándose (hexagonales), palmas enfrentadas.","execution":"Empujá las mancuernas hacia arriba manteniéndolas juntas todo el tiempo. Bajá al pecho sin separarlas.","cues":["Las mancuernas se aprietan entre sí todo el recorrido","Sentí la contracción interna del pecho","Codos pegados al cuerpo"],"mistakes":["Separar las mancuernas durante el movimiento","No apretar las mancuernas entre sí","Usar mancuernas redondas (se resbalan)"]},"en":{"setup":"Lie on a flat bench. Press the flat faces of hex dumbbells together, palms facing each other.","execution":"Press dumbbells up while keeping them pressed together throughout. Lower to chest without separating them.","cues":["Dumbbells squeezed together the entire time","Feel the inner chest contraction","Elbows tucked close to body"],"mistakes":["Letting dumbbells separate during the movement","Not actively pressing them together","Using round dumbbells (they slip)"]}}'::jsonb, true),
    ('Press de pecho unilateral en polea', 'Single-Arm Cable Chest Press', 3, 'weight_reps', 'cable', '{"es":{"setup":"Polea a la altura del pecho. Parate de espaldas, un pie adelante para estabilidad. Agarra la manija con una mano a la altura del pecho.","execution":"Empujá la manija hacia adelante y ligeramente hacia adentro. Volvé controladamente sin dejar que el torso rote.","cues":["Core activado para no rotar","Empujá desde el pecho, no el hombro","Pie adelantado del mismo lado que trabaja"],"mistakes":["Rotar el torso para ayudar","Perder estabilidad del core","Usar demasiado peso y compensar"]},"en":{"setup":"Cable at chest height. Stand with your back to the machine, staggered stance for stability. Grab handle at chest level with one hand.","execution":"Push the handle forward and slightly inward. Return under control without letting your torso rotate.","cues":["Core braced to prevent rotation","Push from the chest, not the shoulder","Lead foot on the working side"],"mistakes":["Rotating the torso to assist","Losing core stability","Too heavy, compensating with body"]}}'::jsonb, true),
    ('Dominadas', 'Pull-Ups', 2, 'weight_reps', 'bodyweight', '{"es":{"setup":"Cuélgate de la barra con agarre prono (palmas hacia fuera) a la anchura de los hombros o ligeramente más ancho. Brazos completamente extendidos, escápulas relajadas.","execution":"Inicia el movimiento retrayendo las escápulas y tirando de los codos hacia abajo y atrás. Sube hasta que la barbilla supere la barra, luego baja de forma controlada hasta la extensión completa.","cues":["Pecho al frente, codos hacia abajo","Aprieta las escápulas arriba del todo","Baja completo sin dejarte caer"],"mistakes":["Usar impulso con las piernas o balanceo","No bajar hasta extensión completa","Subir solo con los brazos sin activar la espalda"]},"en":{"setup":"Hang from the bar with an overhand grip at shoulder width or slightly wider. Arms fully extended, shoulder blades relaxed.","execution":"Initiate by retracting the shoulder blades and driving your elbows down and back. Pull until your chin clears the bar, then lower under control to full extension.","cues":["Chest up, drive elbows down","Squeeze shoulder blades at the top","Full dead hang at the bottom"],"mistakes":["Kipping or swinging for momentum","Partial range of motion at the bottom","Pulling only with arms instead of engaging lats"]}}'::jsonb, true),
    ('Dominadas con peso', 'Weighted Pull-Ups', 2, 'weight_reps', 'bodyweight', '{"es":{"setup":"Coloca el peso en un cinturón de lastre o sujeta una mancuerna entre los pies. Cuélgate con agarre prono a la anchura de los hombros, brazos extendidos.","execution":"Retrae las escápulas y tira de los codos hacia abajo. Sube hasta que la barbilla supere la barra. Baja de forma lenta y controlada hasta extensión completa.","cues":["Mantén el core apretado para no balancearte","Controla la bajada, más lento que sin peso","Escápulas activas en todo el recorrido"],"mistakes":["Balancear el cuerpo por el peso extra","Acortar el rango de movimiento por la carga","Soltar de golpe en la bajada"]},"en":{"setup":"Attach weight via a dip belt or hold a dumbbell between your feet. Hang with an overhand shoulder-width grip, arms fully extended.","execution":"Retract your shoulder blades and drive elbows down. Pull until your chin clears the bar. Lower slowly and with control to full arm extension.","cues":["Brace your core to minimize swinging","Slow eccentric — control the descent","Shoulder blades active throughout"],"mistakes":["Swinging the body due to added load","Cutting range of motion short","Dropping too fast on the way down"]}}'::jsonb, true),
    ('Dominadas agarre supino', 'Chin-Ups', 2, 'reps_only', 'bodyweight', '{"es":{"setup":"Cuélgate de la barra con agarre supino (palmas hacia ti) a la anchura de los hombros. Brazos completamente extendidos.","execution":"Tira llevando los codos hacia abajo y hacia las costillas. Sube hasta que la barbilla supere la barra. Baja controladamente hasta extensión completa.","cues":["Codos pegados al cuerpo","Aprieta la espalda y bíceps arriba","Extensión completa abajo"],"mistakes":["Balancear el cuerpo para coger impulso","No extender los brazos completamente abajo","Dejar que los hombros se vayan hacia delante"]},"en":{"setup":"Hang from the bar with an underhand grip (palms facing you) at shoulder width. Arms fully extended.","execution":"Pull by driving your elbows down toward your ribs. Rise until your chin clears the bar. Lower with control to full extension.","cues":["Keep elbows close to your body","Squeeze back and biceps at top","Full extension at the bottom"],"mistakes":["Swinging or kipping for momentum","Not fully extending arms at the bottom","Letting shoulders roll forward"]}}'::jsonb, true),
    ('Dominadas agarre neutro', 'Neutral-Grip Pull-Ups', 2, 'reps_only', 'bodyweight', '{"es":{"setup":"Agarra las asas paralelas con las palmas enfrentadas. Cuélgate con brazos extendidos y el core activado.","execution":"Tira llevando los codos hacia abajo pegados al cuerpo. Sube hasta que la barbilla supere las manos. Baja de forma controlada hasta extensión completa.","cues":["Codos cerca del torso en todo momento","Pecho hacia las manos arriba","Baja sin dejarte caer"],"mistakes":["Abrir los codos hacia fuera","Acortar el recorrido por comodidad","Usar impulso con las piernas"]},"en":{"setup":"Grip the parallel handles with palms facing each other. Hang with arms fully extended and core engaged.","execution":"Pull by driving your elbows straight down, keeping them close to your torso. Rise until your chin clears your hands. Lower under control to full extension.","cues":["Elbows tight to the torso throughout","Drive chest toward your hands at the top","Controlled descent every rep"],"mistakes":["Flaring elbows outward","Shortening range of motion","Using leg momentum to swing up"]}}'::jsonb, true),
    ('Dominadas asistidas en máquina', 'Machine Assisted Pull-Ups', 2, 'weight_reps', 'machine', '{"es":{"setup":"Sube a la plataforma de la máquina, coloca las rodillas (o pies) en el soporte y agarra la barra con agarre prono. Selecciona el contrapeso de asistencia.","execution":"Tira de los codos hacia abajo retrayendo las escápulas. Sube hasta que la barbilla supere la barra. Baja controladamente sin dejar que el contrapeso tire de ti de golpe.","cues":["Misma técnica que una dominada libre","No dejes que la máquina te suba: tú tiras","Baja despacio, controla el contrapeso"],"mistakes":["Dejarse impulsar por el contrapeso en la subida","Soltar la tensión en la bajada","Inclinarse excesivamente hacia atrás"]},"en":{"setup":"Step onto the machine platform, place your knees (or feet) on the pad, and grip the bar overhand. Select the counterweight assistance.","execution":"Drive your elbows down while retracting your shoulder blades. Pull until your chin clears the bar. Lower under control without letting the weight stack yank you down.","cues":["Same technique as a free pull-up","You pull — don''t let the machine push you","Slow descent, control the counterweight"],"mistakes":["Letting the counterweight do the work on the way up","Releasing tension on the way down","Excessive backward lean"]}}'::jsonb, true),
    ('Jalón al pecho agarre prono', 'Overhand Lat Pulldown', 2, 'weight_reps', 'cable', '{"es":{"setup":"Siéntate con los muslos bien sujetos bajo las almohadillas. Agarra la barra con agarre prono algo más ancho que los hombros.","execution":"Lleva la barra hacia la parte alta del pecho tirando de los codos hacia abajo y atrás. Aprieta las escápulas al final. Vuelve arriba con control sin soltar la tensión.","cues":["Pecho alto, saca pecho hacia la barra","Codos hacia abajo, no hacia atrás","No te inclines excesivamente hacia atrás"],"mistakes":["Tirar con impulso echándose hacia atrás","Bajar la barra demasiado abajo (por debajo del pecho)","Soltar el peso de golpe en la fase excéntrica"]},"en":{"setup":"Sit with thighs secured under the pads. Grip the bar overhand, slightly wider than shoulder width.","execution":"Pull the bar to your upper chest by driving your elbows down and back. Squeeze your shoulder blades at the bottom. Return the bar up with control, maintaining tension.","cues":["Chest up — drive it toward the bar","Elbows down, not back","Don''t lean excessively backward"],"mistakes":["Using momentum by leaning back too far","Pulling the bar below the chest","Releasing the weight too quickly on the way up"]}}'::jsonb, true),
    ('Jalón al pecho agarre supino', 'Underhand Lat Pulldown', 2, 'weight_reps', 'cable', '{"es":{"setup":"Siéntate con los muslos bajo las almohadillas. Agarra la barra con agarre supino (palmas hacia ti) a la anchura de los hombros.","execution":"Tira de la barra hacia la parte alta del pecho llevando los codos hacia abajo y cerca del cuerpo. Aprieta escápulas y bíceps abajo. Sube con control.","cues":["Codos pegados al torso","Aprieta al máximo abajo antes de subir","Pecho erguido durante todo el movimiento"],"mistakes":["Echar el torso demasiado atrás","Tirar solo con los bíceps sin activar dorsales","Usar impulso balanceando el cuerpo"]},"en":{"setup":"Sit with thighs under the pads. Grip the bar underhand (palms facing you) at shoulder width.","execution":"Pull the bar to your upper chest, driving elbows down and close to your body. Squeeze shoulder blades and biceps at the bottom. Return up with control.","cues":["Elbows tight to the torso","Maximum squeeze at the bottom before releasing","Chest tall throughout the movement"],"mistakes":["Leaning the torso too far back","Pulling only with biceps, lats disengaged","Using momentum by rocking the body"]}}'::jsonb, true),
    ('Jalón al pecho agarre neutro', 'Neutral-Grip Lat Pulldown', 2, 'weight_reps', 'cable', '{"es":{"setup":"Siéntate con los muslos bajo las almohadillas. Agarra el accesorio de agarre neutro con las palmas enfrentadas.","execution":"Tira de los codos hacia abajo y cerca del cuerpo hasta que las manos lleguen a la altura del pecho. Aprieta las escápulas. Sube con control manteniendo tensión.","cues":["Codos pegados al cuerpo","Aprieta escápulas al final del tirón","Pecho alto, no te hundas"],"mistakes":["Separar los codos del cuerpo","Inclinar el torso excesivamente","Usar impulso en lugar de fuerza controlada"]},"en":{"setup":"Sit with thighs secured under pads. Grip the neutral-grip attachment with palms facing each other.","execution":"Drive your elbows down and close to your body until your hands reach chest level. Squeeze shoulder blades. Return up with control, keeping tension.","cues":["Elbows close to your body","Squeeze shoulder blades at the bottom","Chest up, don''t slouch"],"mistakes":["Flaring elbows away from the body","Leaning the torso too far back","Using momentum instead of controlled strength"]}}'::jsonb, true),
    ('Jalón al pecho agarre ancho', 'Wide-Grip Lat Pulldown', 2, 'weight_reps', 'cable', '{"es":{"setup":"Siéntate con los muslos bien sujetos. Agarra la barra prono con las manos bien separadas, cerca de los extremos de la barra.","execution":"Tira de los codos hacia abajo y hacia fuera llevando la barra a la parte alta del pecho. Aprieta los dorsales abajo. Sube controladamente.","cues":["Piensa en llevar los codos al suelo","Pecho hacia la barra, no la barra hacia ti","Contracción clara de dorsales abajo"],"mistakes":["Tirar echándose excesivamente hacia atrás","Agarrar demasiado ancho, limitando el recorrido","No completar el rango de movimiento arriba"]},"en":{"setup":"Sit with thighs secured. Grip the bar overhand with hands wide apart, near the ends of the bar.","execution":"Drive your elbows down and slightly out, pulling the bar to your upper chest. Squeeze your lats at the bottom. Return up with control.","cues":["Think of driving elbows to the floor","Chest to the bar, not bar to you","Clear lat contraction at the bottom"],"mistakes":["Leaning excessively backward to pull","Gripping too wide, limiting range of motion","Not fully extending arms at the top"]}}'::jsonb, true),
    ('Jalón al pecho agarre cerrado', 'Close-Grip Lat Pulldown', 2, 'weight_reps', 'cable', '{"es":{"setup":"Siéntate con los muslos bajo las almohadillas. Agarra la barra o accesorio con las manos juntas, separadas unos 15-20 cm.","execution":"Tira de la barra al pecho llevando los codos hacia abajo y atrás. Aprieta fuerte en la contracción. Sube con control hasta extensión completa.","cues":["Codos hacia las costillas","Aguanta la contracción 1 segundo abajo","Estira completo arriba"],"mistakes":["Inclinar el torso excesivamente hacia atrás","No llegar a extensión completa arriba","Tirar solo con los brazos"]},"en":{"setup":"Sit with thighs under pads. Grip the bar or attachment with hands close together, about 15-20 cm apart.","execution":"Pull the bar to your chest, driving elbows down and back. Squeeze hard at the contraction. Return up with control to full extension.","cues":["Elbows toward your ribs","Hold the contraction for 1 second at the bottom","Full stretch at the top"],"mistakes":["Excessive backward torso lean","Not reaching full extension at the top","Pulling only with arms"]}}'::jsonb, true),
    ('Jalón al pecho con barra V', 'V-Bar Lat Pulldown', 2, 'weight_reps', 'barbell', '{"es":{"setup":"Coloca el accesorio V en la polea alta. Siéntate con los muslos bajo las almohadillas y agarra con las palmas enfrentadas.","execution":"Tira del accesorio hacia el pecho alto llevando los codos hacia abajo y cerca del cuerpo. Aprieta las escápulas. Sube controladamente.","cues":["Codos pegados al torso","Saca pecho para encontrarte con la V","Contracción fuerte abajo"],"mistakes":["Echar el cuerpo hacia atrás para compensar peso","Abrir los codos hacia fuera","Soltar la tensión arriba de golpe"]},"en":{"setup":"Attach the V-bar to the high pulley. Sit with thighs under pads and grip with palms facing each other.","execution":"Pull the attachment to your upper chest, driving elbows down and close to your body. Squeeze your shoulder blades. Return up with control.","cues":["Elbows tight to the torso","Push chest out to meet the V-bar","Strong contraction at the bottom"],"mistakes":["Leaning back to compensate for heavy weight","Flaring elbows outward","Releasing tension suddenly at the top"]}}'::jsonb, true),
    ('Jalón al pecho con cuerda', 'Rope Lat Pulldown', 2, 'weight_reps', 'cable', '{"es":{"setup":"Coloca la cuerda en la polea alta. Siéntate con los muslos bajo las almohadillas y agarra cada extremo de la cuerda.","execution":"Tira separando los extremos de la cuerda mientras los llevas hacia los lados del pecho. Aprieta las escápulas abriendo la cuerda al final. Sube con control.","cues":["Separa la cuerda al final del movimiento","Codos hacia las caderas","Aprieta escápulas como si sujetaras un lápiz"],"mistakes":["No separar la cuerda al final del recorrido","Echar el torso excesivamente hacia atrás","Usar impulso en lugar de tracción controlada"]},"en":{"setup":"Attach the rope to the high pulley. Sit with thighs under pads and grip each end of the rope.","execution":"Pull down while spreading the rope ends apart toward each side of your chest. Squeeze shoulder blades, opening the rope at the bottom. Return up with control.","cues":["Spread the rope apart at the bottom","Elbows toward your hips","Squeeze shoulder blades like holding a pencil"],"mistakes":["Not splitting the rope at the bottom","Excessive backward lean","Using momentum instead of controlled pulling"]}}'::jsonb, true),
    ('Jalón al pecho unilateral', 'Single-Arm Lat Pulldown', 2, 'weight_reps', 'cable', '{"es":{"setup":"Coloca un asa en la polea alta. Siéntate de frente o ligeramente lateral y agarra con una mano.","execution":"Tira del asa hacia el lateral del pecho llevando el codo hacia abajo y atrás. Aprieta el dorsal en la contracción. Sube con control. Repite con el otro brazo.","cues":["Siente el dorsal trabajar, no solo el brazo","Codo hacia la cadera","Mantén el torso estable sin rotar"],"mistakes":["Rotar el torso para compensar","Tirar solo con el bíceps","Usar pesos desiguales entre lados"]},"en":{"setup":"Attach a single handle to the high pulley. Sit facing forward or slightly angled and grip with one hand.","execution":"Pull the handle toward the side of your chest, driving your elbow down and back. Squeeze the lat at the bottom. Return up with control. Repeat on the other arm.","cues":["Feel the lat, not just the arm","Elbow drives toward the hip","Keep torso stable, no rotation"],"mistakes":["Rotating the torso to compensate","Pulling only with the bicep","Using uneven weight between sides"]}}'::jsonb, true),
    ('Jalón tras nuca', 'Behind-the-Neck Lat Pulldown', 2, 'weight_reps', 'cable', '{"es":{"setup":"Siéntate erguido con los muslos bajo las almohadillas. Agarre prono ancho. Inclina ligeramente la cabeza hacia delante.","execution":"Tira de la barra por detrás de la cabeza hasta la altura de la nuca, llevando los codos hacia abajo. Aprieta las escápulas. Sube con control. Usa peso moderado.","cues":["Cabeza ligeramente adelante para dejar paso","Codos en línea con el torso, no hacia atrás","Peso moderado, aquí la técnica manda"],"mistakes":["Usar demasiado peso forzando el cuello","Bajar la barra demasiado (más allá de la nuca)","Tener poca movilidad de hombros para este ejercicio"]},"en":{"setup":"Sit upright with thighs under pads. Wide overhand grip. Tilt your head slightly forward.","execution":"Pull the bar behind your head to the base of your neck, driving elbows down. Squeeze your shoulder blades. Return up with control. Use moderate weight.","cues":["Head slightly forward to clear the bar path","Elbows in line with torso, not pulled back","Moderate weight — technique over ego"],"mistakes":["Using too much weight, straining the neck","Pulling the bar too far below the neck","Attempting this with limited shoulder mobility"]}}'::jsonb, true),
    ('Jalón con brazos rectos en polea', 'Straight-Arm Cable Pulldown', 2, 'weight_reps', 'cable', '{"es":{"setup":"De pie frente a la polea alta, un paso atrás. Agarra la barra o cuerda con brazos extendidos y ligera flexión de codos. Inclina el torso ligeramente hacia delante.","execution":"Manteniendo los brazos casi rectos, lleva la barra en arco hacia los muslos contrayendo los dorsales. Aguanta la contracción abajo. Vuelve arriba con control.","cues":["Brazos casi rectos todo el tiempo","Aprieta los dorsales, no tires con los brazos","Controla la vuelta arriba"],"mistakes":["Flexionar los codos para usar los bíceps","Usar impulso balanceando el torso","No controlar la fase excéntrica"]},"en":{"setup":"Stand facing the high pulley, one step back. Grip the bar or rope with extended arms and a slight elbow bend. Lean your torso slightly forward.","execution":"Keeping arms nearly straight, sweep the bar in an arc toward your thighs by contracting your lats. Hold the contraction at the bottom. Return up with control.","cues":["Arms nearly straight the entire time","Squeeze lats, don''t pull with arms","Control the return to the top"],"mistakes":["Bending elbows to recruit biceps","Using momentum by rocking the torso","Not controlling the eccentric phase"]}}'::jsonb, true),
    ('Remo con barra agarre prono', 'Overhand Barbell Row', 2, 'weight_reps', 'barbell', '{"es":{"setup":"De pie, pies a la anchura de los hombros. Inclínate con la cadera hasta que el torso quede a unos 45°. Agarra la barra prono algo más ancho que los hombros. Rodillas ligeramente flexionadas.","execution":"Tira de la barra hacia el abdomen bajo retrayendo las escápulas y llevando los codos hacia atrás. Aprieta arriba. Baja con control hasta extensión de brazos.","cues":["Espalda recta, pecho fuera","Codos hacia el techo","La barra va al ombligo"],"mistakes":["Redondear la espalda baja","Incorporarse demasiado para usar impulso","Tirar solo con los brazos sin retraer escápulas"]},"en":{"setup":"Stand with feet shoulder-width apart. Hinge at the hips until your torso is roughly 45°. Grip the bar overhand, slightly wider than shoulder width. Slight knee bend.","execution":"Pull the bar toward your lower abdomen, retracting shoulder blades and driving elbows back. Squeeze at the top. Lower with control to full arm extension.","cues":["Flat back, chest out","Elbows toward the ceiling","Bar goes to the navel"],"mistakes":["Rounding the lower back","Standing too upright to cheat the weight","Pulling with arms only, no scapular retraction"]}}'::jsonb, true),
    ('Remo con barra agarre supino', 'Underhand Barbell Row', 2, 'weight_reps', 'barbell', '{"es":{"setup":"De pie, pies a la anchura de los hombros. Inclínate con la cadera a unos 45°. Agarra la barra supino (palmas hacia arriba) a la anchura de los hombros. Rodillas ligeramente flexionadas.","execution":"Tira de la barra hacia el abdomen bajo llevando los codos hacia atrás y cerca del cuerpo. Aprieta la contracción arriba. Baja con control.","cues":["Codos pegados al cuerpo","Aprieta bíceps y espalda arriba","Espalda neutra en todo momento"],"mistakes":["Redondear la espalda baja","Usar impulso con el torso","Agarrar demasiado ancho, perdiendo el beneficio del supino"]},"en":{"setup":"Stand with feet shoulder-width apart. Hinge at the hips to about 45°. Grip the bar underhand (palms up) at shoulder width. Slight knee bend.","execution":"Pull the bar to your lower abdomen, driving elbows back and close to the body. Squeeze the contraction at the top. Lower with control.","cues":["Elbows close to the body","Squeeze biceps and back at the top","Neutral spine throughout"],"mistakes":["Rounding the lower back","Using torso momentum to cheat","Gripping too wide, losing the underhand advantage"]}}'::jsonb, true),
    ('Remo con mancuerna a una mano', 'Single-Arm Dumbbell Row', 2, 'weight_reps', 'dumbbell', '{"es":{"setup":"Apoya una mano y la rodilla del mismo lado en un banco. El otro pie en el suelo. Toma la mancuerna con el brazo libre, colgando perpendicular al suelo.","execution":"Tira de la mancuerna hacia la cadera llevando el codo hacia el techo. Aprieta el dorsal arriba. Baja con control hasta extensión completa.","cues":["Codo al techo, no hacia fuera","Siente el dorsal, no solo el brazo","Torso estable, sin rotar"],"mistakes":["Rotar el torso para subir más peso","Tirar solo con el bíceps","No bajar la mancuerna completamente"]},"en":{"setup":"Place one hand and the same-side knee on a bench. Other foot on the floor. Hold the dumbbell with the free arm, hanging perpendicular to the ground.","execution":"Row the dumbbell toward your hip, driving the elbow toward the ceiling. Squeeze the lat at the top. Lower with control to full extension.","cues":["Elbow to the ceiling, not out to the side","Feel the lat, not just the arm","Stable torso, no twisting"],"mistakes":["Rotating the torso to heave more weight","Pulling with bicep only","Not lowering the dumbbell fully"]}}'::jsonb, true),
    ('Remo en polea baja sentado', 'Seated Cable Row', 2, 'weight_reps', 'cable', '{"es":{"setup":"Siéntate con los pies en las plataformas, rodillas ligeramente flexionadas. Agarra el accesorio con los brazos extendidos y el torso erguido.","execution":"Tira del accesorio hacia el abdomen retrayendo las escápulas y llevando los codos atrás. Aprieta la contracción. Vuelve al inicio estirando los brazos con control sin redondear la espalda.","cues":["Pecho fuera, hombros atrás","Los codos pasan pegados al cuerpo","No balancees el torso"],"mistakes":["Inclinarse hacia delante y atrás como remando un bote","Redondear la espalda en la extensión","Tirar solo con los brazos sin escápulas"]},"en":{"setup":"Sit with feet on the platforms, knees slightly bent. Grip the attachment with arms extended and torso upright.","execution":"Pull the attachment toward your abdomen, retracting shoulder blades and driving elbows back. Squeeze the contraction. Return to the start by extending arms with control, keeping your back straight.","cues":["Chest out, shoulders back","Elbows stay close to the body","Don''t rock the torso"],"mistakes":["Rocking back and forth like rowing a boat","Rounding the back at full extension","Pulling with arms only, no scapular retraction"]}}'::jsonb, true),
    ('Remo en polea baja agarre ancho', 'Wide-Grip Seated Cable Row', 2, 'weight_reps', 'cable', '{"es":{"setup":"Siéntate con los pies en las plataformas. Agarra una barra larga con agarre prono ancho. Torso erguido, brazos extendidos.","execution":"Tira de la barra hacia el pecho alto llevando los codos hacia fuera y atrás. Aprieta las escápulas. Vuelve al inicio con control.","cues":["Codos a la altura de los hombros","Aprieta entre las escápulas","Torso fijo, no te balancees"],"mistakes":["Balancear el torso hacia delante y atrás","Bajar los codos (convertiría en un remo bajo)","Usar demasiado peso sacrificando rango"]},"en":{"setup":"Sit with feet on platforms. Grip a long bar with a wide overhand grip. Torso upright, arms extended.","execution":"Pull the bar toward your upper chest, driving elbows out and back at shoulder height. Squeeze your shoulder blades together. Return to the start with control.","cues":["Elbows at shoulder height","Squeeze between the shoulder blades","Torso stays still, no rocking"],"mistakes":["Rocking the torso back and forth","Dropping the elbows (turns it into a low row)","Too much weight, sacrificing range of motion"]}}'::jsonb, true),
    ('Remo en polea baja con barra V', 'V-Bar Seated Cable Row', 2, 'weight_reps', 'cable', '{"es":{"setup":"Siéntate con los pies en las plataformas. Coloca la barra V y agarra con las palmas enfrentadas. Torso erguido, brazos extendidos.","execution":"Tira de la V hacia el abdomen llevando los codos hacia atrás y cerca del cuerpo. Retrae las escápulas en la contracción. Vuelve con control.","cues":["Pecho fuera, espalda neutra","Codos pegados al torso","Contracción clara al final del tirón"],"mistakes":["Balancear el torso para generar impulso","Redondear la espalda al estirar los brazos","No completar la retracción escapular"]},"en":{"setup":"Sit with feet on platforms. Attach the V-bar and grip with palms facing each other. Torso upright, arms extended.","execution":"Pull the V-bar to your abdomen, driving elbows back close to your body. Retract shoulder blades at the contraction. Return with control.","cues":["Chest out, neutral spine","Elbows tight to the torso","Clear contraction at the end of the pull"],"mistakes":["Rocking the torso for momentum","Rounding the back when extending arms","Incomplete scapular retraction"]}}'::jsonb, true),
    ('Remo en polea baja con cuerda', 'Rope Seated Cable Row', 2, 'weight_reps', 'cable', '{"es":{"setup":"Siéntate con los pies en las plataformas. Agarra cada extremo de la cuerda con agarre neutro. Torso erguido.","execution":"Tira de la cuerda hacia el abdomen separando los extremos al final del movimiento. Aprieta las escápulas abriendo la cuerda. Vuelve con control.","cues":["Separa la cuerda al final del tirón","Codos hacia atrás, no hacia los lados","Contrae escápulas como si aplastaras algo entre ellas"],"mistakes":["No separar la cuerda al final","Inclinarse demasiado hacia atrás","Perder la posición neutra de la espalda"]},"en":{"setup":"Sit with feet on platforms. Grip each end of the rope with a neutral grip. Torso upright.","execution":"Pull the rope toward your abdomen, spreading the ends apart at the end of the movement. Squeeze shoulder blades while splitting the rope. Return with control.","cues":["Split the rope at the end of the pull","Elbows back, not out to the sides","Squeeze shoulder blades like crushing something between them"],"mistakes":["Not splitting the rope at the end","Leaning too far back","Losing neutral spine position"]}}'::jsonb, true),
    ('Remo en polea baja unilateral', 'Single-Arm Seated Cable Row', 2, 'weight_reps', 'cable', '{"es":{"setup":"Siéntate frente a la polea baja. Agarra un asa con una mano, brazo extendido. Torso erguido, core activado para evitar rotación.","execution":"Tira del asa hacia la cadera llevando el codo hacia atrás. Aprieta el dorsal en la contracción. Vuelve con control. Repite con el otro lado.","cues":["No rotar el torso: el core trabaja anti-rotación","Codo hacia la cadera, no hacia fuera","Mismas repeticiones y peso en ambos lados"],"mistakes":["Rotar el torso para compensar peso","Tirar solo con el brazo sin activar el dorsal","Descompensar volumen entre lados"]},"en":{"setup":"Sit facing the low pulley. Grip a single handle with one hand, arm extended. Torso upright, core braced to prevent rotation.","execution":"Pull the handle toward your hip, driving the elbow back. Squeeze the lat at the contraction. Return with control. Repeat on the other side.","cues":["No torso rotation — core works anti-rotation","Elbow toward the hip, not out","Same reps and weight on both sides"],"mistakes":["Rotating the torso to compensate for weight","Pulling with the arm only, lat disengaged","Volume imbalance between sides"]}}'::jsonb, true),
    ('Remo en polea alta', 'High Cable Row', 2, 'weight_reps', 'cable', '{"es":{"setup":"De pie o sentado frente a una polea alta. Agarra la cuerda o barra con ambas manos. Brazos extendidos hacia arriba y adelante.","execution":"Tira del accesorio hacia la cara o el pecho alto llevando los codos hacia atrás. Retrae las escápulas. Vuelve a la posición inicial con control.","cues":["Codos altos, a la altura de los hombros","Aprieta entre las escápulas","Torso estable, no te inclines atrás"],"mistakes":["Dejar caer los codos abajo (se convierte en un remo bajo)","Inclinar el torso hacia atrás para usar impulso","No completar la retracción escapular"]},"en":{"setup":"Stand or sit facing a high pulley. Grip the rope or bar with both hands. Arms extended up and forward.","execution":"Pull the attachment toward your face or upper chest, driving elbows back. Retract shoulder blades. Return to starting position with control.","cues":["Elbows high, at shoulder level","Squeeze between shoulder blades","Stable torso, don''t lean back"],"mistakes":["Dropping elbows low (turns it into a low row)","Leaning back for momentum","Incomplete scapular retraction"]}}'::jsonb, true),
    ('Remo en barra T', 'T-Bar Row', 2, 'weight_reps', 'barbell', '{"es":{"setup":"Colócate a horcajadas sobre la barra T. Inclínate con la cadera a unos 45°. Agarra las asas con ambas manos. Rodillas ligeramente flexionadas, espalda neutra.","execution":"Tira de la barra hacia el pecho llevando los codos hacia atrás. Aprieta las escápulas en la contracción. Baja con control hasta extensión.","cues":["Espalda plana, pecho fuera","Codos hacia el techo","Aprieta fuerte arriba 1 segundo"],"mistakes":["Redondear la espalda baja","Incorporarse para usar impulso","Dejar caer el peso en la bajada"]},"en":{"setup":"Straddle the T-bar. Hinge at the hips to about 45°. Grip the handles with both hands. Slight knee bend, neutral spine.","execution":"Pull the bar toward your chest, driving elbows back. Squeeze shoulder blades at the contraction. Lower with control to full extension.","cues":["Flat back, chest out","Elbows toward the ceiling","Hard squeeze at the top for 1 second"],"mistakes":["Rounding the lower back","Standing up to cheat the weight","Dropping the weight on the way down"]}}'::jsonb, true),
    ('Remo en barra T con agarre neutro', 'Neutral-Grip T-Bar Row', 2, 'weight_reps', 'barbell', '{"es":{"setup":"Colócate a horcajadas sobre la barra T. Usa el accesorio de agarre neutro (palmas enfrentadas). Inclinación de torso a ~45°, espalda neutra.","execution":"Tira hacia el abdomen con los codos pegados al cuerpo. Aprieta las escápulas arriba. Baja con control.","cues":["Codos cerca del torso","Espalda plana durante todo el movimiento","Contracción firme arriba"],"mistakes":["Redondear la espalda baja","Separar los codos del cuerpo","Usar impulso con el torso"]},"en":{"setup":"Straddle the T-bar. Use the neutral-grip attachment (palms facing). Torso at ~45°, neutral spine.","execution":"Pull toward your abdomen with elbows close to your body. Squeeze shoulder blades at the top. Lower with control.","cues":["Elbows close to the torso","Flat back throughout the movement","Firm contraction at the top"],"mistakes":["Rounding the lower back","Flaring elbows away from the body","Using torso momentum to cheat"]}}'::jsonb, true),
    ('Remo en máquina', 'Machine Row', 2, 'weight_reps', 'machine', '{"es":{"setup":"Siéntate en la máquina con el pecho apoyado en la almohadilla. Ajusta la altura para que las asas queden a la altura del pecho. Agarra las asas.","execution":"Tira de las asas hacia ti retrayendo las escápulas. Aprieta la contracción 1 segundo. Vuelve al inicio con control sin soltar la tensión.","cues":["Pecho pegado a la almohadilla","Retrae escápulas antes de tirar con los brazos","Control en la vuelta, sin dejar caer"],"mistakes":["Despegar el pecho de la almohadilla para usar impulso","Tirar solo con los brazos sin escápulas","Soltar el peso de golpe"]},"en":{"setup":"Sit with your chest against the pad. Adjust the height so handles are at chest level. Grip the handles.","execution":"Pull the handles toward you, retracting shoulder blades. Hold the contraction for 1 second. Return to start with control, maintaining tension.","cues":["Chest stays against the pad","Retract shoulder blades before pulling with arms","Control the return, don''t drop the weight"],"mistakes":["Lifting chest off the pad to use momentum","Pulling with arms only, no scapular retraction","Releasing the weight abruptly"]}}'::jsonb, true),
    ('Remo en máquina convergente', 'Converging Machine Row', 2, 'weight_reps', 'machine', '{"es":{"setup":"Siéntate con el pecho contra la almohadilla. Agarra las asas independientes. El movimiento convergente imita un remo con mancuernas.","execution":"Tira de ambas asas hacia ti de forma simultánea, retrayendo las escápulas. Las manos convergen al final. Aprieta y vuelve con control.","cues":["Deja que las manos se acerquen al final","Aprieta las escápulas en la contracción","Pecho contra la almohadilla siempre"],"mistakes":["Despegar el pecho para usar impulso","No aprovechar el rango convergente","Soltar la tensión en la vuelta"]},"en":{"setup":"Sit with chest against the pad. Grip the independent handles. The converging path mimics a dumbbell row.","execution":"Pull both handles toward you simultaneously, retracting shoulder blades. Hands converge at the end. Squeeze and return with control.","cues":["Let the hands come together at the end","Squeeze shoulder blades at the contraction","Chest stays against the pad throughout"],"mistakes":["Lifting chest off pad for momentum","Not using the full converging range","Releasing tension on the return"]}}'::jsonb, true),
    ('Remo Pendlay', 'Pendlay Row', 2, 'weight_reps', 'barbell', '{"es":{"setup":"De pie con pies a la anchura de los hombros. Inclínate hasta que el torso quede paralelo al suelo. Agarre prono algo más ancho que los hombros. La barra empieza en el suelo cada repetición.","execution":"Tira explosivamente de la barra hacia el abdomen bajo retrayendo las escápulas. Baja la barra al suelo de forma controlada. Cada repetición comienza desde parado en el suelo.","cues":["Torso paralelo al suelo, siempre","Explosivo arriba, controlado abajo","La barra toca el suelo entre cada rep"],"mistakes":["Incorporar el torso para hacer trampa","No dejar la barra en el suelo entre repeticiones","Redondear la espalda baja"]},"en":{"setup":"Stand with feet shoulder-width apart. Bend until torso is parallel to the floor. Overhand grip slightly wider than shoulders. Bar starts on the floor each rep.","execution":"Explosively row the bar to your lower abdomen, retracting shoulder blades. Lower the bar to the floor in a controlled manner. Each rep starts from a dead stop on the floor.","cues":["Torso parallel to the floor, always","Explosive up, controlled down","Bar touches the floor between every rep"],"mistakes":["Rising up with the torso to cheat","Not returning the bar to the floor between reps","Rounding the lower back"]}}'::jsonb, true),
    ('Remo Meadows', 'Meadows Row', 2, 'weight_reps', 'barbell', '{"es":{"setup":"Colócate perpendicular al extremo de una barra T o landmine. Adelanta la pierna contraria al brazo que trabaja. Agarra el extremo grueso de la barra con una mano.","execution":"Tira de la barra en arco hacia la cadera llevando el codo hacia arriba y atrás. Aprieta el dorsal arriba. Baja con control. Repite con el otro lado.","cues":["Codo alto, hacia el techo","Estira bien abajo, siente el dorsal","La pierna adelantada da estabilidad"],"mistakes":["Rotar excesivamente el torso","No estirar completamente abajo","Redondear la espalda por mala postura"]},"en":{"setup":"Stand perpendicular to the end of a T-bar or landmine. Step the opposite leg forward from the working arm. Grip the thick end of the bar with one hand.","execution":"Row the bar in an arc toward your hip, driving the elbow up and back. Squeeze the lat at the top. Lower with control. Repeat on the other side.","cues":["Elbow high, toward the ceiling","Full stretch at the bottom, feel the lat","Front leg provides stability"],"mistakes":["Excessive torso rotation","Not stretching fully at the bottom","Rounding the back due to poor posture"]}}'::jsonb, true),
    ('Remo Helms', 'Helms Row', 2, 'weight_reps', 'dumbbell', '{"es":{"setup":"Coloca un banco inclinado a unos 30-45°. Túmbate boca abajo con el pecho apoyado en el banco. Toma una mancuerna en cada mano, brazos colgando.","execution":"Rema ambas mancuernas hacia las caderas llevando los codos hacia atrás. Aprieta las escápulas arriba. Baja con control hasta extensión completa.","cues":["El pecho no se despega del banco","Codos hacia las caderas","Sin impulso: el banco te obliga a usar técnica pura"],"mistakes":["Despegar el pecho del banco","Usar poca inclinación, limitando el rango","No bajar las mancuernas completamente"]},"en":{"setup":"Set an incline bench to 30-45°. Lie face down with chest supported on the bench. Hold a dumbbell in each hand, arms hanging.","execution":"Row both dumbbells toward your hips, driving elbows back. Squeeze shoulder blades at the top. Lower with control to full extension.","cues":["Chest stays on the bench","Elbows drive toward the hips","No momentum — the bench forces strict form"],"mistakes":["Lifting chest off the bench","Too little incline, limiting range of motion","Not lowering dumbbells fully"]}}'::jsonb, true),
    ('Remo con mancuernas en banco inclinado', 'Incline Bench Dumbbell Row', 2, 'weight_reps', 'dumbbell', '{"es":{"setup":"Coloca un banco inclinado a unos 30-45°. Túmbate boca abajo con el pecho apoyado. Toma una mancuerna en cada mano con los brazos colgando.","execution":"Rema las mancuernas hacia los lados del torso retrayendo las escápulas. Aprieta arriba. Baja con control hasta extensión completa.","cues":["Pecho pegado al banco","Retrae las escápulas antes de tirar","Controla la bajada, no dejes caer"],"mistakes":["Despegar el pecho para coger impulso","No completar la retracción escapular","Rango de movimiento incompleto"]},"en":{"setup":"Set an incline bench to 30-45°. Lie face down with chest supported. Hold a dumbbell in each hand, arms hanging.","execution":"Row the dumbbells to the sides of your torso, retracting shoulder blades. Squeeze at the top. Lower with control to full extension.","cues":["Chest stays on the bench","Retract shoulder blades before pulling","Control the descent, don''t drop"],"mistakes":["Lifting chest off the bench for momentum","Incomplete scapular retraction","Partial range of motion"]}}'::jsonb, true),
    ('Remo invertido en barra', 'Inverted Row', 2, 'reps_only', 'barbell', '{"es":{"setup":"Coloca una barra a la altura de la cadera en un rack. Cuélgate debajo con agarre prono, cuerpo recto y talones en el suelo.","execution":"Tira del pecho hacia la barra retrayendo las escápulas. El cuerpo sube como una tabla rígida. Baja con control hasta extensión completa de brazos.","cues":["Cuerpo recto como una plancha","Pecho a la barra, no la barbilla","Aprieta las escápulas arriba"],"mistakes":["Dejar caer la cadera (perder la línea recta)","Subir solo el pecho sin las caderas","No llegar hasta la barra"]},"en":{"setup":"Set a bar at hip height in a rack. Hang underneath with an overhand grip, body straight, heels on the floor.","execution":"Pull your chest to the bar by retracting shoulder blades. Your body rises as a rigid plank. Lower with control to full arm extension.","cues":["Body straight like a plank","Chest to the bar, not chin","Squeeze shoulder blades at the top"],"mistakes":["Letting hips sag (losing the straight line)","Pulling only the chest up without the hips","Not reaching the bar"]}}'::jsonb, true),
    ('Remo renegade con mancuernas', 'Renegade Row', 2, 'weight_reps', 'dumbbell', '{"es":{"setup":"Posición de plancha alta con las manos sobre dos mancuernas. Pies separados (más ancho = más estable). Core activado.","execution":"Rema una mancuerna hacia la cadera mientras te estabilizas con la otra mano. Baja con control y alterna. El cuerpo no debe rotar.","cues":["Caderas quietas, sin rotar","Pies anchos para estabilidad","Core apretado todo el tiempo"],"mistakes":["Rotar las caderas al remar","Pies demasiado juntos (inestable)","Usar impulso en lugar de fuerza controlada"]},"en":{"setup":"High plank position with hands on two dumbbells. Feet wide apart (wider = more stable). Core braced.","execution":"Row one dumbbell toward your hip while stabilizing with the other hand. Lower with control and alternate. Your body should not rotate.","cues":["Hips still, no rotation","Wide feet for stability","Core tight the entire time"],"mistakes":["Rotating the hips when rowing","Feet too close together (unstable)","Using momentum instead of controlled strength"]}}'::jsonb, true),
    ('Peso muerto convencional', 'Conventional Deadlift', 2, 'weight_reps', 'barbell', '{"es":{"setup":"Pies a la anchura de las caderas, barra sobre el medio del pie. Agarre prono o mixto a la anchura de los hombros. Caderas más altas que las rodillas, hombros sobre la barra.","execution":"Empuja el suelo con los pies mientras extiendes caderas y rodillas simultáneamente. La barra sube pegada al cuerpo. Bloquea arriba con glúteos apretados. Baja controladamente invirtiendo el movimiento.","cues":["Empuja el suelo, no tires de la barra","Barra pegada al cuerpo siempre","Espalda neutra de principio a fin"],"mistakes":["Redondear la espalda baja","Alejar la barra del cuerpo","Extender las rodillas antes que las caderas (se convierte en buenos días)"]},"en":{"setup":"Feet hip-width apart, bar over mid-foot. Overhand or mixed grip at shoulder width. Hips higher than knees, shoulders over the bar.","execution":"Push the floor away with your feet while extending hips and knees simultaneously. The bar travels close to your body. Lock out at the top with glutes squeezed. Lower by reversing the movement under control.","cues":["Push the floor, don''t pull the bar","Bar stays glued to your body","Neutral spine from start to finish"],"mistakes":["Rounding the lower back","Bar drifting away from the body","Extending knees before hips (turns into a good morning)"]}}'::jsonb, true),
    ('Peso muerto sumo', 'Sumo Deadlift', 2, 'weight_reps', 'barbell', '{"es":{"setup":"Pies muy separados con las puntas hacia fuera. Agarra la barra entre las piernas con brazos rectos. Caderas cerca de la barra, torso más erguido que en convencional.","execution":"Empuja el suelo hacia fuera con los pies mientras extiendes caderas y rodillas. La barra sube pegada al cuerpo. Bloquea arriba con glúteos apretados.","cues":["Empuja el suelo hacia los lados","Rodillas en la dirección de los pies","Pecho alto, torso más vertical que en convencional"],"mistakes":["Dejar que las rodillas colapsen hacia dentro","Tirar con la espalda en lugar de empujar con las piernas","Caderas suben antes que los hombros"]},"en":{"setup":"Wide stance with toes pointed out. Grip the bar between your legs with straight arms. Hips close to the bar, torso more upright than conventional.","execution":"Push the floor apart with your feet while extending hips and knees. The bar travels close to your body. Lock out at the top with glutes squeezed.","cues":["Push the floor sideways","Knees track over the toes","Chest tall, torso more upright than conventional"],"mistakes":["Letting knees cave inward","Pulling with the back instead of pushing with legs","Hips rising before shoulders"]}}'::jsonb, true),
    ('Rack pull', 'Rack Pull', 2, 'weight_reps', 'barbell', '{"es":{"setup":"Coloca la barra en un rack a la altura de las rodillas o justo por debajo. Agarre prono o mixto a la anchura de los hombros. Posición similar al peso muerto pero con menos flexión de caderas.","execution":"Extiende las caderas llevando la barra pegada al cuerpo hasta el bloqueo. Aprieta los glúteos y trapecios arriba. Baja con control hasta los topes.","cues":["Barra pegada a los muslos","Extiende caderas con fuerza","Bloqueo fuerte arriba: glúteos y espalda"],"mistakes":["Redondear la espalda por exceso de peso","Hiperextender la columna arriba","Dejar caer la barra de golpe en los topes"]},"en":{"setup":"Set the bar in a rack at knee height or just below. Overhand or mixed grip at shoulder width. Similar to deadlift position but with less hip flexion.","execution":"Extend hips, pulling the bar close to your body to lockout. Squeeze glutes and traps at the top. Lower with control to the pins.","cues":["Bar glued to your thighs","Drive hips through with force","Strong lockout: glutes and back"],"mistakes":["Rounding the back due to excessive weight","Hyperextending the spine at the top","Dropping the bar onto the pins"]}}'::jsonb, true),
    ('Encogimientos con barra', 'Barbell Shrug', 2, 'weight_reps', 'barbell', '{"es":{"setup":"De pie con la barra a la altura de los muslos, agarre prono a la anchura de los hombros. Brazos rectos, hombros relajados.","execution":"Sube los hombros rectos hacia las orejas sin flexionar los codos. Aguanta la contracción arriba 1 segundo. Baja con control.","cues":["Hombros rectos hacia arriba, no hacia atrás","Aguanta arriba, no rebotes","Brazos rectos: son solo ganchos"],"mistakes":["Rotar los hombros (no aporta nada y daña la articulación)","Flexionar los codos para subir más","Usar demasiado impulso con las piernas"]},"en":{"setup":"Stand with the bar at thigh level, overhand grip at shoulder width. Arms straight, shoulders relaxed.","execution":"Shrug your shoulders straight up toward your ears without bending elbows. Hold the contraction at the top for 1 second. Lower with control.","cues":["Shoulders straight up, not backward","Hold at the top, don''t bounce","Arms are just hooks — keep them straight"],"mistakes":["Rolling the shoulders (useless and harmful to the joint)","Bending elbows to shrug higher","Using too much leg momentum"]}}'::jsonb, true),
    ('Encogimientos con mancuernas', 'Dumbbell Shrug', 2, 'weight_reps', 'dumbbell', '{"es":{"setup":"De pie con una mancuerna en cada mano a los lados del cuerpo. Brazos rectos, hombros relajados.","execution":"Sube los hombros rectos hacia las orejas sin flexionar los codos. Aguanta 1 segundo arriba. Baja con control.","cues":["Hombros rectos hacia arriba","Pausa arriba, contracción consciente","Los brazos no se doblan"],"mistakes":["Rotar los hombros en círculo","Flexionar codos o usar impulso","Inclinar el torso hacia delante"]},"en":{"setup":"Stand with a dumbbell in each hand at your sides. Arms straight, shoulders relaxed.","execution":"Shrug shoulders straight up toward your ears without bending elbows. Hold for 1 second at the top. Lower with control.","cues":["Shoulders straight up","Pause at the top, conscious contraction","Arms don''t bend"],"mistakes":["Rolling shoulders in circles","Bending elbows or using momentum","Leaning the torso forward"]}}'::jsonb, true),
    ('Encogimientos en máquina Smith', 'Smith Machine Shrug', 2, 'weight_reps', 'smith_machine', '{"es":{"setup":"De pie dentro de la máquina Smith con la barra a la altura de los muslos. Agarre prono a la anchura de los hombros. Desbloquea la barra.","execution":"Sube los hombros rectos hacia las orejas. La guía de la máquina asegura la trayectoria vertical. Aguanta arriba. Baja con control.","cues":["Aprovecha la guía para concentrarte en apretar","Pausa arriba 1 segundo","Movimiento vertical puro"],"mistakes":["Rotar los hombros (la máquina no lo impide)","Flexionar los codos","Usar demasiado peso y hacer medias repeticiones"]},"en":{"setup":"Stand inside the Smith machine with the bar at thigh level. Overhand grip at shoulder width. Unrack the bar.","execution":"Shrug shoulders straight up toward your ears. The machine guide ensures a vertical path. Hold at the top. Lower with control.","cues":["Use the guide to focus on squeezing","Pause at the top for 1 second","Pure vertical movement"],"mistakes":["Rolling shoulders (the machine doesn''t prevent this)","Bending elbows","Too much weight leading to half reps"]}}'::jsonb, true),
    ('Hiperextensiones', 'Back Extensions', 2, 'reps_only', 'bodyweight', '{"es":{"setup":"Colócate en el banco de hiperextensiones con las caderas sobre la almohadilla. Los pies bien sujetos. Brazos cruzados en el pecho o detrás de la cabeza.","execution":"Baja el torso controladamente hasta que quede casi perpendicular al suelo. Sube contrayendo los erectores y glúteos hasta que el cuerpo forme una línea recta. No hiperextiendas.","cues":["Sube hasta la línea recta, no más","Aprieta glúteos arriba","Baja controlado, sin dejarte caer"],"mistakes":["Hiperextender la columna (subir demasiado)","Bajar de golpe sin control","Redondear la espalda en la bajada"]},"en":{"setup":"Position yourself on the hyperextension bench with hips on the pad. Feet secured. Arms crossed on your chest or behind your head.","execution":"Lower your torso in a controlled manner until nearly perpendicular to the floor. Rise by contracting your spinal erectors and glutes until your body forms a straight line. Do not hyperextend.","cues":["Rise to a straight line, no further","Squeeze glutes at the top","Lower under control, don''t drop"],"mistakes":["Hyperextending the spine (going too high)","Dropping down without control","Rounding the back on the descent"]}}'::jsonb, true),
    ('Hiperextensiones con peso', 'Weighted Back Extensions', 2, 'weight_reps', 'bodyweight', '{"es":{"setup":"Colócate en el banco de hiperextensiones con un disco abrazado al pecho o una barra detrás de la nuca. Caderas sobre la almohadilla, pies sujetos.","execution":"Baja el torso controladamente. Sube contrayendo erectores y glúteos hasta la línea recta. No hiperextiendas. Mantén el peso pegado al cuerpo.","cues":["Peso pegado al cuerpo, no alejado","Línea recta arriba, no más","Movimiento lento y controlado"],"mistakes":["Hiperextender la columna por inercia del peso","Usar demasiado peso comprometiendo la técnica","Alejar el peso del cuerpo (aumento de palanca peligroso)"]},"en":{"setup":"Position yourself on the hyperextension bench holding a plate against your chest or a bar behind your neck. Hips on the pad, feet secured.","execution":"Lower your torso under control. Rise by contracting erectors and glutes to a straight line. Do not hyperextend. Keep the weight close to your body.","cues":["Weight close to the body, not away","Straight line at the top, no further","Slow, controlled movement"],"mistakes":["Hyperextending the spine due to weight momentum","Too much weight compromising technique","Holding weight away from the body (dangerous leverage increase)"]}}'::jsonb, true),
    ('Elevaciones en Y en banco inclinado', 'Incline Bench Y-Raise', 2, 'weight_reps', 'dumbbell', '{"es":{"setup":"Túmbate boca abajo en un banco inclinado a unos 30-45°. Brazos colgando con mancuernas ligeras y pulgares hacia arriba.","execution":"Eleva los brazos en forma de Y (hacia delante y hacia fuera a unos 45° del cuerpo) hasta la altura de la cabeza. Baja con control. Usa peso ligero.","cues":["Forma de Y con los brazos","Pulgares hacia arriba","Peso ligero, aquí importa la activación"],"mistakes":["Usar demasiado peso (es un ejercicio de activación)","Subir los brazos rectos al frente (sería una I, no una Y)","Encoger los hombros al subir"]},"en":{"setup":"Lie face down on an incline bench set to 30-45°. Arms hanging with light dumbbells and thumbs pointing up.","execution":"Raise your arms in a Y shape (forward and out at about 45° from the body) to head height. Lower with control. Use light weight.","cues":["Y shape with your arms","Thumbs pointing up","Light weight — activation matters here"],"mistakes":["Using too much weight (this is an activation exercise)","Raising arms straight forward (that''s an I, not a Y)","Shrugging shoulders while raising"]}}'::jsonb, true),
    ('Face pull en polea', 'Cable Face Pull', 4, 'weight_reps', 'cable', '{"es":{"setup":"Polea a la altura de la cara. Agarra la cuerda con ambas manos, palmas enfrentadas. Da un paso atrás con los brazos extendidos.","execution":"Tira de la cuerda hacia la cara separando los extremos y llevando los codos hacia atrás y arriba. Rota externamente los hombros al final. Vuelve con control.","cues":["Codos altos, por encima de los hombros","Separa la cuerda y rota los hombros hacia fuera","Aprieta entre las escápulas"],"mistakes":["Codos caídos (lo convierte en un remo)","No separar la cuerda al final","Usar impulso echándose hacia atrás"]},"en":{"setup":"Set pulley at face height. Grip the rope with both hands, palms facing each other. Step back with arms extended.","execution":"Pull the rope toward your face, spreading the ends apart and driving elbows back and high. Externally rotate your shoulders at the end. Return with control.","cues":["Elbows high, above shoulder level","Split the rope and rotate shoulders outward","Squeeze between shoulder blades"],"mistakes":["Dropping elbows (turns it into a row)","Not splitting the rope at the end","Using momentum by leaning back"]}}'::jsonb, true),
    ('Press militar con barra de pie', 'Standing Barbell Overhead Press', 4, 'weight_reps', 'barbell', '{"es":{"setup":"De pie con los pies a la anchura de los hombros. Agarra la barra a la anchura de los hombros, apoyada en la parte alta del pecho con los codos ligeramente por delante.","execution":"Empuja la barra hacia arriba en línea recta, apartando la cabeza al paso de la barra. Bloquea los codos arriba con la barra sobre la línea media del pie. Baja controladamente hasta el pecho.","cues":["Aprieta glúteos y abdomen antes de empujar","La barra sube recta, no hacia delante","Cabeza a través al final del movimiento"],"mistakes":["Arquear excesivamente la espalda baja","Inclinar el torso hacia atrás convirtiendo el press en inclinado","No bloquear completamente arriba"]},"en":{"setup":"Stand with feet shoulder-width apart. Grip the bar at shoulder width, resting on upper chest with elbows slightly in front.","execution":"Press the bar straight up, moving your head out of the way as the bar passes. Lock out overhead with the bar over midfoot. Lower under control back to your chest.","cues":["Squeeze glutes and brace core before pressing","Bar path goes straight up, not forward","Push head through at the top"],"mistakes":["Excessive lower back arch","Leaning back and turning it into an incline press","Not fully locking out overhead"]}}'::jsonb, true),
    ('Press militar con barra sentado', 'Seated Barbell Overhead Press', 4, 'weight_reps', 'barbell', '{"es":{"setup":"Siéntate en un banco con respaldo vertical (85-90°). Agarra la barra a la anchura de los hombros, apoyada en la parte alta del pecho.","execution":"Empuja la barra verticalmente, apartando la cabeza al paso. Bloquea arriba y baja controladamente hasta la clavícula.","cues":["Espalda pegada al respaldo","Empuja recto hacia el techo","Codos apuntando ligeramente adelante al inicio"],"mistakes":["Despegar la espalda baja del respaldo","Bajar la barra por detrás de la cabeza","Rebotar la barra en el pecho"]},"en":{"setup":"Sit on a bench with back support at 85-90°. Grip the bar at shoulder width, resting on upper chest.","execution":"Press the bar straight up, moving your head out of the way. Lock out at the top and lower under control to collarbone level.","cues":["Keep back flat against the pad","Press straight toward the ceiling","Elbows slightly forward at the bottom"],"mistakes":["Arching lower back off the bench","Lowering the bar behind the head","Bouncing the bar off the chest"]}}'::jsonb, true),
    ('Press de hombros con mancuernas sentado', 'Seated Dumbbell Shoulder Press', 4, 'weight_reps', 'dumbbell', '{"es":{"setup":"Siéntate en un banco con respaldo a 85-90°. Sube las mancuernas a la altura de los hombros con las palmas mirando al frente y los codos a unos 45° del torso.","execution":"Empuja las mancuernas hacia arriba juntándolas ligeramente en la parte alta sin chocarlas. Baja controladamente hasta que los codos queden a la altura del hombro o ligeramente por debajo.","cues":["Espalda pegada al respaldo","No choques las mancuernas arriba","Baja hasta que los brazos formen 90°"],"mistakes":["Abrir los codos demasiado (en línea con los hombros)","Usar impulso con la espalda baja","Rango de movimiento incompleto"]},"en":{"setup":"Sit on a bench set to 85-90°. Bring dumbbells to shoulder height, palms facing forward, elbows at roughly 45° from your torso.","execution":"Press the dumbbells up, converging slightly at the top without clanking them. Lower under control until elbows are at or slightly below shoulder level.","cues":["Keep back against the pad","Don''t bang dumbbells together at top","Lower until upper arms are at least parallel to floor"],"mistakes":["Flaring elbows directly out to the sides","Using momentum from the lower back","Partial range of motion"]}}'::jsonb, true),
    ('Press de hombros con mancuernas de pie', 'Standing Dumbbell Shoulder Press', 4, 'weight_reps', 'dumbbell', '{"es":{"setup":"De pie con los pies a la anchura de los hombros. Sube las mancuernas a la altura de los hombros con las palmas al frente.","execution":"Empuja las mancuernas hacia arriba convergiendo ligeramente en la parte alta. Baja controladamente hasta la altura de los hombros. Mantén el core activado durante todo el movimiento.","cues":["Aprieta glúteos y abdomen","No te inclines hacia atrás","Controla la bajada"],"mistakes":["Arquear la espalda para generar impulso","Usar las piernas para ayudar al empuje","Dejar que las mancuernas caigan sin control"]},"en":{"setup":"Stand with feet shoulder-width apart. Bring dumbbells to shoulder height, palms facing forward.","execution":"Press dumbbells overhead, converging slightly at the top. Lower under control to shoulder level. Keep your core braced throughout the movement.","cues":["Squeeze glutes and brace core","Don''t lean back","Control the descent"],"mistakes":["Arching the back for momentum","Using leg drive to assist the press","Dropping the dumbbells without control"]}}'::jsonb, true),
    ('Press Arnold', 'Arnold Press', 4, 'weight_reps', 'dumbbell', '{"es":{"setup":"Siéntate en banco con respaldo a 85-90°. Sube las mancuernas a la altura del pecho con las palmas mirando hacia ti (como al final de un curl).","execution":"Empuja hacia arriba mientras rotas las muñecas, de modo que al llegar arriba las palmas miren al frente. Invierte el movimiento al bajar, terminando con palmas hacia ti.","cues":["La rotación ocurre durante la subida, no antes","Movimiento fluido, sin pausas","Codos a 45° del torso en la posición baja"],"mistakes":["Rotar las muñecas antes de empezar a subir","Hacer la rotación demasiado rápido o brusca","No completar el rango de rotación"]},"en":{"setup":"Sit on a bench at 85-90°. Hold dumbbells at chest height with palms facing you (like the top of a curl).","execution":"Press upward while rotating your wrists so palms face forward at the top. Reverse the motion on the way down, finishing with palms facing you.","cues":["Rotation happens during the press, not before","Smooth continuous motion, no pauses","Elbows at 45° from torso at the bottom"],"mistakes":["Rotating wrists before starting the press","Jerky or rushed rotation","Not completing full rotation range"]}}'::jsonb, true),
    ('Press de hombros en máquina', 'Machine Shoulder Press', 4, 'weight_reps', 'machine', '{"es":{"setup":"Ajusta el asiento para que los agarres queden a la altura de los hombros. Siéntate con la espalda pegada al respaldo y agarra las empuñaduras.","execution":"Empuja los agarres hacia arriba hasta extender los brazos sin bloquear completamente. Baja controladamente hasta que los codos queden a la altura de los hombros.","cues":["Espalda siempre en contacto con el respaldo","Empuja de forma simétrica con ambos brazos","No bloquees los codos del todo arriba"],"mistakes":["Despegar la espalda del respaldo","Ajustar el asiento demasiado bajo (hombros por encima de las manos)","Usar rango parcial"]},"en":{"setup":"Adjust the seat so handles are at shoulder height. Sit with your back flat against the pad and grip the handles.","execution":"Press the handles upward until arms are extended without fully locking out. Lower under control until elbows return to shoulder height.","cues":["Keep back against the pad at all times","Push evenly with both arms","Don''t fully lock out elbows at top"],"mistakes":["Lifting back off the pad","Setting the seat too low (shoulders above hands)","Using partial range of motion"]}}'::jsonb, true),
    ('Press de hombros en máquina Smith', 'Smith Machine Shoulder Press', 4, 'weight_reps', 'smith_machine', '{"es":{"setup":"Coloca un banco con respaldo a 85-90° dentro de la Smith. Ajusta la altura de la barra para que quede a la altura de la barbilla al sentarte. Agarre a la anchura de los hombros.","execution":"Destraba la barra y empuja hacia arriba hasta extender los brazos. Baja controladamente hasta la altura de la barbilla o la parte alta del pecho.","cues":["Siéntate bien centrado bajo la barra","Espalda pegada al respaldo","Baja hasta que los codos formen 90°"],"mistakes":["Sentarse demasiado adelante o atrás respecto a la barra","Bajar la barra por detrás de la cabeza","No destrabar correctamente antes de empezar"]},"en":{"setup":"Place a bench at 85-90° inside the Smith machine. Set bar height to chin level when seated. Grip at shoulder width.","execution":"Unrack the bar and press up to arm extension. Lower under control to chin or upper chest level.","cues":["Sit centered under the bar","Keep back flat against the pad","Lower until elbows reach 90°"],"mistakes":["Sitting too far forward or back relative to the bar path","Lowering the bar behind the head","Failing to properly unrack before starting"]}}'::jsonb, true),
    ('Push press con barra', 'Barbell Push Press', 4, 'weight_reps', 'barbell', '{"es":{"setup":"De pie con los pies a la anchura de las caderas. Barra apoyada en la parte alta del pecho con agarre a la anchura de los hombros, codos ligeramente adelantados.","execution":"Haz un leve dip de rodillas (un cuarto de sentadilla) y explota hacia arriba usando las piernas para impulsar la barra. Termina el empuje con los brazos hasta bloquear arriba. Baja la barra controladamente al pecho.","cues":["El dip es corto y rápido, no una sentadilla","Piernas y brazos trabajan en secuencia","Bloquea arriba con la barra sobre el centro del pie"],"mistakes":["Hacer el dip demasiado profundo","Empujar la barra hacia delante en vez de recto","No usar las piernas y convertirlo en press estricto"]},"en":{"setup":"Stand with feet hip-width apart. Bar resting on upper chest, shoulder-width grip, elbows slightly forward.","execution":"Perform a short knee dip (quarter squat) then explosively drive through your legs to launch the bar upward. Finish pressing with your arms to lockout. Lower the bar under control to chest.","cues":["Dip is short and explosive, not a squat","Legs then arms in sequence","Lock out with bar over midfoot"],"mistakes":["Dipping too deep","Pushing the bar forward instead of straight up","Not using leg drive, turning it into a strict press"]}}'::jsonb, true),
    ('Elevaciones laterales con mancuernas', 'Dumbbell Lateral Raise', 4, 'weight_reps', 'dumbbell', '{"es":{"setup":"De pie con mancuernas a los lados, ligera flexión de codos. Pies a la anchura de los hombros, torso ligeramente inclinado hacia delante.","execution":"Eleva los brazos hacia los lados hasta la altura de los hombros, manteniendo la ligera flexión de codos. Baja controladamente sin dejar caer el peso.","cues":["Lidera con los codos, no con las manos","Meñique ligeramente más alto que el pulgar arriba","Sin impulso del cuerpo"],"mistakes":["Subir las mancuernas por encima del hombro (involucra trapecios)","Balancear el torso para generar impulso","Usar demasiado peso sacrificando la técnica"]},"en":{"setup":"Stand holding dumbbells at your sides with a slight elbow bend. Feet shoulder-width apart, torso slightly leaning forward.","execution":"Raise arms out to the sides until shoulder height, keeping the slight elbow bend. Lower under control without dropping the weight.","cues":["Lead with elbows, not hands","Pinky slightly higher than thumb at the top","No body momentum"],"mistakes":["Raising dumbbells above shoulder height (recruits traps)","Swinging the torso for momentum","Using too much weight and sacrificing form"]}}'::jsonb, true),
    ('Elevaciones laterales en polea', 'Cable Lateral Raise', 4, 'weight_reps', 'cable', '{"es":{"setup":"Coloca la polea en la posición más baja. De pie de lado a la máquina, agarra el asa con la mano más alejada. Ligera flexión de codos.","execution":"Eleva el brazo hacia el lado hasta la altura del hombro, manteniendo la flexión de codo constante. Baja lentamente resistiendo la tensión del cable.","cues":["Lidera con el codo","Mantén el torso firme, sin inclinarte","Pausa breve arriba"],"mistakes":["Girar el torso para ayudar a subir","Usar impulso tirando con el cuerpo","Dejar que el cable tire el brazo sin control en la bajada"]},"en":{"setup":"Set the cable pulley to the lowest position. Stand sideways to the machine and grab the handle with the far hand. Maintain a slight elbow bend.","execution":"Raise your arm out to the side to shoulder height, keeping elbow bend constant. Lower slowly, resisting the cable tension.","cues":["Lead with the elbow","Keep torso still, don''t lean","Brief pause at the top"],"mistakes":["Rotating the torso to assist the lift","Using body momentum to swing the weight up","Letting the cable pull the arm down without control"]}}'::jsonb, true),
    ('Elevaciones laterales en máquina', 'Machine Lateral Raise', 4, 'weight_reps', 'machine', '{"es":{"setup":"Ajusta el asiento para que las almohadillas queden justo por encima de los codos. Siéntate con la espalda recta y los brazos a los lados.","execution":"Eleva los brazos hacia los lados empujando con los codos contra las almohadillas hasta la altura de los hombros. Baja lentamente resistiendo el peso.","cues":["Empuja con los codos, no con las manos","Sube hasta la línea del hombro, no más","Controla especialmente la bajada"],"mistakes":["Encoger los hombros al subir","Subir por encima de la horizontal","Soltar el peso en la bajada"]},"en":{"setup":"Adjust the seat so pads rest just above your elbows. Sit with back straight and arms at your sides.","execution":"Raise your arms to the sides by pushing elbows into the pads up to shoulder height. Lower slowly, resisting the weight.","cues":["Push with elbows, not hands","Raise to shoulder line, no higher","Control the eccentric especially"],"mistakes":["Shrugging shoulders on the way up","Raising above horizontal","Dropping the weight on the way down"]}}'::jsonb, true),
    ('Elevaciones laterales inclinado en banco', 'Incline Bench Lateral Raise', 4, 'weight_reps', 'dumbbell', '{"es":{"setup":"Inclina un banco a unos 30-45°. Recuéstate de lado con el brazo de trabajo colgando perpendicular al suelo, mancuerna en mano.","execution":"Eleva la mancuerna lateralmente hasta la altura del hombro manteniendo ligera flexión de codo. Baja controladamente. La inclinación del banco aumenta la tensión en la parte baja del recorrido.","cues":["Mantén el cuerpo pegado al banco","Movimiento lento y controlado","Siente el estiramiento abajo"],"mistakes":["Rotar el torso para ayudarse","Usar impulso desde la posición inclinada","Rango de movimiento incompleto"]},"en":{"setup":"Set a bench to 30-45°. Lie on your side with the working arm hanging perpendicular to the floor, dumbbell in hand.","execution":"Raise the dumbbell laterally to shoulder height with a slight elbow bend. Lower under control. The incline increases tension at the bottom of the range.","cues":["Keep your body pressed against the bench","Slow and controlled movement","Feel the stretch at the bottom"],"mistakes":["Rotating the torso to assist","Using momentum from the inclined position","Incomplete range of motion"]}}'::jsonb, true),
    ('Elevaciones frontales con mancuernas', 'Dumbbell Front Raise', 4, 'weight_reps', 'dumbbell', '{"es":{"setup":"De pie con mancuernas frente a los muslos, palmas mirando hacia el cuerpo. Ligera flexión de codos.","execution":"Eleva una o ambas mancuernas al frente hasta la altura de los hombros. Baja controladamente sin dejar caer el peso.","cues":["Brazo recto pero no bloqueado","Solo hasta la altura del hombro","Sin balanceo del cuerpo"],"mistakes":["Subir por encima de la horizontal","Balancear el torso para impulsar el peso","Arquear la espalda baja"]},"en":{"setup":"Stand with dumbbells in front of your thighs, palms facing your body. Slight elbow bend.","execution":"Raise one or both dumbbells to the front until shoulder height. Lower under control without dropping the weight.","cues":["Arm straight but not locked","Only to shoulder height","No body swing"],"mistakes":["Raising above horizontal","Swinging the torso for momentum","Arching the lower back"]}}'::jsonb, true),
    ('Elevaciones frontales con barra', 'Barbell Front Raise', 4, 'weight_reps', 'barbell', '{"es":{"setup":"De pie con la barra apoyada en los muslos, agarre a la anchura de los hombros o ligeramente más estrecho, palmas hacia el cuerpo.","execution":"Eleva la barra al frente hasta la altura de los hombros manteniendo los brazos casi extendidos. Baja lentamente hasta los muslos.","cues":["Core activo todo el rato","Movimiento controlado, sin tirones","Para a la altura de los ojos"],"mistakes":["Usar impulso inclinando el torso atrás","Subir demasiado alto (involucra trapecios)","Flexionar demasiado los codos"]},"en":{"setup":"Stand with the bar resting on your thighs, shoulder-width or slightly narrower grip, palms facing your body.","execution":"Raise the bar to the front until shoulder height with arms nearly extended. Lower slowly back to thighs.","cues":["Brace your core throughout","Controlled movement, no jerking","Stop at eye level"],"mistakes":["Using momentum by leaning the torso back","Raising too high (recruits traps)","Bending elbows too much"]}}'::jsonb, true),
    ('Elevaciones frontales en polea', 'Cable Front Raise', 4, 'weight_reps', 'cable', '{"es":{"setup":"Polea en posición baja. De espaldas a la máquina, pasa el cable entre las piernas y agarra el asa con una o ambas manos.","execution":"Eleva el brazo o barra al frente hasta la altura del hombro. Baja resistiendo la tensión del cable durante todo el recorrido.","cues":["Tensión constante en todo el rango","Sin balanceo del cuerpo","Pausa arriba un instante"],"mistakes":["Inclinarse hacia atrás para facilitar la subida","Perder la tensión al bajar demasiado rápido","Flexionar excesivamente los codos"]},"en":{"setup":"Set cable to lowest position. Stand facing away from the machine, pass the cable between your legs and grab the handle with one or both hands.","execution":"Raise the handle to the front until shoulder height. Lower resisting the cable tension through the full range.","cues":["Constant tension throughout the range","No body swing","Brief pause at the top"],"mistakes":["Leaning back to make the lift easier","Losing tension by lowering too fast","Excessive elbow bending"]}}'::jsonb, true),
    ('Elevaciones frontales con disco', 'Plate Front Raise', 4, 'weight_reps', 'plate', '{"es":{"setup":"De pie con un disco sujeto con ambas manos a las 3 y las 9 (por los lados), brazos extendidos frente a los muslos.","execution":"Eleva el disco al frente hasta la altura de los hombros o ligeramente por encima. Baja de forma controlada hasta los muslos.","cues":["Agarra fuerte el disco por los lados","Core apretado, sin balanceo","Brazos casi rectos"],"mistakes":["Dejar que el disco gire o se incline","Usar impulso del cuerpo","Subir demasiado rápido y sin control"]},"en":{"setup":"Stand holding a plate with both hands at the 3 and 9 o''clock positions (by the sides), arms extended in front of thighs.","execution":"Raise the plate to the front to shoulder height or slightly above. Lower under control back to thighs.","cues":["Grip the plate firmly by the sides","Core tight, no swinging","Arms nearly straight"],"mistakes":["Letting the plate tilt or rotate","Using body momentum","Raising too fast without control"]}}'::jsonb, true),
    ('Pájaros con mancuernas', 'Dumbbell Reverse Fly', 4, 'weight_reps', 'dumbbell', '{"es":{"setup":"Inclínate hacia delante con el torso casi paralelo al suelo, rodillas ligeramente flexionadas. Mancuernas colgando debajo del pecho con palmas enfrentadas.","execution":"Abre los brazos hacia los lados apretando las escápulas, manteniendo ligera flexión de codos. Sube hasta la línea del torso y baja controladamente.","cues":["Aprieta las escápulas arriba","Codos ligeramente flexionados y fijos","Torso inmóvil durante todo el movimiento"],"mistakes":["Usar impulso levantando el torso","Subir demasiado y encoger los trapecios","Cambiar el ángulo de flexión de los codos durante el movimiento"]},"en":{"setup":"Hinge forward with torso nearly parallel to the floor, knees slightly bent. Dumbbells hanging below chest, palms facing each other.","execution":"Open arms out to the sides squeezing your shoulder blades, keeping a slight elbow bend. Raise to torso level and lower under control.","cues":["Squeeze shoulder blades at the top","Slight elbow bend, keep it fixed","Torso stays still throughout"],"mistakes":["Using momentum by lifting the torso","Going too high and shrugging the traps","Changing elbow angle during the movement"]}}'::jsonb, true),
    ('Pájaros en polea', 'Cable Reverse Fly', 4, 'weight_reps', 'cable', '{"es":{"setup":"Poleas a la altura del pecho, cruzando los cables. Agarra el asa izquierda con la mano derecha y viceversa, sin accesorios o con asas de estribo.","execution":"Abre los brazos hacia los lados separando las manos con ligera flexión de codos. Aprieta las escápulas al final del recorrido. Vuelve controladamente al inicio.","cues":["Brazos a la altura de los hombros","Aprieta escápulas al abrir","Sin mover el torso"],"mistakes":["Flexionar demasiado los codos (convierte el ejercicio en remo)","Usar impulso del cuerpo","No cruzar los cables correctamente"]},"en":{"setup":"Set both pulleys at chest height with cables crossed. Grab the left handle with your right hand and vice versa.","execution":"Open your arms out to the sides with a slight elbow bend. Squeeze shoulder blades at the end. Return under control to the starting position.","cues":["Arms at shoulder height","Squeeze shoulder blades as you open","Keep torso still"],"mistakes":["Bending elbows too much (turns it into a row)","Using body momentum","Not crossing cables properly"]}}'::jsonb, true),
    ('Pájaros en máquina pec deck inversa', 'Reverse Pec Deck Fly', 4, 'weight_reps', 'machine', '{"es":{"setup":"Siéntate mirando hacia la máquina (al revés del uso normal). Ajusta los brazos para que las asas queden frente a ti a la altura de los hombros. Pecho contra el respaldo.","execution":"Abre los brazos hacia atrás apretando las escápulas al final. Vuelve controladamente sin que las placas lleguen a tocarse.","cues":["Pecho pegado al respaldo","Abre hasta sentir la contracción en el deltoides trasero","No dejes que el peso descanse entre repeticiones"],"mistakes":["Despegar el pecho del respaldo","Usar demasiado peso y encoger trapecios","Dejar caer el peso en la fase negativa"]},"en":{"setup":"Sit facing the machine (reverse of normal use). Adjust arms so handles are in front of you at shoulder height. Chest pressed against the pad.","execution":"Open your arms back, squeezing shoulder blades at the end. Return under control without letting the weight stack touch down.","cues":["Chest stays against the pad","Open until you feel rear delt contraction","Don''t let weight rest between reps"],"mistakes":["Lifting chest off the pad","Too much weight causing trap shrugging","Dropping the weight on the negative phase"]}}'::jsonb, true),
    ('Pájaros inclinado en banco', 'Incline Bench Reverse Fly', 4, 'weight_reps', 'dumbbell', '{"es":{"setup":"Inclina un banco a 30-45°. Túmbate boca abajo con el pecho apoyado en el banco. Mancuernas colgando con los brazos perpendiculares al suelo.","execution":"Abre los brazos hacia los lados apretando las escápulas arriba. Mantén ligera flexión de codos. Baja de forma controlada.","cues":["El banco elimina el impulso del cuerpo","Lidera con los codos","Aprieta escápulas 1 segundo arriba"],"mistakes":["Levantar el pecho del banco","Usar demasiado peso perdiendo el rango","No mantener la flexión de codos constante"]},"en":{"setup":"Set a bench to 30-45°. Lie face down with your chest supported on the bench. Dumbbells hanging with arms perpendicular to the floor.","execution":"Open arms to the sides, squeezing shoulder blades at the top. Maintain a slight elbow bend. Lower under control.","cues":["The bench eliminates body momentum","Lead with elbows","Squeeze shoulder blades for 1 second at top"],"mistakes":["Lifting chest off the bench","Using too much weight and losing range","Not keeping elbow bend constant"]}}'::jsonb, true),
    ('Remo al mentón con barra', 'Barbell Upright Row', 4, 'weight_reps', 'barbell', '{"es":{"setup":"De pie con la barra frente a los muslos, agarre algo más estrecho que la anchura de los hombros. Pies a la anchura de las caderas.","execution":"Tira de la barra hacia arriba pegada al cuerpo, liderando con los codos hacia fuera y arriba. Sube hasta que los codos lleguen a la altura de los hombros. Baja controladamente.","cues":["Los codos siempre más altos que las manos","Barra pegada al cuerpo","No subas los codos por encima de los hombros"],"mistakes":["Subir los codos muy por encima de los hombros (riesgo de impingement)","Agarre demasiado estrecho","Usar impulso balanceando el torso"]},"en":{"setup":"Stand with the bar in front of your thighs, grip slightly narrower than shoulder width. Feet hip-width apart.","execution":"Pull the bar upward close to your body, leading with elbows out and up. Raise until elbows reach shoulder height. Lower under control.","cues":["Elbows always higher than hands","Keep bar close to your body","Don''t raise elbows above shoulder level"],"mistakes":["Raising elbows far above shoulders (impingement risk)","Too narrow a grip","Using body swing for momentum"]}}'::jsonb, true),
    ('Remo al mentón con mancuernas', 'Dumbbell Upright Row', 4, 'weight_reps', 'dumbbell', '{"es":{"setup":"De pie con mancuernas frente a los muslos, palmas mirando al cuerpo. Pies a la anchura de las caderas.","execution":"Tira de las mancuernas hacia arriba pegadas al cuerpo, codos hacia fuera y arriba. Las mancuernas permiten un recorrido más natural para los hombros. Baja controladamente.","cues":["Codos lideran el movimiento","Las mancuernas suben junto al cuerpo","Hasta la altura de los hombros, no más"],"mistakes":["Subir los codos por encima de los hombros","Separar las mancuernas del cuerpo","Encoger los trapecios en vez de abrir los codos"]},"en":{"setup":"Stand with dumbbells in front of your thighs, palms facing your body. Feet hip-width apart.","execution":"Pull the dumbbells upward close to your body, elbows out and up. Dumbbells allow a more natural shoulder path. Lower under control.","cues":["Elbows lead the movement","Dumbbells travel close to the body","To shoulder height, no higher"],"mistakes":["Raising elbows above shoulders","Letting dumbbells drift away from the body","Shrugging traps instead of opening elbows"]}}'::jsonb, true),
    ('Remo al mentón en polea', 'Cable Upright Row', 4, 'weight_reps', 'cable', '{"es":{"setup":"Polea en posición baja con barra recta o EZ. De pie frente a la máquina, agarra la barra con las manos algo más estrechas que los hombros.","execution":"Tira de la barra hacia arriba pegada al cuerpo, codos hacia fuera. La tensión del cable mantiene la carga constante. Sube hasta la altura de los hombros y baja controladamente.","cues":["Codos siempre por encima de las manos","Tensión constante gracias al cable","Torso recto y estable"],"mistakes":["Inclinarse hacia atrás","Subir más allá de la línea de los hombros","Usar tirón brusco al inicio"]},"en":{"setup":"Set cable to lowest position with a straight or EZ bar. Stand facing the machine, grip slightly narrower than shoulder width.","execution":"Pull the bar upward close to your body with elbows flaring out. Cable provides constant tension. Raise to shoulder height and lower under control.","cues":["Elbows always above hands","Constant tension from the cable","Torso upright and stable"],"mistakes":["Leaning back","Raising beyond shoulder line","Jerking at the start of the rep"]}}'::jsonb, true),
    ('Rotación externa con mancuerna', 'Dumbbell External Rotation', 4, 'weight_reps', 'dumbbell', '{"es":{"setup":"Túmbate de lado o de pie con el codo pegado al costado flexionado a 90°. Mancuerna ligera en la mano del brazo de trabajo. Puedes poner una toalla entre el codo y el torso.","execution":"Rota el antebrazo hacia fuera manteniendo el codo pegado al costado. Vuelve lentamente a la posición inicial. El movimiento es solo rotación, no extensión.","cues":["Codo fijo pegado al cuerpo","Movimiento lento y controlado","Peso ligero, esto es rehabilitación/prehab"],"mistakes":["Despegar el codo del costado","Usar demasiado peso","Mover todo el brazo en vez de solo rotar"]},"en":{"setup":"Lie on your side or stand with elbow pinned to your side at 90°. Light dumbbell in the working hand. You can place a towel between elbow and torso.","execution":"Rotate your forearm outward keeping the elbow against your side. Slowly return to start. The movement is pure rotation, not extension.","cues":["Elbow stays glued to your side","Slow and controlled movement","Light weight — this is prehab"],"mistakes":["Letting the elbow drift away from your body","Using too much weight","Moving the whole arm instead of just rotating"]}}'::jsonb, true),
    ('Rotación externa en polea', 'Cable External Rotation', 4, 'weight_reps', 'cable', '{"es":{"setup":"Polea a la altura del codo. De pie de lado a la máquina, agarra el asa con la mano más alejada. Codo pegado al costado a 90°.","execution":"Rota el antebrazo hacia fuera alejándolo de la polea, manteniendo el codo fijo contra el costado. Vuelve controladamente.","cues":["Codo inmóvil pegado al cuerpo","Solo rota, no tires","Usa peso ligero"],"mistakes":["Compensar con rotación del torso","Despegar el codo del costado","Hacer el movimiento demasiado rápido"]},"en":{"setup":"Set cable at elbow height. Stand sideways to the machine, grab the handle with the far hand. Elbow pinned to your side at 90°.","execution":"Rotate your forearm outward away from the cable, keeping elbow fixed against your side. Return under control.","cues":["Elbow stays glued to your side","Only rotate, don''t pull","Use light weight"],"mistakes":["Compensating with torso rotation","Letting elbow drift from your side","Performing the movement too fast"]}}'::jsonb, true),
    ('Rotación externa con banda', 'Band External Rotation', 4, 'reps_only', 'band', '{"es":{"setup":"Sujeta una banda elástica con ambas manos, codos pegados al costado a 90°. Los antebrazos apuntan al frente, paralelos entre sí.","execution":"Rota ambos antebrazos hacia fuera estirando la banda, manteniendo los codos pegados al cuerpo. Vuelve lentamente a la posición inicial sin perder tensión.","cues":["Codos pegados al cuerpo todo el rato","Movimiento suave y controlado","Mantén algo de tensión en la banda incluso al volver"],"mistakes":["Separar los codos del torso","Hacer el movimiento rápido y sin control","Usar una banda demasiado dura"]},"en":{"setup":"Hold a resistance band with both hands, elbows pinned to your sides at 90°. Forearms pointing forward, parallel to each other.","execution":"Rotate both forearms outward stretching the band, keeping elbows against your body. Slowly return to start without losing all tension.","cues":["Elbows glued to your body throughout","Smooth, controlled movement","Keep some band tension even at the start position"],"mistakes":["Letting elbows drift from your torso","Rushing the movement without control","Using a band that''s too heavy"]}}'::jsonb, true),
    ('Pull-apart con banda', 'Band Pull-Apart', 4, 'reps_only', 'band', '{"es":{"setup":"De pie con los brazos extendidos al frente a la altura de los hombros. Sujeta una banda elástica con ambas manos, separadas a la anchura de los hombros.","execution":"Abre los brazos hacia los lados estirando la banda hasta que toque el pecho. Aprieta las escápulas al final. Vuelve controladamente.","cues":["Brazos rectos durante todo el movimiento","Aprieta las escápulas al abrir","Pecho arriba, hombros abajo"],"mistakes":["Flexionar los codos para facilitar el movimiento","No abrir completamente hasta el pecho","Encoger los hombros al separar"]},"en":{"setup":"Stand with arms extended in front at shoulder height. Hold a band with both hands, shoulder-width apart.","execution":"Pull your arms apart, stretching the band until it touches your chest. Squeeze shoulder blades at the end. Return under control.","cues":["Keep arms straight throughout","Squeeze shoulder blades as you pull apart","Chest up, shoulders down"],"mistakes":["Bending elbows to make it easier","Not opening fully to the chest","Shrugging shoulders as you pull apart"]}}'::jsonb, true),
    ('Landmine press', 'Landmine Press', 4, 'weight_reps', 'barbell', '{"es":{"setup":"Coloca un extremo de la barra en una esquina o en un accesorio landmine. De pie frente al extremo libre, sujétalo con ambas manos a la altura del pecho.","execution":"Empuja la barra hacia arriba y ligeramente al frente siguiendo el arco natural del landmine. Extiende los brazos y vuelve controladamente al pecho.","cues":["Core apretado para estabilizar","Empuja en el arco natural, no luches contra él","Codos cerca del cuerpo"],"mistakes":["Arquear la espalda baja","Usar las piernas para impulsar","Agarrar la barra demasiado lejos del extremo"]},"en":{"setup":"Place one end of a barbell in a corner or landmine attachment. Stand facing the free end, hold it with both hands at chest height.","execution":"Press the bar up and slightly forward following the natural landmine arc. Extend your arms and return under control to chest.","cues":["Brace core to stabilize","Press along the natural arc, don''t fight it","Elbows close to body"],"mistakes":["Arching the lower back","Using leg drive to assist","Gripping too far from the end of the bar"]}}'::jsonb, true),
    ('Landmine press unilateral', 'Single-Arm Landmine Press', 4, 'weight_reps', 'barbell', '{"es":{"setup":"Barra en landmine. De pie en posición escalonada (pie contrario al brazo de trabajo adelantado). Sujeta el extremo con una mano a la altura del hombro.","execution":"Empuja la barra hacia arriba y al frente con un brazo siguiendo el arco natural. Extiende el brazo completamente y baja controladamente.","cues":["Posición escalonada para estabilidad","Core muy activo contra la rotación","Empuja en diagonal siguiendo el arco"],"mistakes":["Rotar el torso para ayudar al empuje","No estabilizar con el core (la barra tira de ti)","Usar demasiado peso perdiendo control"]},"en":{"setup":"Bar in landmine. Stand in a staggered stance (opposite foot forward from pressing arm). Hold the end with one hand at shoulder height.","execution":"Press the bar up and forward with one arm following the natural arc. Fully extend and lower under control.","cues":["Staggered stance for stability","Core braced hard against rotation","Press diagonally following the arc"],"mistakes":["Rotating the torso to assist the press","Not bracing core (the bar pulls you off balance)","Too much weight, losing control"]}}'::jsonb, true),
    ('Press de hombros con kettlebell', 'Kettlebell Shoulder Press', 4, 'weight_reps', 'kettlebell', '{"es":{"setup":"De pie con la kettlebell en posición de rack: codo pegado al cuerpo, kettlebell apoyada en el antebrazo y el hombro. Pies a la anchura de los hombros.","execution":"Empuja la kettlebell hacia arriba rotando ligeramente la muñeca hasta bloquear el brazo arriba. La kettlebell debe quedar apoyada en la parte trasera del antebrazo. Baja controladamente a la posición de rack.","cues":["Buena posición de rack antes de empujar","Core apretado, sin inclinarte","Bloquea el brazo arriba con la kettlebell estable"],"mistakes":["Mala posición de rack (muñeca doblada, codo lejos)","Inclinarse hacia el lado contrario","No bloquear completamente arriba"]},"en":{"setup":"Stand with the kettlebell in rack position: elbow close to body, kettlebell resting on forearm and shoulder. Feet shoulder-width apart.","execution":"Press the kettlebell overhead, slightly rotating the wrist until arm locks out. The kettlebell should rest on the back of your forearm. Lower under control to rack position.","cues":["Good rack position before pressing","Core tight, don''t lean","Lock out overhead with stable kettlebell"],"mistakes":["Bad rack position (bent wrist, elbow flared)","Leaning to the opposite side","Not fully locking out overhead"]}}'::jsonb, true),
    ('Lu raise con mancuernas', 'Dumbbell Lu Raise', 4, 'weight_reps', 'dumbbell', '{"es":{"setup":"De pie con mancuernas ligeras a los lados. El movimiento combina elevación lateral hasta 90° seguida de una rotación y press por encima de la cabeza.","execution":"Eleva las mancuernas lateralmente hasta la altura de los hombros (como lateral raise). Desde ahí, rota los brazos hacia arriba y presiona hasta extender los brazos sobre la cabeza. Invierte el movimiento para bajar.","cues":["Lateral raise + rotación + press, todo en uno fluido","Usa peso muy ligero","Control total en cada fase"],"mistakes":["Usar demasiado peso (es un ejercicio de movilidad/prehab)","Saltar alguna fase del movimiento","Hacer el movimiento rápido sin control"]},"en":{"setup":"Stand with light dumbbells at your sides. The movement combines a lateral raise to 90° followed by an upward rotation and press overhead.","execution":"Raise dumbbells laterally to shoulder height (like a lateral raise). From there, rotate arms upward and press to full overhead extension. Reverse the movement to lower.","cues":["Lateral raise + rotation + press, all in one fluid motion","Use very light weight","Full control in every phase"],"mistakes":["Using too much weight (this is a mobility/prehab exercise)","Skipping a phase of the movement","Rushing through without control"]}}'::jsonb, true),
    ('Curl con barra recta', 'Straight Barbell Curl', 5, 'weight_reps', 'barbell', '{"es":{"setup":"De pie con la barra recta, agarre supino (palmas arriba) a la anchura de los hombros. Brazos extendidos, codos pegados al costado.","execution":"Flexiona los codos subiendo la barra hacia los hombros sin mover los codos de su posición. Aprieta el bíceps arriba y baja controladamente hasta la extensión completa.","cues":["Codos clavados al costado","Aprieta arriba un instante","Baja lento, no dejes caer"],"mistakes":["Balancear el torso para subir el peso","Adelantar los codos para facilitar la subida","Rango de movimiento incompleto abajo"]},"en":{"setup":"Stand holding a straight bar with an underhand grip (palms up) at shoulder width. Arms extended, elbows pinned to your sides.","execution":"Curl the bar toward your shoulders without moving your elbows from their position. Squeeze the biceps at the top and lower under control to full extension.","cues":["Elbows pinned to your sides","Squeeze at the top for a moment","Lower slowly, don''t drop"],"mistakes":["Swinging the torso to lift the weight","Moving elbows forward to make it easier","Incomplete range of motion at the bottom"]}}'::jsonb, true),
    ('Curl con barra EZ', 'EZ-Bar Curl', 5, 'weight_reps', 'barbell', '{"es":{"setup":"De pie con la barra EZ, agarra las curvas interiores con las palmas hacia arriba. Brazos extendidos, codos pegados al costado.","execution":"Flexiona los codos subiendo la barra hacia los hombros. El agarre angular de la EZ reduce la tensión en las muñecas. Aprieta arriba y baja controladamente.","cues":["Muñecas en posición neutra natural","Codos fijos al costado","Extensión completa abajo"],"mistakes":["Balancear el cuerpo para impulsar","Mover los codos adelante durante la subida","No bajar completamente"]},"en":{"setup":"Stand with an EZ bar, gripping the inner curves with palms facing up. Arms extended, elbows at your sides.","execution":"Curl the bar toward your shoulders. The angled grip of the EZ bar reduces wrist strain. Squeeze at the top and lower under control.","cues":["Wrists in natural neutral position","Elbows fixed at your sides","Full extension at the bottom"],"mistakes":["Swinging the body for momentum","Moving elbows forward during the curl","Not lowering fully"]}}'::jsonb, true),
    ('Curl con mancuernas alterno', 'Alternating Dumbbell Curl', 5, 'weight_reps', 'dumbbell', '{"es":{"setup":"De pie con mancuernas a los lados, palmas mirando al cuerpo. Pies a la anchura de los hombros.","execution":"Flexiona un brazo supinando la muñeca (girando la palma hacia arriba) durante la subida. Aprieta el bíceps arriba y baja controladamente. Alterna con el otro brazo.","cues":["Supina durante la subida, no antes","Un brazo trabaja mientras el otro descansa","Codos fijos al costado"],"mistakes":["Balancear el torso de un lado a otro","No supinar completamente","Mover los codos hacia adelante"]},"en":{"setup":"Stand with dumbbells at your sides, palms facing your body. Feet shoulder-width apart.","execution":"Curl one arm up while supinating (rotating palm upward) during the lift. Squeeze the bicep at top and lower under control. Alternate with the other arm.","cues":["Supinate during the curl, not before","One arm works while the other rests","Elbows fixed at your sides"],"mistakes":["Swinging the torso side to side","Not fully supinating","Moving elbows forward"]}}'::jsonb, true),
    ('Curl con mancuernas simultáneo', 'Simultaneous Dumbbell Curl', 5, 'weight_reps', 'dumbbell', '{"es":{"setup":"De pie con mancuernas a los lados, palmas mirando al frente (supinadas). Codos pegados al costado.","execution":"Flexiona ambos brazos a la vez subiendo las mancuernas hacia los hombros. Aprieta arriba y baja controladamente ambos brazos simultáneamente.","cues":["Ambos brazos suben y bajan al mismo tiempo","Core activo para no balancearte","Extensión completa abajo"],"mistakes":["Usar impulso con la cadera","Alternar sin querer (un brazo se adelanta)","No bajar del todo"]},"en":{"setup":"Stand with dumbbells at your sides, palms facing forward (supinated). Elbows pinned to sides.","execution":"Curl both arms simultaneously toward your shoulders. Squeeze at the top and lower both arms under control at the same time.","cues":["Both arms move together at the same pace","Core braced to prevent swinging","Full extension at the bottom"],"mistakes":["Using hip momentum","Arms getting out of sync","Not lowering fully"]}}'::jsonb, true),
    ('Curl martillo con mancuernas', 'Dumbbell Hammer Curl', 5, 'weight_reps', 'dumbbell', '{"es":{"setup":"De pie con mancuernas a los lados, palmas mirando al cuerpo (agarre neutro). Codos pegados al costado.","execution":"Flexiona los codos subiendo las mancuernas sin girar las muñecas, manteniendo las palmas enfrentadas durante todo el recorrido. Aprieta arriba y baja controladamente.","cues":["Palmas siempre mirándose entre sí","Codos clavados al costado","Como si martillearas un clavo"],"mistakes":["Rotar las muñecas durante el movimiento","Balancear el cuerpo","Mover los codos adelante"]},"en":{"setup":"Stand with dumbbells at your sides, palms facing each other (neutral grip). Elbows at your sides.","execution":"Curl the dumbbells up without rotating your wrists, keeping palms facing each other throughout. Squeeze at top and lower under control.","cues":["Palms always facing each other","Elbows pinned to your sides","Like hammering a nail"],"mistakes":["Rotating wrists during the movement","Swinging the body","Moving elbows forward"]}}'::jsonb, true),
    ('Curl concentrado con mancuerna', 'Dumbbell Concentration Curl', 5, 'weight_reps', 'dumbbell', '{"es":{"setup":"Sentado en un banco, inclínate y apoya la parte posterior del brazo (tríceps) contra la cara interna del muslo. Mancuerna en la mano con el brazo extendido.","execution":"Flexiona el codo subiendo la mancuerna hacia el hombro. El muslo impide que el codo se mueva. Aprieta el bíceps arriba y baja lentamente.","cues":["El codo no se mueve de su sitio","Contracción máxima arriba","Baja lento, resiste la gravedad"],"mistakes":["Mover el codo del muslo para ayudarse","Usar impulso del torso","Rango de movimiento incompleto"]},"en":{"setup":"Sit on a bench, lean forward and brace the back of your arm (triceps) against the inner thigh. Dumbbell in hand with arm extended.","execution":"Curl the dumbbell toward your shoulder. The thigh prevents elbow movement. Squeeze the bicep at top and lower slowly.","cues":["Elbow stays locked in place","Maximum contraction at top","Lower slowly, resist gravity"],"mistakes":["Lifting elbow off the thigh for help","Using torso momentum","Incomplete range of motion"]}}'::jsonb, true),
    ('Curl en banco predicador con barra EZ', 'EZ-Bar Preacher Curl', 5, 'weight_reps', 'barbell', '{"es":{"setup":"Siéntate en el banco predicador con los brazos apoyados en la almohadilla inclinada. Agarra la barra EZ por las curvas interiores, palmas hacia arriba.","execution":"Flexiona los codos subiendo la barra hacia los hombros. Los brazos quedan fijos contra la almohadilla eliminando el impulso. Baja controladamente hasta casi la extensión completa.","cues":["Axilas pegadas al borde del banco","Brazos completamente apoyados en la almohadilla","No bajes del todo si sientes presión en el codo"],"mistakes":["Levantar los codos de la almohadilla","Extender completamente con peso elevado (riesgo para el codo)","Usar impulso levantando los hombros"]},"en":{"setup":"Sit at the preacher bench with arms resting on the angled pad. Grip the EZ bar on the inner curves, palms up.","execution":"Curl the bar toward your shoulders. Arms stay fixed against the pad, eliminating momentum. Lower under control to near full extension.","cues":["Armpits snug against the top of the pad","Arms fully resting on the pad","Don''t fully extend if you feel elbow pressure"],"mistakes":["Lifting elbows off the pad","Full extension with heavy weight (elbow injury risk)","Using shoulder momentum to lift"]}}'::jsonb, true),
    ('Curl en banco predicador con mancuerna', 'Dumbbell Preacher Curl', 5, 'weight_reps', 'dumbbell', '{"es":{"setup":"Siéntate en el banco predicador con un brazo apoyado en la almohadilla. Mancuerna en la mano con agarre supino.","execution":"Flexiona el codo subiendo la mancuerna hacia el hombro. El brazo unilateral permite mayor concentración. Baja controladamente sin extender completamente.","cues":["Todo el brazo apoyado en la almohadilla","Siente la contracción completa arriba","Controla la bajada especialmente"],"mistakes":["Despegar el brazo de la almohadilla al final","Extender completamente con carga alta","Usar el hombro para iniciar el movimiento"]},"en":{"setup":"Sit at the preacher bench with one arm resting on the pad. Dumbbell in hand with underhand grip.","execution":"Curl the dumbbell toward your shoulder. The unilateral work allows greater focus. Lower under control without fully extending.","cues":["Entire arm resting on the pad","Feel the full contraction at top","Control the lowering phase especially"],"mistakes":["Peeling arm off the pad at the bottom","Full extension under heavy load","Using the shoulder to initiate the movement"]}}'::jsonb, true),
    ('Curl en banco inclinado con mancuernas', 'Incline Dumbbell Curl', 5, 'weight_reps', 'dumbbell', '{"es":{"setup":"Banco inclinado a 45-60°. Siéntate con la espalda pegada al respaldo. Brazos colgando a los lados con mancuernas, palmas al frente.","execution":"Flexiona los codos subiendo las mancuernas hacia los hombros. La inclinación pre-estira el bíceps, aumentando la demanda. Baja controladamente hasta extensión completa.","cues":["Espalda pegada al respaldo todo el rato","Codos apuntan al suelo, no se mueven","Siente el estiramiento abajo"],"mistakes":["Despegar la espalda del banco","Adelantar los codos (anula el estiramiento)","Usar peso excesivo perdiendo rango"]},"en":{"setup":"Set bench to 45-60°. Sit with back against the pad. Arms hanging at your sides with dumbbells, palms forward.","execution":"Curl the dumbbells toward your shoulders. The incline pre-stretches the bicep, increasing demand. Lower under control to full extension.","cues":["Back stays on the pad throughout","Elbows point to the floor and don''t move","Feel the stretch at the bottom"],"mistakes":["Lifting back off the bench","Moving elbows forward (negates the stretch)","Too much weight causing partial range"]}}'::jsonb, true),
    ('Curl en polea baja con barra recta', 'Straight Bar Cable Curl', 5, 'weight_reps', 'cable', '{"es":{"setup":"Polea en posición baja con barra recta. De pie frente a la máquina, agarra la barra con palmas hacia arriba a la anchura de los hombros.","execution":"Flexiona los codos subiendo la barra hacia los hombros. El cable mantiene tensión constante durante todo el recorrido. Baja controladamente.","cues":["Tensión constante gracias al cable","Codos pegados al costado","No te inclines hacia atrás"],"mistakes":["Inclinarse hacia atrás para ayudar","Mover los codos adelante","Soltar el peso en la bajada"]},"en":{"setup":"Set cable to lowest position with a straight bar. Stand facing the machine, grip the bar palms up at shoulder width.","execution":"Curl the bar toward your shoulders. The cable provides constant tension throughout the range. Lower under control.","cues":["Constant tension from the cable","Elbows pinned to your sides","Don''t lean back"],"mistakes":["Leaning back to assist","Moving elbows forward","Dropping the weight on the way down"]}}'::jsonb, true),
    ('Curl en polea baja con barra EZ', 'EZ-Bar Cable Curl', 5, 'weight_reps', 'cable', '{"es":{"setup":"Polea en posición baja con accesorio de barra EZ. De pie frente a la máquina, agarra las curvas interiores con palmas hacia arriba.","execution":"Flexiona los codos subiendo la barra EZ hacia los hombros. El agarre angular es más cómodo para las muñecas. Baja controladamente manteniendo la tensión.","cues":["Muñecas cómodas en el agarre angular","Codos fijos al costado","Resiste la bajada"],"mistakes":["Balancear el cuerpo","Dejar que los codos se adelanten","Perder tensión al bajar rápido"]},"en":{"setup":"Set cable to lowest position with an EZ bar attachment. Stand facing the machine, grip the inner curves palms up.","execution":"Curl the EZ bar toward your shoulders. The angled grip is easier on the wrists. Lower under control maintaining tension.","cues":["Wrists comfortable in the angled grip","Elbows fixed at your sides","Resist on the way down"],"mistakes":["Swinging the body","Letting elbows drift forward","Losing tension by lowering too fast"]}}'::jsonb, true),
    ('Curl en polea baja con cuerda', 'Rope Cable Curl', 5, 'weight_reps', 'cable', '{"es":{"setup":"Polea en posición baja con accesorio de cuerda. De pie frente a la máquina, agarra los extremos de la cuerda con agarre neutro.","execution":"Flexiona los codos subiendo la cuerda. Al llegar arriba, separa los extremos y supina (gira las palmas hacia arriba) para una contracción máxima. Baja controladamente.","cues":["Separa y supina arriba para máxima contracción","Codos fijos","Agarre neutro durante la subida"],"mistakes":["No separar la cuerda arriba","Usar impulso del cuerpo","Mover los codos"]},"en":{"setup":"Set cable to lowest position with rope attachment. Stand facing the machine, grip rope ends with neutral grip.","execution":"Curl the rope upward. At the top, split the rope ends apart and supinate (turn palms up) for maximum contraction. Lower under control.","cues":["Split and supinate at top for peak contraction","Elbows fixed","Neutral grip during the curl"],"mistakes":["Not splitting the rope at top","Using body momentum","Moving elbows"]}}'::jsonb, true),
    ('Curl en polea alta', 'High Cable Curl', 5, 'weight_reps', 'cable', '{"es":{"setup":"Poleas altas en una estación de cable cruzado. De pie en el centro, agarra las asas con palmas hacia arriba, brazos extendidos a los lados a la altura de los hombros.","execution":"Flexiona los codos tirando las asas hacia las orejas. Los brazos permanecen a la altura de los hombros durante todo el movimiento. Extiende controladamente.","cues":["Brazos a la altura de los hombros todo el rato","Aprieta como si hicieras una pose de doble bíceps","Codos fijos en el espacio"],"mistakes":["Dejar caer los codos por debajo de los hombros","Avanzar el cuerpo para facilitar el movimiento","Usar peso excesivo perdiendo la posición"]},"en":{"setup":"High pulleys on a cable crossover station. Stand in the center, grab handles with palms up, arms extended to the sides at shoulder height.","execution":"Curl by bending elbows, pulling handles toward your ears. Arms stay at shoulder height throughout. Extend under control.","cues":["Arms at shoulder height the entire time","Squeeze like a double bicep pose","Elbows fixed in space"],"mistakes":["Letting elbows drop below shoulders","Stepping forward to make it easier","Too much weight losing position"]}}'::jsonb, true),
    ('Curl spider con barra EZ', 'EZ-Bar Spider Curl', 5, 'weight_reps', 'barbell', '{"es":{"setup":"Inclina un banco a 45° y apóyate con el pecho en la parte alta (lado inclinado hacia arriba). Los brazos cuelgan verticalmente con la barra EZ.","execution":"Flexiona los codos subiendo la barra hacia la cara. El ángulo elimina todo impulso y maximiza la tensión en la parte contraída. Baja controladamente.","cues":["Pecho pegado al banco","Los brazos cuelgan rectos antes de empezar","Contracción brutal arriba"],"mistakes":["Levantar el pecho del banco para ayudar","Balancear los brazos","No bajar completamente"]},"en":{"setup":"Set a bench to 45° and lean your chest on the high side (incline facing up). Arms hang vertically holding the EZ bar.","execution":"Curl the bar toward your face. The angle eliminates all momentum and maximizes tension at peak contraction. Lower under control.","cues":["Chest pressed against the bench","Arms hang straight before starting","Intense contraction at top"],"mistakes":["Lifting chest off the bench to assist","Swinging the arms","Not lowering fully"]}}'::jsonb, true),
    ('Curl spider con mancuernas', 'Dumbbell Spider Curl', 5, 'weight_reps', 'dumbbell', '{"es":{"setup":"Banco inclinado a 45°, apóyate con el pecho en la parte alta. Brazos colgando verticalmente con mancuernas, palmas al frente.","execution":"Flexiona los codos subiendo las mancuernas hacia los hombros. El ángulo elimina impulso y maximiza el trabajo del bíceps en contracción. Baja lentamente.","cues":["Pecho firme contra el banco","Movimiento puro de bíceps, sin trampa","Baja lento para aprovechar la negativa"],"mistakes":["Despegar el pecho para hacer trampa","Balancear las mancuernas","Rango parcial"]},"en":{"setup":"Bench at 45°, lean chest on the high side. Arms hanging vertically with dumbbells, palms forward.","execution":"Curl dumbbells toward your shoulders. The angle eliminates momentum and maximizes bicep work at contraction. Lower slowly.","cues":["Chest firm against the bench","Pure bicep movement, no cheating","Lower slowly to capitalize on the eccentric"],"mistakes":["Peeling chest off to cheat","Swinging the dumbbells","Partial range of motion"]}}'::jsonb, true),
    ('Curl 21s con barra', 'Barbell 21s Curl', 5, 'weight_reps', 'barbell', '{"es":{"setup":"De pie con barra recta o EZ, agarre supino a la anchura de los hombros. Codos pegados al costado.","execution":"Haz 7 repeticiones de la parte baja a la mitad (90°), 7 de la mitad hasta arriba, y 7 con rango completo. Todo sin descanso entre bloques.","cues":["7 abajo + 7 arriba + 7 completas = 1 serie","Usa menos peso del habitual","Codos siempre fijos"],"mistakes":["Usar demasiado peso (vas a necesitar menos de lo que crees)","Hacer trampa con el cuerpo en las últimas repeticiones","No diferenciar bien los rangos parciales"]},"en":{"setup":"Stand with a straight or EZ bar, underhand grip at shoulder width. Elbows pinned to sides.","execution":"Do 7 reps from the bottom to midpoint (90°), 7 from midpoint to top, and 7 full range. All without rest between blocks.","cues":["7 bottom + 7 top + 7 full = 1 set","Use less weight than you think","Elbows always fixed"],"mistakes":["Using too much weight (you''ll need less than expected)","Cheating with the body on the last reps","Not clearly differentiating the partial ranges"]}}'::jsonb, true),
    ('Curl arrastre con barra', 'Barbell Drag Curl', 5, 'weight_reps', 'barbell', '{"es":{"setup":"De pie con barra recta, agarre supino a la anchura de los hombros. Brazos extendidos con la barra frente a los muslos.","execution":"Sube la barra pegada al cuerpo arrastrándola por el torso, llevando los codos hacia atrás (no al frente). La barra sube por el abdomen y pecho. Baja arrastrando de vuelta.","cues":["La barra se arrastra por el cuerpo, no se separa","Los codos van hacia atrás, no adelante","Enfatiza la cabeza larga del bíceps"],"mistakes":["Separar la barra del cuerpo (se convierte en curl normal)","Llevar los codos al frente","Usar demasiado peso"]},"en":{"setup":"Stand with a straight bar, underhand grip at shoulder width. Arms extended with bar in front of thighs.","execution":"Raise the bar by dragging it up your torso, pulling elbows back (not forward). The bar slides up your abs and chest. Lower by dragging back down.","cues":["Bar drags along the body, never leaves it","Elbows go backward, not forward","Emphasizes the long head of the bicep"],"mistakes":["Separating the bar from the body (becomes a regular curl)","Moving elbows forward","Using too much weight"]}}'::jsonb, true),
    ('Curl arrastre con mancuernas', 'Dumbbell Drag Curl', 5, 'weight_reps', 'dumbbell', '{"es":{"setup":"De pie con mancuernas a los lados, palmas al frente. Pies a la anchura de los hombros.","execution":"Sube las mancuernas arrastrándolas por los costados del cuerpo, llevando los codos hacia atrás. Las mancuernas suben por las caderas y el torso. Baja arrastrando.","cues":["Mancuernas pegadas al cuerpo","Codos hacia atrás, no adelante","Movimiento lento y controlado"],"mistakes":["Separar las mancuernas del cuerpo","Mover los codos al frente","Balancear el torso"]},"en":{"setup":"Stand with dumbbells at your sides, palms forward. Feet shoulder-width apart.","execution":"Raise the dumbbells by dragging them along the sides of your body, pulling elbows back. Dumbbells travel up your hips and torso. Lower by dragging down.","cues":["Dumbbells stay close to body","Elbows go backward, not forward","Slow and controlled movement"],"mistakes":["Separating dumbbells from the body","Moving elbows forward","Swinging the torso"]}}'::jsonb, true),
    ('Curl Zottman con mancuernas', 'Dumbbell Zottman Curl', 5, 'weight_reps', 'dumbbell', '{"es":{"setup":"De pie con mancuernas a los lados, palmas al frente (supinadas). Codos pegados al costado.","execution":"Sube con agarre supino (palmas arriba) como un curl normal. Arriba, gira las muñecas a pronado (palmas abajo) y baja lentamente con ese agarre. Abajo, vuelve a supinar y repite.","cues":["Sube supino, baja prono","La bajada en prono trabaja los antebrazos","Baja especialmente lento"],"mistakes":["Girar las muñecas durante la subida o bajada (solo arriba y abajo)","Bajar demasiado rápido en prono","Usar demasiado peso (la fase prona es más débil)"]},"en":{"setup":"Stand with dumbbells at your sides, palms forward (supinated). Elbows at your sides.","execution":"Curl up with palms facing up (supinated) like a regular curl. At the top, rotate wrists to pronated (palms down) and lower slowly with that grip. At the bottom, rotate back to supinated and repeat.","cues":["Curl up supinated, lower pronated","The pronated lowering works forearms","Lower extra slowly"],"mistakes":["Rotating wrists during the lift or descent (only at top and bottom)","Lowering too fast in pronated position","Too much weight (the pronated phase is weaker)"]}}'::jsonb, true),
    ('Curl bayesiano en polea', 'Bayesian Cable Curl', 5, 'weight_reps', 'cable', '{"es":{"setup":"Polea baja detrás de ti. De pie de espaldas a la máquina, agarra el asa con una mano. Da un paso adelante para tensar el cable con el brazo extendido detrás del cuerpo.","execution":"Flexiona el codo llevando la mano hacia el hombro. El brazo empieza detrás del cuerpo, pre-estirando el bíceps al máximo. Baja controladamente hasta la extensión completa detrás.","cues":["El brazo empieza detrás del torso","Máximo estiramiento del bíceps abajo","Codo fijo, solo el antebrazo se mueve"],"mistakes":["Adelantar el codo (pierde el estiramiento)","No retroceder lo suficiente para tensar el cable","Balancear el cuerpo"]},"en":{"setup":"Low cable behind you. Stand facing away from the machine, grab the handle with one hand. Step forward to tension the cable with arm extended behind your body.","execution":"Curl by bending your elbow, bringing hand toward shoulder. The arm starts behind your body, pre-stretching the bicep maximally. Lower under control to full extension behind.","cues":["Arm starts behind your torso","Maximum bicep stretch at bottom","Elbow fixed, only forearm moves"],"mistakes":["Moving elbow forward (loses the stretch)","Not stepping far enough to tension the cable","Swinging the body"]}}'::jsonb, true),
    ('Curl en máquina', 'Machine Bicep Curl', 5, 'weight_reps', 'machine', '{"es":{"setup":"Ajusta el asiento para que los codos queden alineados con el eje de rotación de la máquina. Apoya los brazos en la almohadilla y agarra las asas.","execution":"Flexiona los codos tirando de las asas hacia los hombros. La máquina guía el movimiento y aísla los bíceps. Baja controladamente sin dejar que las placas se toquen.","cues":["Codos alineados con el pivote de la máquina","No despegues los brazos de la almohadilla","Contracción completa arriba"],"mistakes":["Mal ajuste del asiento (codos desalineados del pivote)","Levantar los brazos de la almohadilla","Dejar caer el peso entre repeticiones"]},"en":{"setup":"Adjust the seat so elbows align with the machine''s pivot point. Rest arms on the pad and grip the handles.","execution":"Curl by bending elbows, pulling handles toward shoulders. The machine guides the movement and isolates biceps. Lower under control without letting plates touch.","cues":["Elbows aligned with the machine pivot","Don''t lift arms off the pad","Full contraction at top"],"mistakes":["Poor seat adjustment (elbows misaligned with pivot)","Lifting arms off the pad","Dropping weight between reps"]}}'::jsonb, true),
    ('Curl martillo en polea con cuerda', 'Rope Cable Hammer Curl', 5, 'weight_reps', 'cable', '{"es":{"setup":"Polea en posición baja con accesorio de cuerda. De pie frente a la máquina, agarra los extremos de la cuerda con agarre neutro (palmas enfrentadas).","execution":"Flexiona los codos subiendo la cuerda con agarre neutro mantenido durante todo el recorrido. Aprieta arriba y baja controladamente.","cues":["Agarre neutro todo el rato (como martillo)","Codos fijos al costado","Tensión constante del cable"],"mistakes":["Rotar las muñecas durante el movimiento","Usar impulso del cuerpo","Separar los codos del torso"]},"en":{"setup":"Set cable to lowest position with rope attachment. Stand facing the machine, grip rope ends with neutral grip (palms facing each other).","execution":"Curl the rope up maintaining a neutral grip throughout. Squeeze at top and lower under control.","cues":["Neutral grip throughout (hammer style)","Elbows fixed at sides","Constant cable tension"],"mistakes":["Rotating wrists during the movement","Using body momentum","Letting elbows drift from torso"]}}'::jsonb, true),
    ('Curl martillo inclinado con mancuernas', 'Incline Dumbbell Hammer Curl', 5, 'weight_reps', 'dumbbell', '{"es":{"setup":"Banco inclinado a 45-60°. Siéntate con la espalda pegada al respaldo. Mancuernas colgando a los lados con agarre neutro (palmas enfrentadas).","execution":"Flexiona los codos subiendo las mancuernas con agarre neutro. La inclinación pre-estira el bíceps y el braquial. Baja controladamente hasta extensión completa.","cues":["Palmas enfrentadas todo el rato","Espalda pegada al respaldo","Siente el estiramiento abajo"],"mistakes":["Rotar las muñecas a supino","Despegar la espalda del banco","Adelantar los codos"]},"en":{"setup":"Set bench to 45-60°. Sit with back against the pad. Dumbbells hanging at sides with neutral grip (palms facing each other).","execution":"Curl the dumbbells with neutral grip maintained. The incline pre-stretches the bicep and brachialis. Lower under control to full extension.","cues":["Palms facing each other throughout","Back stays on the pad","Feel the stretch at the bottom"],"mistakes":["Rotating wrists to supinated","Lifting back off the bench","Moving elbows forward"]}}'::jsonb, true),
    ('Curl con kettlebell', 'Kettlebell Curl', 5, 'weight_reps', 'kettlebell', '{"es":{"setup":"De pie sujetando una kettlebell por el asa con una o ambas manos, brazos extendidos frente a los muslos. El peso colgante de la kettlebell desafía el agarre.","execution":"Flexiona los codos subiendo la kettlebell hacia los hombros. El centro de gravedad más bajo que el agarre hace que el antebrazo trabaje más. Baja controladamente.","cues":["Agarre firme del asa","Codos pegados al costado","Controla el balanceo de la kettlebell"],"mistakes":["Dejar que la kettlebell se balancee sin control","Usar impulso del cuerpo","Soltar parcialmente el agarre arriba"]},"en":{"setup":"Stand holding a kettlebell by the handle with one or both hands, arms extended in front of thighs. The hanging weight challenges grip strength.","execution":"Curl the kettlebell toward your shoulders. The center of gravity being lower than the grip makes forearms work harder. Lower under control.","cues":["Firm grip on the handle","Elbows pinned to sides","Control the kettlebell''s swing"],"mistakes":["Letting the kettlebell swing uncontrolled","Using body momentum","Partially releasing the grip at the top"]}}'::jsonb, true),
    ('Extensión de tríceps en polea con barra recta', 'Straight Bar Tricep Pushdown', 6, 'weight_reps', 'cable', '{"es":{"setup":"Polea alta con barra recta. Parate de frente, agarre prono (palmas abajo) al ancho de los hombros. Codos pegados al torso.","execution":"Empujá la barra hacia abajo extendiendo los codos hasta bloquear. Volvé arriba controladamente sin mover los codos de su posición.","cues":["Codos clavados al costado del cuerpo","Apretá los tríceps abajo","Solo se mueven los antebrazos"],"mistakes":["Abrir los codos del cuerpo","Inclinarse sobre la barra usando peso corporal","Subir demasiado y perder tensión"]},"en":{"setup":"High cable with straight bar. Face the machine, overhand grip at shoulder width. Elbows pinned to your sides.","execution":"Push the bar down by extending elbows to full lockout. Return up under control without moving elbows from position.","cues":["Elbows glued to your sides","Squeeze triceps at the bottom","Only forearms move"],"mistakes":["Elbows drifting away from body","Leaning over the bar using bodyweight","Going too high and losing tension"]}}'::jsonb, true),
    ('Extensión de tríceps en polea con barra V', 'V-Bar Tricep Pushdown', 6, 'weight_reps', 'cable', '{"es":{"setup":"Polea alta con barra V. Agarre neutro (palmas enfrentadas), codos pegados al cuerpo.","execution":"Empujá hacia abajo extendiendo los codos completamente. Volvé arriba sin dejar que los codos se muevan de posición.","cues":["El agarre neutro es más cómodo para las muñecas","Apretá fuerte abajo","Codos fijos"],"mistakes":["Mover los codos adelante-atrás","Usar impulso del cuerpo","No extender completamente abajo"]},"en":{"setup":"High cable with V-bar. Neutral grip (palms facing), elbows pinned to body.","execution":"Push down by fully extending elbows. Return up without letting elbows move from position.","cues":["Neutral grip is easier on wrists","Squeeze hard at the bottom","Fixed elbows"],"mistakes":["Elbows swinging forward and back","Using body momentum","Not fully extending at the bottom"]}}'::jsonb, true),
    ('Extensión de tríceps en polea con cuerda', 'Rope Tricep Pushdown', 6, 'weight_reps', 'cable', '{"es":{"setup":"Polea alta con cuerda. Agarra los extremos con agarre neutro. Codos pegados al cuerpo, torso ligeramente inclinado.","execution":"Empujá hacia abajo y separá los extremos de la cuerda al final del movimiento para máxima contracción. Volvé arriba controladamente.","cues":["Abrí la cuerda abajo para apretar más","Codos fijos al costado","Sentí el pico de contracción al separar"],"mistakes":["No separar la cuerda abajo","Codos alejándose del cuerpo","Usar el peso del cuerpo para empujar"]},"en":{"setup":"High cable with rope. Grip the ends with neutral grip. Elbows pinned, torso slightly leaned forward.","execution":"Push down and spread the rope apart at the bottom for maximum contraction. Return up under control.","cues":["Split the rope at the bottom for extra squeeze","Elbows fixed at your sides","Feel the peak contraction when splitting"],"mistakes":["Not splitting the rope at the bottom","Elbows drifting from body","Using bodyweight to push"]}}'::jsonb, true),
    ('Extensión de tríceps en polea agarre supino', 'Underhand Tricep Pushdown', 6, 'weight_reps', 'cable', '{"es":{"setup":"Polea alta con barra recta o EZ. Agarre supino (palmas hacia arriba), codos pegados al torso.","execution":"Empujá la barra hacia abajo extendiendo los codos. Apretá los tríceps abajo y volvé controladamente.","cues":["Palmas mirando al techo","Codos pegados, no se mueven","Enfatiza la cabeza medial del tríceps"],"mistakes":["Muñecas flexionadas hacia atrás","Agarre demasiado ancho","Usar peso excesivo (este agarre es más débil)"]},"en":{"setup":"High cable with straight or EZ bar. Underhand grip (palms up), elbows pinned to torso.","execution":"Push the bar down extending elbows. Squeeze triceps at the bottom and return under control.","cues":["Palms facing the ceiling","Elbows pinned, don''t move","Emphasizes the medial tricep head"],"mistakes":["Wrists bending backward","Grip too wide","Too heavy (this grip is weaker)"]}}'::jsonb, true),
    ('Extensión de tríceps en polea unilateral', 'Single-Arm Tricep Pushdown', 6, 'weight_reps', 'cable', '{"es":{"setup":"Polea alta con manija de una mano. Parate de frente, codo pegado al costado. La otra mano puede apoyarse en la estructura.","execution":"Empujá hacia abajo extendiendo el codo completamente. Volvé arriba sin dejar que el codo se mueva.","cues":["Codo fijo como bisagra","Apretá el tríceps al bloquear","Podés rotar ligeramente al final"],"mistakes":["Mover el codo para ayudar","Rotar el torso","Usar demasiado peso y compensar"]},"en":{"setup":"High cable with single handle. Face the machine, elbow pinned to your side. Other hand can hold the frame.","execution":"Push down by fully extending the elbow. Return up without letting the elbow move.","cues":["Elbow fixed like a hinge","Squeeze tricep at lockout","Slight rotation at the end is okay"],"mistakes":["Moving the elbow to assist","Rotating the torso","Too heavy, compensating"]}}'::jsonb, true),
    ('Press francés con barra EZ', 'EZ-Bar Skull Crusher', 6, 'weight_reps', 'barbell', '{"es":{"setup":"Acuéstate en banco plano. Agarra la barra EZ en la curva interna con agarre cerrado. Brazos extendidos sobre la frente.","execution":"Bajá la barra flexionando los codos hasta que quede cerca de la frente o ligeramente detrás de la cabeza. Extendé los codos para volver arriba.","cues":["Los codos apuntan al techo, no se abren","Bajá a la frente o detrás de la cabeza","Movimiento solo de los codos"],"mistakes":["Abrir los codos hacia afuera","Bajar la barra a la nariz (peligroso)","Mover los hombros para ayudar"]},"en":{"setup":"Lie on a flat bench. Grip the EZ bar on the inner curve with a narrow grip. Arms extended over your forehead.","execution":"Lower the bar by bending elbows until it''s near the forehead or slightly behind the head. Extend elbows to return up.","cues":["Elbows point at the ceiling, don''t flare","Lower to forehead or behind head","Movement only from the elbows"],"mistakes":["Flaring elbows outward","Lowering to the nose (dangerous)","Moving shoulders to assist"]}}'::jsonb, true),
    ('Press francés con mancuernas', 'Dumbbell Skull Crusher', 6, 'weight_reps', 'dumbbell', '{"es":{"setup":"Acuéstate en banco plano. Una mancuerna en cada mano con agarre neutro (palmas enfrentadas). Brazos extendidos sobre la cara.","execution":"Bajá las mancuernas flexionando los codos hasta los lados de la cabeza. Extendé para volver a la posición inicial.","cues":["Agarre neutro es más amigable para los codos","Codos fijos apuntando al techo","Controlá cada mancuerna por separado"],"mistakes":["Dejar caer las mancuernas sin control","Codos abriéndose","Usar excesivo impulso de hombros"]},"en":{"setup":"Lie on a flat bench. One dumbbell in each hand, neutral grip (palms facing). Arms extended above your face.","execution":"Lower dumbbells by bending elbows to the sides of your head. Extend to return to start.","cues":["Neutral grip is more elbow-friendly","Elbows fixed pointing at ceiling","Control each dumbbell independently"],"mistakes":["Dropping dumbbells without control","Elbows flaring out","Excessive shoulder momentum"]}}'::jsonb, true),
    ('Press francés con barra recta', 'Barbell Skull Crusher', 6, 'weight_reps', 'barbell', '{"es":{"setup":"Acuéstate en banco plano. Agarra la barra recta con agarre cerrado (ancho de hombros o menos). Brazos extendidos sobre la frente.","execution":"Bajá la barra flexionando los codos hacia la frente o detrás de la cabeza. Extendé para volver arriba.","cues":["Codos paralelos, no se abren","Bajá controladamente","La barra recta exige más a las muñecas, cuidá la posición"],"mistakes":["Muñecas dobladas hacia atrás","Codos abriéndose","Dejar caer la barra sin control"]},"en":{"setup":"Lie on a flat bench. Grip the straight bar with a narrow grip (shoulder width or less). Arms extended above forehead.","execution":"Lower the bar by bending elbows toward forehead or behind head. Extend to return up.","cues":["Elbows parallel, don''t flare","Lower under control","Straight bar is harder on wrists—watch position"],"mistakes":["Wrists bending backward","Elbows flaring out","Dropping the bar without control"]}}'::jsonb, true),
    ('Extensión de tríceps con mancuerna sobre cabeza', 'Overhead Dumbbell Tricep Extension', 6, 'weight_reps', 'dumbbell', '{"es":{"setup":"Sentado o de pie. Sostené una mancuerna con ambas manos por un extremo, brazos extendidos por encima de la cabeza.","execution":"Bajá la mancuerna detrás de la cabeza flexionando los codos. Cuando sientas el estiramiento, extendé los codos para volver arriba.","cues":["Codos apuntan al techo, pegados a la cabeza","Sentí el estiramiento en la cabeza larga del tríceps","Core activado para no arquear"],"mistakes":["Codos abriéndose hacia afuera","Arquear excesivamente la espalda baja","Mover los hombros para asistir"]},"en":{"setup":"Seated or standing. Hold one dumbbell with both hands by one end, arms fully extended overhead.","execution":"Lower the dumbbell behind your head by bending elbows. When you feel the stretch, extend elbows to return up.","cues":["Elbows point to ceiling, close to head","Feel the stretch on the long head","Core braced to avoid arching"],"mistakes":["Elbows flaring outward","Excessive lower back arch","Moving shoulders to assist"]}}'::jsonb, true),
    ('Extensión de tríceps con mancuerna a una mano', 'Single-Arm Overhead Dumbbell Tricep Extension', 6, 'weight_reps', 'dumbbell', '{"es":{"setup":"Sentado o de pie. Una mancuerna en una mano, brazo extendido sobre la cabeza. La otra mano puede estabilizar el codo.","execution":"Bajá la mancuerna detrás de la cabeza flexionando el codo. Extendé para volver arriba.","cues":["Codo apunta al techo sin moverse","Podés usar la otra mano para estabilizar","Sentí el estiramiento en cada rep"],"mistakes":["Codo moviéndose hacia adelante","Inclinar el torso para compensar","No usar rango completo"]},"en":{"setup":"Seated or standing. One dumbbell in one hand, arm extended overhead. Other hand can stabilize the elbow.","execution":"Lower the dumbbell behind your head by bending the elbow. Extend to return up.","cues":["Elbow points to ceiling without moving","Use other hand to stabilize if needed","Feel the stretch each rep"],"mistakes":["Elbow drifting forward","Leaning torso to compensate","Not using full range of motion"]}}'::jsonb, true),
    ('Extensión de tríceps sobre cabeza en polea', 'Overhead Cable Tricep Extension', 6, 'weight_reps', 'cable', '{"es":{"setup":"Polea baja con barra o manija. De espaldas a la polea, un paso adelante. Brazos sobre la cabeza, codos flexionados.","execution":"Extendé los codos empujando hacia arriba y adelante. Volvé controladamente sintiendo el estiramiento.","cues":["Codos fijos cerca de la cabeza","La polea da tensión constante, aprovechala","Postura adelantada con un pie"],"mistakes":["Codos abriéndose","Moverse demasiado lejos de la polea","Usar el torso para impulsar"]},"en":{"setup":"Low cable with bar or handle. Face away from the machine, step forward. Arms overhead, elbows bent.","execution":"Extend elbows pushing up and forward. Return under control feeling the stretch.","cues":["Elbows fixed near your head","Cable provides constant tension—use it","Staggered stance for stability"],"mistakes":["Elbows flaring","Standing too far from the cable","Using torso to generate force"]}}'::jsonb, true),
    ('Extensión de tríceps sobre cabeza en polea con cuerda', 'Overhead Rope Cable Tricep Extension', 6, 'weight_reps', 'cable', '{"es":{"setup":"Polea baja con cuerda. De espaldas a la polea, un paso adelante. Agarra la cuerda detrás de la cabeza con codos flexionados.","execution":"Extendé los codos y separá los extremos de la cuerda al final para máxima contracción. Volvé controladamente.","cues":["Abrí la cuerda arriba para extra contracción","Codos pegados a la cabeza","Incliná el torso ligeramente hacia adelante"],"mistakes":["No separar la cuerda al extender","Codos moviéndose","Perder estabilidad del core"]},"en":{"setup":"Low cable with rope. Face away, step forward. Grab rope behind your head with elbows bent.","execution":"Extend elbows and spread the rope apart at the top for maximum contraction. Return under control.","cues":["Split rope at top for extra squeeze","Elbows close to head","Slight forward torso lean"],"mistakes":["Not splitting the rope when extending","Elbows moving around","Losing core stability"]}}'::jsonb, true),
    ('Patada de tríceps con mancuerna', 'Dumbbell Tricep Kickback', 6, 'weight_reps', 'dumbbell', '{"es":{"setup":"Inclinate apoyando una mano y rodilla en un banco. Brazo de trabajo con el codo a 90°, pegado al torso, paralelo al suelo.","execution":"Extendé el codo hacia atrás hasta que el brazo quede completamente recto. Apretá el tríceps arriba y volvé a 90°.","cues":["Brazo superior paralelo al suelo, no se mueve","Apretá fuerte al extender","Movimiento lento y controlado"],"mistakes":["Balancear la mancuerna con impulso","El codo cae y pierde la posición","Usar demasiado peso (este ejercicio es de aislamiento)"]},"en":{"setup":"Lean forward with one hand and knee on a bench. Working arm bent at 90°, upper arm parallel to the floor and pinned to torso.","execution":"Extend the elbow back until arm is fully straight. Squeeze tricep at the top and return to 90°.","cues":["Upper arm parallel to floor, doesn''t move","Squeeze hard at extension","Slow, controlled movement"],"mistakes":["Swinging the dumbbell with momentum","Elbow dropping and losing position","Too heavy (this is an isolation move)"]}}'::jsonb, true),
    ('Patada de tríceps en polea', 'Cable Tricep Kickback', 6, 'weight_reps', 'cable', '{"es":{"setup":"Polea baja con manija. Inclinate hacia adelante, codo a 90° pegado al costado, brazo paralelo al suelo.","execution":"Extendé el codo hacia atrás contra la resistencia de la polea. Apretá y volvé controladamente.","cues":["La polea mantiene tensión constante, mejor que mancuerna","Codo fijo, solo mueve el antebrazo","Apretá al final"],"mistakes":["Pararse demasiado erguido","Mover el brazo completo en lugar de solo el codo","Ir demasiado rápido"]},"en":{"setup":"Low cable with handle. Lean forward, elbow at 90° pinned to your side, upper arm parallel to floor.","execution":"Extend elbow back against cable resistance. Squeeze and return under control.","cues":["Cable keeps constant tension—better than dumbbells","Elbow fixed, only forearm moves","Squeeze at the end"],"mistakes":["Standing too upright","Moving the whole arm instead of just the elbow","Going too fast"]}}'::jsonb, true),
    ('Fondos en banco', 'Bench Dips', 6, 'reps_only', 'bodyweight', '{"es":{"setup":"Manos en el borde de un banco detrás de vos, dedos hacia adelante. Piernas extendidas o flexionadas según nivel. Trasero cerca del banco.","execution":"Bajá flexionando los codos hasta ~90°. Empujá hacia arriba hasta extender los brazos.","cues":["Mantenete cerca del banco","Codos hacia atrás, no hacia afuera","Bajá hasta 90° en los codos"],"mistakes":["Codos abriéndose hacia los lados","Bajar demasiado y forzar los hombros","Alejarse demasiado del banco"]},"en":{"setup":"Hands on the edge of a bench behind you, fingers forward. Legs extended or bent depending on level. Hips close to the bench.","execution":"Lower by bending elbows to about 90°. Push up until arms are fully extended.","cues":["Stay close to the bench","Elbows point backward, not outward","Lower to 90° at the elbows"],"mistakes":["Elbows flaring to the sides","Going too deep and straining shoulders","Drifting too far from the bench"]}}'::jsonb, true),
    ('Fondos en banco con peso', 'Weighted Bench Dips', 6, 'weight_reps', 'bodyweight', '{"es":{"setup":"Misma posición que fondos en banco, pero con un disco o peso en los muslos. Piernas en otro banco para mayor rango.","execution":"Bajá controladamente hasta ~90° en los codos. Empujá hacia arriba hasta extender.","cues":["El peso debe estar estable en los muslos","Mismo patrón que sin peso","Controlá especialmente la bajada"],"mistakes":["Peso inestable que se resbala","Reducir rango por el peso extra","Bajar demasiado y forzar hombros"]},"en":{"setup":"Same position as bench dips but with a plate or weight on your thighs. Feet on another bench for greater range.","execution":"Lower under control to about 90° at elbows. Push up to full extension.","cues":["Weight must be stable on thighs","Same pattern as unweighted","Control the descent especially"],"mistakes":["Unstable weight sliding off","Reducing range due to extra load","Going too deep and straining shoulders"]}}'::jsonb, true),
    ('Extensión de tríceps en máquina', 'Machine Tricep Extension', 6, 'weight_reps', 'machine', '{"es":{"setup":"Ajustá el asiento para que los codos queden alineados con el eje de la máquina. Espalda contra el respaldo, agarra las manijas.","execution":"Extendé los codos empujando las manijas hacia abajo hasta bloquear. Volvé controladamente sin perder tensión.","cues":["Codos alineados con el eje de rotación","Extensión completa abajo","Controlá la vuelta"],"mistakes":["Asiento mal ajustado (codos desalineados)","No extender completamente","Dejar que el peso caiga sin control"]},"en":{"setup":"Adjust seat so elbows align with the machine''s pivot point. Back against pad, grip the handles.","execution":"Extend elbows pushing handles down to lockout. Return under control without losing tension.","cues":["Elbows aligned with the pivot","Full extension at the bottom","Control the return"],"mistakes":["Seat poorly adjusted (elbows misaligned)","Not fully extending","Letting the weight drop without control"]}}'::jsonb, true),
    ('Press JM con barra', 'JM Press', 6, 'weight_reps', 'barbell', '{"es":{"setup":"Acuéstate en banco plano. Agarra la barra con agarre al ancho de hombros o ligeramente cerrado. Brazos extendidos sobre el pecho alto.","execution":"Bajá la barra combinando flexión de codo y descenso hacia la barbilla/cuello. Es un híbrido entre press cerrado y press francés. Extendé para volver.","cues":["Los codos bajan y se flexionan simultáneamente","La barra va hacia la barbilla, no al pecho","Movimiento híbrido, no es ni press ni francés puro"],"mistakes":["Convertirlo en un press cerrado normal","Convertirlo en un press francés normal","Usar demasiado peso sin dominar la técnica"]},"en":{"setup":"Lie on a flat bench. Grip the bar at shoulder width or slightly narrower. Arms extended above upper chest.","execution":"Lower the bar combining elbow flexion and descent toward chin/neck area. It''s a hybrid of close-grip press and skull crusher. Extend to return.","cues":["Elbows lower and bend simultaneously","Bar goes toward chin, not chest","Hybrid movement—neither pure press nor pure crusher"],"mistakes":["Turning it into a regular close-grip press","Turning it into a regular skull crusher","Too heavy before mastering the technique"]}}'::jsonb, true),
    ('Press Tate con mancuernas', 'Dumbbell Tate Press', 6, 'weight_reps', 'dumbbell', '{"es":{"setup":"Acuéstate en banco plano con mancuernas sostenidas arriba, brazos extendidos, palmas mirando a los pies.","execution":"Bajá las mancuernas hacia el pecho flexionando los codos hacia adentro (los codos apuntan hacia afuera). Los extremos internos de las mancuernas bajan al pecho. Extendé para volver.","cues":["Los codos van hacia afuera, no hacia la cabeza","Las mancuernas bajan al centro del pecho","Movimiento único, cuesta acostumbrarse"],"mistakes":["Confundirlo con un press francés (dirección incorrecta de codos)","Dejar caer las mancuernas en el pecho","Usar demasiado peso antes de dominar el patrón"]},"en":{"setup":"Lie on a flat bench holding dumbbells above you, arms extended, palms facing your feet.","execution":"Lower the dumbbells toward your chest by bending elbows outward. The inner ends of the dumbbells come down to chest. Extend to return.","cues":["Elbows flare outward, not toward head","Dumbbells lower to the center of chest","Unique movement pattern—takes practice"],"mistakes":["Confusing it with a skull crusher (wrong elbow direction)","Dropping dumbbells onto chest","Too heavy before mastering the pattern"]}}'::jsonb, true),
    ('Curl de muñeca con barra', 'Barbell Wrist Curl', 7, 'weight_reps', 'barbell', '{"es":{"setup":"Siéntate en un banco con los antebrazos apoyados en los muslos, muñecas sobresaliendo del borde de las rodillas. Agarra la barra con agarre supino.","execution":"Deja que la barra ruede hacia los dedos bajando las muñecas. Luego enrolla la barra hacia arriba flexionando las muñecas al máximo. Movimiento lento y controlado.","cues":["Solo se mueven las muñecas","Deja rodar hasta los dedos y luego aprieta","Movimiento lento, sin impulso"],"mistakes":["Mover los antebrazos (deben estar fijos)","Usar impulso con el cuerpo","Peso excesivo que limita el rango"]},"en":{"setup":"Sit on a bench with forearms resting on your thighs, wrists hanging over the edge of your knees. Grip the bar with an underhand grip.","execution":"Let the bar roll toward your fingertips by lowering your wrists. Then curl the bar up by flexing your wrists fully. Slow, controlled movement.","cues":["Only the wrists move","Let it roll to the fingers, then squeeze up","Slow movement, no momentum"],"mistakes":["Moving the forearms (they should be fixed)","Using body momentum","Excessive weight limiting range of motion"]}}'::jsonb, true),
    ('Curl de muñeca con mancuernas', 'Dumbbell Wrist Curl', 7, 'weight_reps', 'dumbbell', '{"es":{"setup":"Siéntate con los antebrazos apoyados en los muslos, muñecas fuera de las rodillas. Una mancuerna en cada mano con agarre supino.","execution":"Baja las muñecas dejando rodar las mancuernas hacia los dedos. Flexiona las muñecas hacia arriba apretando los flexores del antebrazo. Movimiento controlado.","cues":["Antebrazos fijos en los muslos","Rango completo: baja y sube al máximo","Sin prisa, contrae conscientemente"],"mistakes":["Levantar los antebrazos de los muslos","Usar impulso para subir las mancuernas","Rango de movimiento incompleto"]},"en":{"setup":"Sit with forearms resting on your thighs, wrists over the edge of your knees. A dumbbell in each hand with an underhand grip.","execution":"Lower your wrists, letting the dumbbells roll toward your fingertips. Flex your wrists upward, squeezing the forearm flexors. Controlled movement.","cues":["Forearms stay fixed on the thighs","Full range: lower and raise completely","No rush, contract consciously"],"mistakes":["Lifting forearms off the thighs","Using momentum to curl the dumbbells","Incomplete range of motion"]}}'::jsonb, true),
    ('Curl de muñeca invertido con barra', 'Barbell Reverse Wrist Curl', 7, 'weight_reps', 'barbell', '{"es":{"setup":"Siéntate con los antebrazos apoyados en los muslos, muñecas fuera de las rodillas. Agarra la barra con agarre prono (palmas hacia abajo).","execution":"Baja las muñecas al máximo. Extiende las muñecas hacia arriba contrayendo los extensores del antebrazo. Usa peso ligero: estos músculos son pequeños.","cues":["Solo se mueven las muñecas","Peso ligero, rango completo","Contracción consciente arriba"],"mistakes":["Usar demasiado peso (riesgo de lesión)","Mover los antebrazos","Rango de movimiento parcial"]},"en":{"setup":"Sit with forearms on your thighs, wrists over the edge of your knees. Grip the bar with an overhand grip (palms down).","execution":"Lower your wrists fully. Extend your wrists upward, contracting the forearm extensors. Use light weight — these muscles are small.","cues":["Only the wrists move","Light weight, full range","Conscious contraction at the top"],"mistakes":["Using too much weight (injury risk)","Moving the forearms","Partial range of motion"]}}'::jsonb, true),
    ('Curl de muñeca invertido con mancuernas', 'Dumbbell Reverse Wrist Curl', 7, 'weight_reps', 'dumbbell', '{"es":{"setup":"Siéntate con los antebrazos apoyados en los muslos, muñecas fuera de las rodillas. Mancuernas con agarre prono (palmas hacia abajo).","execution":"Baja las muñecas controladamente. Extiende hacia arriba contrayendo los extensores. Peso ligero, movimiento lento.","cues":["Antebrazos fijos, solo muñecas","Peso ligero: calidad sobre cantidad","Pausa arriba 1 segundo"],"mistakes":["Demasiado peso para músculos tan pequeños","Levantar los antebrazos de los muslos","Hacer el movimiento demasiado rápido"]},"en":{"setup":"Sit with forearms on your thighs, wrists over the edge of your knees. Dumbbells with an overhand grip (palms down).","execution":"Lower wrists under control. Extend upward, contracting the extensors. Light weight, slow movement.","cues":["Forearms fixed, only wrists move","Light weight: quality over quantity","Pause at the top for 1 second"],"mistakes":["Too much weight for such small muscles","Lifting forearms off the thighs","Moving too fast"]}}'::jsonb, true),
    ('Curl inverso con barra EZ', 'EZ-Bar Reverse Curl', 7, 'weight_reps', 'barbell', '{"es":{"setup":"De pie con la barra EZ agarrada en prono (palmas hacia abajo) a la anchura de los hombros. Codos pegados al cuerpo.","execution":"Flexiona los codos llevando la barra hacia los hombros manteniendo el agarre prono. Aprieta arriba. Baja con control sin mover los codos.","cues":["Codos pegados al torso, inmóviles","Agarre prono todo el tiempo","Baja despacio, la excéntrica importa"],"mistakes":["Balancear el cuerpo para usar impulso","Mover los codos hacia delante","Usar demasiado peso (es un ejercicio de antebrazo, no de bíceps)"]},"en":{"setup":"Stand with the EZ bar in an overhand grip (palms down) at shoulder width. Elbows pinned to your sides.","execution":"Curl the bar toward your shoulders keeping the overhand grip. Squeeze at the top. Lower with control without moving your elbows.","cues":["Elbows glued to the torso, don''t move","Overhand grip the entire time","Slow descent — the eccentric matters"],"mistakes":["Swinging the body for momentum","Moving elbows forward","Too much weight (this targets forearms, not biceps)"]}}'::jsonb, true),
    ('Curl inverso con barra recta', 'Barbell Reverse Curl', 7, 'weight_reps', 'barbell', '{"es":{"setup":"De pie con la barra recta agarrada en prono a la anchura de los hombros. Codos pegados al cuerpo, brazos extendidos.","execution":"Flexiona los codos llevando la barra hacia los hombros sin mover los codos. Aprieta el braquiorradial arriba. Baja controladamente.","cues":["Codos fijos al cuerpo","La muñeca no se flexiona: mantén alineación","Control en la bajada"],"mistakes":["Impulso con el torso","Flexionar las muñecas (deben estar alineadas)","Adelantar los codos"]},"en":{"setup":"Stand with a straight bar in an overhand grip at shoulder width. Elbows pinned to your body, arms extended.","execution":"Curl the bar toward your shoulders without moving your elbows. Squeeze the brachioradialis at the top. Lower under control.","cues":["Elbows fixed to the body","Wrists don''t flex — keep them aligned","Control on the way down"],"mistakes":["Torso momentum","Flexing the wrists (they should stay aligned)","Elbows drifting forward"]}}'::jsonb, true),
    ('Curl inverso en polea', 'Cable Reverse Curl', 7, 'weight_reps', 'cable', '{"es":{"setup":"De pie frente a la polea baja. Agarra la barra recta o EZ con agarre prono. Codos pegados al cuerpo.","execution":"Flexiona los codos llevando la barra hacia los hombros. La polea mantiene tensión constante. Aprieta arriba. Baja con control.","cues":["Tensión constante gracias a la polea","Codos fijos al torso","Aprieta el antebrazo arriba"],"mistakes":["Mover los codos hacia delante","Usar impulso balanceando el cuerpo","Dejar que la polea tire de ti en la bajada"]},"en":{"setup":"Stand facing the low pulley. Grip the straight or EZ bar with an overhand grip. Elbows pinned to your body.","execution":"Curl the bar toward your shoulders. The cable maintains constant tension. Squeeze at the top. Lower with control.","cues":["Constant tension thanks to the cable","Elbows fixed to the torso","Squeeze the forearm at the top"],"mistakes":["Moving elbows forward","Using momentum by swinging the body","Letting the cable yank you down on the descent"]}}'::jsonb, true),
    ('Paseo del granjero', 'Farmer''s Walk', 7, 'weight_distance', 'dumbbell', '{"es":{"setup":"Toma una mancuerna pesada o kettlebell en cada mano. De pie erguido con hombros atrás y abajo. Core activado.","execution":"Camina con pasos cortos y controlados manteniendo la postura erguida. Aprieta fuerte el agarre. Mantén los hombros estables y nivelados. Recorre la distancia o tiempo objetivo.","cues":["Postura alta, hombros atrás","Agarre de muerte: aprieta como si se te fueran a caer","Pasos cortos y rápidos"],"mistakes":["Inclinarse hacia los lados","Pasos demasiado largos que desestabilizan","Dejar caer los hombros hacia delante"]},"en":{"setup":"Pick up a heavy dumbbell or kettlebell in each hand. Stand tall with shoulders back and down. Core braced.","execution":"Walk with short, controlled steps while maintaining upright posture. Grip hard. Keep shoulders stable and level. Cover the target distance or time.","cues":["Tall posture, shoulders back","Death grip — squeeze like they''re about to slip","Short, quick steps"],"mistakes":["Leaning to one side","Steps too long, causing instability","Letting shoulders roll forward"]}}'::jsonb, true),
    ('Dead hang', 'Dead Hang', 7, 'time', 'bodyweight', '{"es":{"setup":"Cuélgate de una barra con agarre prono a la anchura de los hombros. Brazos completamente extendidos. Hombros relajados (no empaquetados).","execution":"Mantén la posición colgado con los brazos completamente rectos. Respira de forma constante. Aguanta el máximo tiempo posible sin soltar.","cues":["Brazos rectos, sin flexionar","Respira de forma relajada","Agarre firme, sin recolocar las manos"],"mistakes":["Flexionar los codos (ya no es dead hang)","Aguantar la respiración","Balancearse innecesariamente"]},"en":{"setup":"Hang from a bar with an overhand grip at shoulder width. Arms fully extended. Shoulders relaxed (not packed).","execution":"Hold the hanging position with completely straight arms. Breathe steadily. Hold for as long as possible without letting go.","cues":["Arms straight, no bending","Breathe in a relaxed manner","Firm grip, don''t readjust hands"],"mistakes":["Bending the elbows (it''s no longer a dead hang)","Holding your breath","Swinging unnecessarily"]}}'::jsonb, true),
    ('Dead hang con peso', 'Weighted Dead Hang', 7, 'weight_time', 'bodyweight', '{"es":{"setup":"Coloca peso extra con un cinturón de lastre o sujeta una mancuerna entre los pies. Cuélgate con agarre prono, brazos extendidos.","execution":"Mantén la posición colgado con brazos rectos. El peso extra desafía el agarre. Respira de forma controlada. Aguanta el máximo tiempo posible.","cues":["Brazos completamente rectos","Respiración controlada","Aguanta hasta que el agarre falle"],"mistakes":["Flexionar los codos para aliviar tensión","Balancear el cuerpo por el peso extra","Empezar con demasiado peso"]},"en":{"setup":"Add weight via a dip belt or hold a dumbbell between your feet. Hang with an overhand grip, arms extended.","execution":"Hold the hanging position with straight arms. The extra weight challenges your grip. Breathe steadily. Hold as long as possible.","cues":["Arms fully straight","Controlled breathing","Hold until grip fails"],"mistakes":["Bending elbows to relieve tension","Swinging the body due to extra weight","Starting with too much weight"]}}'::jsonb, true),
    ('Agarre con pinza de disco', 'Plate Pinch Hold', 7, 'weight_time', 'plate', '{"es":{"setup":"Junta dos discos lisos (cara lisa hacia fuera) y sujétalos con los dedos en pinza (pulgar de un lado, dedos del otro). De pie erguido.","execution":"Sostén los discos en pinza con el brazo a un lado del cuerpo. Aguanta el máximo tiempo posible sin que se resbalen. Repite con la otra mano.","cues":["Pulgar fuerte contra los dedos","Aprieta antes de que se resbale","Brazo recto a un lado del cuerpo"],"mistakes":["Apoyar los discos contra el muslo","Usar discos con textura (demasiado fácil)","No trabajar ambas manos por igual"]},"en":{"setup":"Put two smooth plates together (smooth sides out) and hold them in a pinch grip (thumb on one side, fingers on the other). Stand upright.","execution":"Hold the plates in a pinch grip with your arm at your side. Hold as long as possible without them slipping. Repeat with the other hand.","cues":["Thumb pressing hard against fingers","Squeeze harder before they slip","Arm straight at your side"],"mistakes":["Resting the plates against your thigh","Using textured plates (too easy)","Not training both hands equally"]}}'::jsonb, true),
    ('Enrollamiento de muñeca con rodillo', 'Wrist Roller', 7, 'weight_reps', 'other', '{"es":{"setup":"De pie con los brazos extendidos al frente a la altura de los hombros, sosteniendo el rodillo con ambas manos. El peso cuelga de la cuerda.","execution":"Enrolla la cuerda alrededor del rodillo girando las muñecas alternadamente hasta subir el peso completamente. Luego desenrolla de forma controlada.","cues":["Brazos rectos a la altura de los hombros","Gira una muñeca mientras sujetas con la otra","Enrollar y desenrollar es una repetición completa"],"mistakes":["Bajar los brazos por cansancio (pierde efectividad)","Desenrollar dejando caer el peso de golpe","Usar demasiado peso demasiado pronto"]},"en":{"setup":"Stand with arms extended forward at shoulder height, holding the roller with both hands. Weight hangs from the rope.","execution":"Roll the rope around the roller by alternating wrist rotations until the weight is fully raised. Then unroll in a controlled manner.","cues":["Arms straight at shoulder height","Rotate one wrist while gripping with the other","Rolling up and down is one full rep"],"mistakes":["Dropping the arms from fatigue (loses effectiveness)","Unrolling by letting the weight drop","Too much weight too soon"]}}'::jsonb, true),
    ('Agarre con gripper', 'Hand Gripper', 7, 'weight_reps', 'other', '{"es":{"setup":"Toma el gripper con una mano. Coloca la parte fija contra la palma y la parte móvil contra los dedos. Codo puede estar flexionado o brazo recto.","execution":"Cierra el gripper apretando con fuerza hasta que las asas se toquen. Mantén cerrado 1 segundo. Abre con control. Repite.","cues":["Cierre completo: las asas se tocan","Pausa con el gripper cerrado","Apertura controlada, no dejes que se abra solo"],"mistakes":["No cerrar completamente (repetición no válida)","Usar la otra mano para ayudar al cierre","Hacer repeticiones demasiado rápidas sin control"]},"en":{"setup":"Hold the gripper with one hand. Place the fixed handle against your palm and the moving handle against your fingers. Elbow can be bent or arm straight.","execution":"Close the gripper by squeezing hard until the handles touch. Hold closed for 1 second. Open with control. Repeat.","cues":["Full close: handles must touch","Pause with the gripper closed","Controlled opening, don''t let it spring open"],"mistakes":["Not closing completely (rep doesn''t count)","Using the other hand to assist the close","Repping too fast without control"]}}'::jsonb, true),
    ('Sentadilla con barra alta', 'High-Bar Back Squat', 8, 'weight_reps', 'barbell', '{"es":{"setup":"Coloca la barra sobre los trapecios superiores, pies a la anchura de hombros con las puntas ligeramente hacia fuera.","execution":"Desciende rompiendo caderas y rodillas a la vez, manteniendo el torso lo más vertical posible. Baja hasta que la cadera quede por debajo de las rodillas y sube empujando el suelo con todo el pie.","cues":["Pecho arriba, codos debajo de la barra","Rodillas en línea con las puntas de los pies","Empuja el suelo, no levantes la barra"],"mistakes":["Despegar los talones del suelo","Dejar que las rodillas colapsen hacia dentro","Inclinar el torso excesivamente hacia delante"]},"en":{"setup":"Place the bar on your upper traps, feet shoulder-width apart with toes slightly turned out.","execution":"Descend by breaking at hips and knees simultaneously, keeping your torso as upright as possible. Go down until hips are below knees, then drive up through the whole foot.","cues":["Chest up, elbows under the bar","Knees tracking over toes","Push the floor away"],"mistakes":["Heels lifting off the floor","Letting knees cave inward","Excessive forward lean of the torso"]}}'::jsonb, true),
    ('Sentadilla con barra baja', 'Low-Bar Back Squat', 8, 'weight_reps', 'barbell', '{"es":{"setup":"Coloca la barra sobre la espina de la escápula (más baja que en barra alta), agarre ancho. Pies ligeramente más abiertos que los hombros.","execution":"Inicia el descenso llevando la cadera hacia atrás. El torso se inclina más que en barra alta de forma natural. Baja hasta paralelo o por debajo y sube empujando la cadera hacia arriba y adelante.","cues":["Cadera atrás primero","Aprieta la espalda alta contra la barra","Mantén la presión abdominal constante"],"mistakes":["Colocar la barra sobre los trapecios como en barra alta","Perder la tensión en la espalda alta y que la barra se desplace","Redondear la zona lumbar en la parte baja"]},"en":{"setup":"Place the bar on your rear deltoids across the scapular spine (lower than high-bar), wider grip. Feet slightly wider than shoulder-width.","execution":"Initiate the descent by pushing hips back. The torso will naturally lean forward more than high-bar. Descend to parallel or below, then drive hips up and forward.","cues":["Hips back first","Squeeze upper back tight against the bar","Maintain constant bracing"],"mistakes":["Placing the bar too high on the traps","Losing upper-back tightness and letting the bar slide","Rounding the lower back at the bottom"]}}'::jsonb, true),
    ('Sentadilla frontal', 'Front Squat', 8, 'weight_reps', 'barbell', '{"es":{"setup":"Apoya la barra en los deltoides frontales, codos altos apuntando al frente. Pies a la anchura de hombros.","execution":"Desciende manteniendo los codos altos y el torso muy vertical. Baja lo más profundo que puedas sin perder la posición de codos. Sube empujando el suelo manteniendo el pecho arriba.","cues":["Codos altos siempre","Torso vertical como si tuvieras una pared detrás","Respira y aprieta el core antes de bajar"],"mistakes":["Dejar caer los codos, lo que hace que la barra ruede hacia delante","Inclinar el torso en exceso","No tener suficiente movilidad de muñeca y forzar el agarre"]},"en":{"setup":"Rest the bar on your front deltoids, elbows high and pointing forward. Feet shoulder-width apart.","execution":"Descend while keeping elbows high and torso very upright. Go as deep as you can without losing elbow position. Drive up through the floor keeping your chest up.","cues":["Elbows high at all times","Torso vertical as if there''s a wall behind you","Brace your core before descending"],"mistakes":["Dropping the elbows, causing the bar to roll forward","Excessive forward lean","Forcing the grip with insufficient wrist mobility"]}}'::jsonb, true),
    ('Sentadilla goblet con mancuerna', 'Dumbbell Goblet Squat', 8, 'weight_reps', 'dumbbell', '{"es":{"setup":"Sujeta una mancuerna vertical contra el pecho, agarrándola por un extremo con ambas manos. Pies a la anchura de hombros o ligeramente más abiertos.","execution":"Desciende empujando las rodillas hacia fuera, manteniendo la mancuerna pegada al pecho. Baja hasta que los codos toquen el interior de las rodillas y sube controladamente.","cues":["Mancuerna pegada al pecho","Rodillas hacia fuera siguiendo las puntas de los pies","Torso vertical"],"mistakes":["Separar la mancuerna del pecho e inclinarse hacia delante","Juntar las rodillas al subir","No bajar lo suficiente"]},"en":{"setup":"Hold a dumbbell vertically against your chest, gripping one end with both hands. Feet shoulder-width or slightly wider.","execution":"Descend pushing your knees out, keeping the dumbbell tight to your chest. Go down until your elbows touch the inside of your knees, then drive up with control.","cues":["Dumbbell tight to chest","Knees tracking out over toes","Upright torso"],"mistakes":["Letting the dumbbell drift away from the chest and leaning forward","Knees caving in on the way up","Cutting depth short"]}}'::jsonb, true),
    ('Sentadilla goblet con kettlebell', 'Kettlebell Goblet Squat', 8, 'weight_reps', 'kettlebell', '{"es":{"setup":"Sujeta la kettlebell por los cuernos contra el pecho, con los codos pegados al cuerpo. Pies a la anchura de hombros.","execution":"Desciende controladamente empujando las rodillas hacia fuera. Usa los codos para abrir las rodillas en la parte baja. Sube empujando con todo el pie.","cues":["Codos entre las rodillas en la parte baja","Peso en el centro del pie","Core apretado durante todo el movimiento"],"mistakes":["Dejar que la kettlebell tire el torso hacia delante","No abrir suficiente las rodillas","Rebotar en la parte baja del movimiento"]},"en":{"setup":"Hold the kettlebell by the horns against your chest, elbows tucked. Feet shoulder-width apart.","execution":"Descend with control, pushing knees out. Use your elbows to pry your knees open at the bottom. Drive up through the whole foot.","cues":["Elbows between knees at the bottom","Weight over midfoot","Core braced throughout"],"mistakes":["Letting the kettlebell pull your torso forward","Not opening the knees enough","Bouncing out of the bottom"]}}'::jsonb, true),
    ('Sentadilla en máquina Smith', 'Smith Machine Squat', 8, 'weight_reps', 'smith_machine', '{"es":{"setup":"Colócate bajo la barra con los pies ligeramente adelantados respecto a la cadera. Barra sobre los trapecios, desbloquea girando las muñecas.","execution":"Desciende controladamente hasta paralelo o por debajo. La posición de pies adelantada permite un torso más vertical. Sube empujando con fuerza contra el suelo.","cues":["Pies adelantados para mayor énfasis en cuádriceps","Espalda apoyada contra la barra en todo momento","Desciende lento, sube explosivo"],"mistakes":["Poner los pies justo debajo de la barra como en sentadilla libre","Bloquear las rodillas agresivamente arriba","Descuidar la profundidad por usar demasiado peso"]},"en":{"setup":"Stand under the bar with feet slightly forward of your hips. Bar on upper traps, unlock by twisting your wrists.","execution":"Descend with control to parallel or below. The forward foot placement allows a more upright torso. Drive up powerfully through the floor.","cues":["Feet forward to emphasize quads","Back pressed against the bar throughout","Slow descent, explosive ascent"],"mistakes":["Placing feet directly under the bar as in free squats","Aggressively locking out knees at the top","Sacrificing depth for heavier weight"]}}'::jsonb, true),
    ('Sentadilla hack en máquina', 'Hack Squat Machine', 8, 'weight_reps', 'machine', '{"es":{"setup":"Apoya la espalda completamente en el respaldo, hombros bajo las almohadillas. Pies en la mitad inferior de la plataforma, separados al ancho de hombros.","execution":"Desbloquea y desciende controladamente hasta que las rodillas formen 90° o más. Empuja la plataforma hasta casi extender las piernas sin bloquear las rodillas.","cues":["Espalda pegada al respaldo todo el tiempo","Pies más bajos = más cuádriceps","No bloquees las rodillas arriba"],"mistakes":["Despegar la espalda baja del respaldo","Colocar los pies demasiado altos, reduciendo el trabajo de cuádriceps","Hacer medias repeticiones"]},"en":{"setup":"Press your back fully against the pad, shoulders under the supports. Place feet on the lower half of the platform, shoulder-width apart.","execution":"Unlock and descend with control until knees reach 90° or deeper. Push the platform back up to near-lockout without fully locking your knees.","cues":["Back glued to the pad at all times","Lower foot placement = more quads","Don''t lock out knees at the top"],"mistakes":["Lower back lifting off the pad","Placing feet too high, reducing quad emphasis","Doing half reps"]}}'::jsonb, true),
    ('Sentadilla búlgara con mancuernas', 'Dumbbell Bulgarian Split Squat', 8, 'weight_reps', 'dumbbell', '{"es":{"setup":"Coloca el empeine del pie trasero sobre un banco. Pie delantero a unos 60-70 cm del banco. Mancuerna en cada mano.","execution":"Desciende verticalmente doblando la rodilla delantera hasta que el muslo quede paralelo al suelo. La rodilla trasera baja hacia el suelo sin tocarlo. Sube empujando con el pie delantero.","cues":["Torso vertical, no te inclines hacia delante","Todo el peso en el pie delantero","Rodilla delantera en línea con el pie"],"mistakes":["Poner el pie delantero demasiado cerca del banco","Inclinarse hacia delante cargando la espalda baja","Impulsarse con el pie trasero en vez del delantero"]},"en":{"setup":"Place the top of your rear foot on a bench. Front foot about 60-70 cm from the bench. Hold a dumbbell in each hand.","execution":"Descend vertically by bending the front knee until the thigh is parallel to the floor. The rear knee drops toward the ground without touching. Push up through the front foot.","cues":["Torso upright, don''t lean forward","All weight on the front foot","Front knee tracking over the foot"],"mistakes":["Front foot too close to the bench","Leaning forward and loading the lower back","Pushing off with the rear foot instead of the front"]}}'::jsonb, true),
    ('Sentadilla búlgara con barra', 'Barbell Bulgarian Split Squat', 8, 'weight_reps', 'barbell', '{"es":{"setup":"Barra sobre los trapecios como en una sentadilla. Empeine del pie trasero apoyado en un banco. Pie delantero firme en el suelo.","execution":"Desciende controladamente manteniendo el torso vertical. Baja hasta que el muslo delantero esté paralelo al suelo. Sube empujando con fuerza a través del pie delantero.","cues":["Estabiliza la barra antes de empezar","Desciende recto, no hacia delante","Mantén el core activado para el equilibrio"],"mistakes":["Perder el equilibrio por falta de estabilización previa","Apoyar demasiado peso en el pie trasero","Dejar que la rodilla pase excesivamente por delante del pie"]},"en":{"setup":"Bar on your upper traps as in a squat. Top of rear foot resting on a bench. Front foot firmly on the floor.","execution":"Descend with control keeping the torso vertical. Lower until the front thigh is parallel to the floor. Drive up powerfully through the front foot.","cues":["Stabilize the bar before starting","Descend straight down, not forward","Keep core engaged for balance"],"mistakes":["Losing balance from poor initial stabilization","Putting too much weight on the rear foot","Letting the knee travel excessively past the toes"]}}'::jsonb, true),
    ('Sentadilla búlgara en máquina Smith', 'Smith Machine Bulgarian Split Squat', 8, 'weight_reps', 'smith_machine', '{"es":{"setup":"Barra de la Smith sobre los trapecios. Pie trasero en un banco detrás de ti. Ajusta el pie delantero para que la rodilla quede alineada al bajar.","execution":"Desbloquea la barra y desciende verticalmente. La guía de la máquina te ayuda con el equilibrio. Baja hasta paralelo y sube de forma controlada.","cues":["Aprovecha la estabilidad de la máquina para centrarte en la pierna","Pie delantero ligeramente adelantado","Controla la bajada, no te dejes caer"],"mistakes":["Mala colocación del pie delantero que sobrecargue la rodilla","Depender tanto de la máquina que pierdas tensión en el core","No alcanzar suficiente profundidad"]},"en":{"setup":"Smith bar on your upper traps. Rear foot on a bench behind you. Adjust front foot so the knee tracks properly when descending.","execution":"Unlock the bar and descend vertically. The machine guide helps with balance. Lower to parallel and drive up with control.","cues":["Use the machine''s stability to focus on the working leg","Front foot slightly forward","Control the descent, don''t drop"],"mistakes":["Poor front foot placement overloading the knee","Relying so much on the machine that you lose core tension","Not reaching sufficient depth"]}}'::jsonb, true),
    ('Sentadilla sissy', 'Sissy Squat', 8, 'reps_only', 'bodyweight', '{"es":{"setup":"De pie, sujétate a un soporte para mantener el equilibrio. Pies al ancho de caderas, de puntillas.","execution":"Inclina el torso hacia atrás mientras doblas las rodillas, dejando que avancen lo máximo posible. Las caderas y el torso forman una línea recta. Desciende hasta que sientas un estiramiento intenso en los cuádriceps y sube contrayendo.","cues":["Cadera y torso alineados, no te sientes hacia atrás","Rodillas hacia delante todo lo posible","Movimiento lento y controlado"],"mistakes":["Romper en la cadera como en una sentadilla normal","Bajar demasiado rápido y perder el control","No mantener los talones elevados"]},"en":{"setup":"Stand holding a support for balance. Feet hip-width apart, up on your toes.","execution":"Lean your torso back while bending the knees, letting them travel forward as far as possible. Hips and torso form a straight line. Descend until you feel an intense quad stretch, then drive up by contracting the quads.","cues":["Hips and torso aligned, don''t sit back","Knees as far forward as possible","Slow, controlled movement"],"mistakes":["Breaking at the hips like a regular squat","Descending too fast and losing control","Not keeping heels elevated"]}}'::jsonb, true),
    ('Sentadilla en pendulum', 'Pendulum Squat', 8, 'weight_reps', 'machine', '{"es":{"setup":"Colócate en la máquina con la espalda contra el respaldo y los hombros bajo las almohadillas. Pies en la parte inferior de la plataforma.","execution":"Desbloquea y desciende controladamente. El movimiento pendular imita una sentadilla natural con gran recorrido. Baja profundo y empuja hasta casi extender las piernas.","cues":["Espalda siempre en contacto con el respaldo","Pies bajos para máximo trabajo de cuádriceps","Aprovecha el rango completo de movimiento"],"mistakes":["Colocar los pies demasiado altos en la plataforma","Hacer repeticiones parciales","Despegar la zona lumbar del respaldo"]},"en":{"setup":"Position yourself with your back against the pad and shoulders under the supports. Place feet on the lower portion of the platform.","execution":"Unlock and descend with control. The pendulum motion mimics a natural squat with great range of motion. Go deep and push back up to near-extension.","cues":["Back always in contact with the pad","Low foot position for maximum quad work","Use the full range of motion"],"mistakes":["Placing feet too high on the platform","Doing partial reps","Lower back lifting off the pad"]}}'::jsonb, true),
    ('Sentadilla con cinturón', 'Belt Squat', 8, 'weight_reps', 'machine', '{"es":{"setup":"Colócate el cinturón de carga en la cadera con el peso colgando entre las piernas. Pies en las plataformas elevadas, al ancho de hombros.","execution":"Desciende como en una sentadilla normal hasta profundidad completa. La carga va directo a las piernas sin comprimir la columna. Sube empujando las plataformas con fuerza.","cues":["Torso vertical, sin carga en la espalda","Profundidad completa","Empuja las plataformas como si quisieras separarlas"],"mistakes":["Inclinarse hacia delante innecesariamente","No bajar lo suficiente","Sujetarse a las asas con demasiada fuerza, quitando trabajo a las piernas"]},"en":{"setup":"Wear the loading belt around your hips with weight hanging between your legs. Feet on the elevated platforms, shoulder-width apart.","execution":"Descend as in a regular squat to full depth. The load goes directly to the legs without spinal compression. Push the platforms forcefully to ascend.","cues":["Upright torso, no load on the spine","Full depth","Push the platforms as if spreading them apart"],"mistakes":["Leaning forward unnecessarily","Not going deep enough","Gripping the handles too hard, taking work from the legs"]}}'::jsonb, true),
    ('Prensa de piernas', 'Leg Press', 8, 'weight_reps', 'machine', '{"es":{"setup":"Siéntate con la espalda y el glúteo bien apoyados en el asiento. Pies al ancho de hombros en el centro de la plataforma.","execution":"Desbloquea y baja la plataforma controladamente hasta que las rodillas formen 90° o ligeramente más. Empuja de vuelta sin bloquear las rodillas arriba.","cues":["Glúteo pegado al asiento en todo momento","Empuja con toda la planta del pie","No bloquees las rodillas arriba"],"mistakes":["Despegar el glúteo del asiento al bajar demasiado","Bloquear las rodillas completamente arriba","Usar un rango de movimiento demasiado corto"]},"en":{"setup":"Sit with your back and glutes pressed firmly into the seat. Feet shoulder-width in the center of the platform.","execution":"Unlock and lower the platform with control until knees reach 90° or slightly more. Push back up without locking your knees at the top.","cues":["Glutes glued to the seat at all times","Push through the entire foot","Don''t lock out knees at the top"],"mistakes":["Glutes lifting off the seat from going too deep","Fully locking the knees at the top","Using too short a range of motion"]}}'::jsonb, true),
    ('Prensa de piernas inclinada', 'Incline Leg Press', 8, 'weight_reps', 'machine', '{"es":{"setup":"Siéntate en la prensa a 45°, espalda y glúteo firmemente apoyados. Pies al ancho de hombros en la plataforma.","execution":"Desbloquea los seguros y baja la plataforma controladamente flexionando las rodillas. Desciende hasta que las rodillas formen al menos 90° y empuja de vuelta.","cues":["Zona lumbar siempre en contacto con el respaldo","Respiración: inhala al bajar, exhala al empujar","Rango completo y controlado"],"mistakes":["Dejar que el glúteo se despegue al final del recorrido","Rebotar la plataforma en la parte baja","Colocar los pies demasiado altos o bajos sin intención"]},"en":{"setup":"Sit on the 45° leg press, back and glutes firmly against the pad. Feet shoulder-width on the platform.","execution":"Release the safeties and lower the platform by bending the knees. Descend until knees reach at least 90° and push back up.","cues":["Lower back always in contact with the pad","Breathe: inhale down, exhale on the push","Full, controlled range of motion"],"mistakes":["Glutes lifting off at the bottom of the rep","Bouncing the platform at the bottom","Foot placement too high or low without intention"]}}'::jsonb, true),
    ('Prensa de piernas horizontal', 'Horizontal Leg Press', 8, 'weight_reps', 'machine', '{"es":{"setup":"Siéntate con la espalda recta contra el respaldo. Pies al ancho de hombros en la plataforma, rodillas alineadas con los pies.","execution":"Empuja la plataforma hasta casi extender las piernas, luego flexiona las rodillas para volver a la posición inicial con control. Mantén un ritmo constante.","cues":["Espalda recta y apoyada","Empuja de forma uniforme con ambas piernas","No bloquees rodillas"],"mistakes":["Redondear la espalda baja","Empujar más con una pierna que con la otra","Usar impulso en vez de fuerza controlada"]},"en":{"setup":"Sit with your back straight against the pad. Feet shoulder-width on the platform, knees aligned with feet.","execution":"Push the platform to near-extension, then bend your knees to return with control. Maintain a steady tempo.","cues":["Back straight and supported","Push evenly with both legs","Don''t lock out knees"],"mistakes":["Rounding the lower back","Pushing more with one leg than the other","Using momentum instead of controlled force"]}}'::jsonb, true),
    ('Prensa de piernas pies juntos', 'Narrow Stance Leg Press', 8, 'weight_reps', 'machine', '{"es":{"setup":"Siéntate en la prensa con la espalda bien apoyada. Coloca los pies juntos en el centro-bajo de la plataforma.","execution":"Desbloquea y baja la plataforma hasta que las rodillas formen 90°. La posición estrecha de pies enfatiza el cuádriceps externo. Empuja de vuelta controladamente.","cues":["Pies juntos y centrados","Rodillas juntas durante todo el movimiento","Contracción fuerte arriba sin bloquear"],"mistakes":["Separar las rodillas durante el movimiento","No mantener la espalda baja en contacto con el asiento","Usar demasiado peso sacrificando el rango"]},"en":{"setup":"Sit on the leg press with your back supported. Place feet together on the lower-center of the platform.","execution":"Unlock and lower the platform until knees reach 90°. The narrow stance emphasizes the outer quads. Push back up with control.","cues":["Feet together and centered","Knees together throughout","Strong contraction at the top without locking"],"mistakes":["Letting knees splay apart during the movement","Lower back losing contact with the seat","Too much weight sacrificing range of motion"]}}'::jsonb, true),
    ('Extensión de cuádriceps en máquina', 'Machine Leg Extension', 8, 'weight_reps', 'machine', '{"es":{"setup":"Ajusta el respaldo para que las rodillas queden alineadas con el eje de la máquina. Rodillo en la parte baja de las espinillas, justo encima del tobillo.","execution":"Extiende las piernas contrayendo los cuádriceps hasta la extensión completa. Mantén la contracción un instante arriba y baja controladamente sin dejar que el peso descanse.","cues":["Rodillas alineadas con el eje de rotación de la máquina","Contrae fuerte arriba y aguanta un segundo","Baja lento, sube con intención"],"mistakes":["Usar impulso para levantar el peso","No llegar a la extensión completa","Mover la cadera o despegar el glúteo del asiento"]},"en":{"setup":"Adjust the backrest so your knees align with the machine''s pivot. Pad on the lower shins, just above the ankles.","execution":"Extend your legs by contracting the quads to full extension. Hold the contraction briefly at the top and lower with control without letting the weight rest.","cues":["Knees aligned with the machine''s axis of rotation","Squeeze hard at the top and hold for a second","Slow descent, purposeful ascent"],"mistakes":["Using momentum to lift the weight","Not reaching full extension","Shifting hips or lifting glutes off the seat"]}}'::jsonb, true),
    ('Extensión de cuádriceps unilateral en máquina', 'Single-Leg Machine Leg Extension', 8, 'weight_reps', 'machine', '{"es":{"setup":"Misma configuración que la extensión bilateral pero trabaja una pierna a la vez. Rodilla alineada con el eje, rodillo sobre el tobillo.","execution":"Extiende una pierna hasta la extensión completa contrayendo el cuádriceps. Baja controladamente y completa todas las repeticiones antes de cambiar de pierna.","cues":["Concéntrate en la conexión mente-músculo de esa pierna","No compenses con la cadera","Misma velocidad y rango en ambas piernas"],"mistakes":["Girar la cadera para ayudar al movimiento","Diferente rango de movimiento entre piernas","Usar demasiado peso y perder el control"]},"en":{"setup":"Same setup as bilateral extensions but work one leg at a time. Knee aligned with the pivot, pad on the ankle.","execution":"Extend one leg to full extension, squeezing the quad. Lower with control and complete all reps before switching legs.","cues":["Focus on the mind-muscle connection in that leg","Don''t compensate with the hip","Same speed and range on both legs"],"mistakes":["Rotating the hip to assist the movement","Different range of motion between legs","Too much weight leading to loss of control"]}}'::jsonb, true),
    ('Zancadas con mancuernas', 'Dumbbell Lunges', 8, 'weight_reps', 'dumbbell', '{"es":{"setup":"De pie con una mancuerna en cada mano, brazos extendidos a los lados. Pies juntos.","execution":"Da un paso largo hacia delante y desciende hasta que la rodilla trasera casi toque el suelo. La rodilla delantera no debe pasar excesivamente la punta del pie. Empuja con el pie delantero para volver a la posición inicial.","cues":["Paso largo, descenso vertical","Torso erguido durante todo el movimiento","Empuja con el talón del pie delantero"],"mistakes":["Paso demasiado corto que sobrecarga la rodilla","Inclinarse hacia delante","Dejar que la rodilla delantera colapse hacia dentro"]},"en":{"setup":"Stand holding a dumbbell in each hand, arms at your sides. Feet together.","execution":"Take a long step forward and descend until the back knee nearly touches the floor. The front knee should not travel excessively past the toes. Push off the front foot to return to the start.","cues":["Long step, vertical descent","Torso upright throughout","Push through the front heel"],"mistakes":["Step too short, overloading the knee","Leaning forward","Front knee collapsing inward"]}}'::jsonb, true),
    ('Zancadas con barra', 'Barbell Lunges', 8, 'weight_reps', 'barbell', '{"es":{"setup":"Barra sobre los trapecios como en una sentadilla. De pie con los pies juntos, core activado.","execution":"Da un paso largo hacia delante y baja hasta que la rodilla trasera casi toque el suelo. Mantén el torso vertical con la barra estable. Empuja con el pie delantero para volver.","cues":["Estabiliza la barra antes de dar el paso","Torso vertical, mirada al frente","Paso amplio y controlado"],"mistakes":["Perder el equilibrio por falta de estabilización","Torso inclinado hacia delante por el peso de la barra","Dar un paso demasiado corto"]},"en":{"setup":"Bar on your upper traps as in a squat. Stand with feet together, core braced.","execution":"Take a long step forward and lower until the back knee nearly touches the floor. Keep torso vertical with the bar stable. Push off the front foot to return.","cues":["Stabilize the bar before stepping","Torso vertical, gaze forward","Wide, controlled step"],"mistakes":["Losing balance from poor stabilization","Torso leaning forward under the bar weight","Step too short"]}}'::jsonb, true),
    ('Zancadas caminando', 'Walking Lunges', 8, 'weight_reps', 'bodyweight', '{"es":{"setup":"De pie con mancuernas a los lados o barra en los trapecios. Necesitas espacio para caminar hacia delante.","execution":"Da un paso largo y desciende hasta que la rodilla trasera casi toque el suelo. En lugar de volver, lleva el pie trasero adelante para dar el siguiente paso. Alterna piernas avanzando.","cues":["Cada paso es largo y controlado","Torso erguido durante toda la caminata","Empuja con el talón para avanzar"],"mistakes":["Pasos cortos y rápidos sin control","Perder el equilibrio lateral","Inclinarse hacia delante progresivamente"]},"en":{"setup":"Stand with dumbbells at your sides or a bar on your traps. You need space to walk forward.","execution":"Take a long step and descend until the back knee nearly touches the floor. Instead of returning, bring the rear foot forward for the next step. Alternate legs while advancing.","cues":["Each step is long and controlled","Torso upright throughout the walk","Push through the heel to advance"],"mistakes":["Short, fast steps without control","Losing lateral balance","Progressively leaning forward"]}}'::jsonb, true),
    ('Zancadas inversas con mancuernas', 'Dumbbell Reverse Lunges', 8, 'weight_reps', 'dumbbell', '{"es":{"setup":"De pie con una mancuerna en cada mano, brazos a los lados. Pies a la anchura de caderas.","execution":"Da un paso largo hacia atrás y baja la rodilla trasera hacia el suelo. La espinilla delantera se mantiene más vertical que en la zancada frontal. Empuja con el pie delantero para volver a la posición inicial.","cues":["Paso atrás largo y controlado","Espinilla delantera casi vertical","Empuja con todo el pie delantero para volver"],"mistakes":["Paso demasiado corto hacia atrás","Impulsar el retorno con el pie trasero","Perder el equilibrio al dar el paso"]},"en":{"setup":"Stand with a dumbbell in each hand, arms at your sides. Feet hip-width apart.","execution":"Take a long step back and lower the rear knee toward the floor. The front shin stays more vertical than in a forward lunge. Push through the front foot to return to the start.","cues":["Long, controlled step back","Front shin nearly vertical","Drive through the entire front foot to return"],"mistakes":["Step too short backward","Using the rear foot to push back up","Losing balance while stepping"]}}'::jsonb, true),
    ('Zancadas laterales con mancuernas', 'Dumbbell Lateral Lunges', 8, 'weight_reps', 'dumbbell', '{"es":{"setup":"De pie con mancuernas a los lados o una mancuerna en posición goblet. Pies juntos.","execution":"Da un paso amplio hacia un lado, flexionando esa rodilla mientras la pierna contraria se mantiene extendida. Baja la cadera hacia atrás y abajo. Empuja con la pierna flexionada para volver al centro.","cues":["Peso en el talón de la pierna que trabaja","Cadera hacia atrás como en una sentadilla lateral","Pierna contraria recta con el pie apoyado"],"mistakes":["Rodilla de la pierna que trabaja colapsando hacia dentro","No bajar suficiente la cadera","Inclinar el torso excesivamente"]},"en":{"setup":"Stand with dumbbells at your sides or one dumbbell in goblet position. Feet together.","execution":"Take a wide step to one side, bending that knee while the opposite leg stays straight. Push hips back and down. Drive through the working leg to return to center.","cues":["Weight on the heel of the working leg","Hips back like a lateral squat","Opposite leg straight with foot planted"],"mistakes":["Working knee collapsing inward","Not dropping the hips low enough","Excessive torso lean"]}}'::jsonb, true),
    ('Step up con mancuernas', 'Dumbbell Step-Up', 8, 'weight_reps', 'dumbbell', '{"es":{"setup":"De pie frente a un cajón o banco a la altura de la rodilla. Mancuerna en cada mano, brazos extendidos.","execution":"Coloca un pie completo sobre el cajón y sube empujando exclusivamente con esa pierna. Lleva la rodilla contraria hacia arriba sin apoyar el pie en el cajón. Baja controladamente con la misma pierna.","cues":["Todo el trabajo lo hace la pierna de arriba","No te impulses con el pie de abajo","Pie completamente apoyado en el cajón"],"mistakes":["Impulsarse con el pie del suelo para subir","Cajón demasiado bajo que no genera suficiente estímulo","Inclinarse hacia delante al subir"]},"en":{"setup":"Stand facing a box or bench at about knee height. Hold a dumbbell in each hand, arms extended.","execution":"Place one full foot on the box and step up by driving through that leg only. Bring the opposite knee up without placing the foot on the box. Lower with control on the same leg.","cues":["All the work is done by the top leg","Don''t push off with the bottom foot","Full foot planted on the box"],"mistakes":["Pushing off the ground foot to assist","Box too low to provide sufficient stimulus","Leaning forward when stepping up"]}}'::jsonb, true),
    ('Step up con barra', 'Barbell Step-Up', 8, 'weight_reps', 'barbell', '{"es":{"setup":"Barra sobre los trapecios, de pie frente a un cajón estable. Asegúrate de tener buen equilibrio antes de empezar.","execution":"Coloca un pie en el cajón y sube empujando con esa pierna. Mantén el torso vertical y estable con la barra. Baja controladamente sin impulsarte.","cues":["Estabiliza la barra antes de cada repetición","Sube solo con la pierna del cajón","Baja despacio y controlado"],"mistakes":["Perder el equilibrio con la barra","Usar el pie del suelo para ayudar","Torso inestable durante el movimiento"]},"en":{"setup":"Bar on your traps, standing in front of a stable box. Ensure good balance before starting.","execution":"Place one foot on the box and drive up with that leg. Keep the torso vertical and the bar stable. Lower with control without pushing off.","cues":["Stabilize the bar before each rep","Drive up with the box leg only","Descend slowly and controlled"],"mistakes":["Losing balance with the bar","Using the ground foot to assist","Unstable torso during the movement"]}}'::jsonb, true),
    ('Sentadilla pistol', 'Pistol Squat', 8, 'reps_only', 'bodyweight', '{"es":{"setup":"De pie sobre una pierna, la pierna libre extendida al frente. Brazos al frente para contrapeso.","execution":"Desciende sobre una sola pierna manteniendo la pierna libre elevada y extendida. Baja lo más profundo posible y sube contrayendo el cuádriceps sin ayuda del pie libre.","cues":["Pierna libre recta y elevada al frente","Brazos al frente como contrapeso","Core activado para el equilibrio"],"mistakes":["Dejar que la rodilla colapse hacia dentro","No tener suficiente movilidad de tobillo y caer hacia atrás","Apoyar el pie libre en el suelo al subir"]},"en":{"setup":"Stand on one leg, free leg extended in front. Arms forward as counterbalance.","execution":"Descend on a single leg, keeping the free leg elevated and straight. Go as deep as possible and drive up by contracting the quad without touching the free foot down.","cues":["Free leg straight and elevated in front","Arms forward as counterweight","Core engaged for balance"],"mistakes":["Knee collapsing inward","Insufficient ankle mobility causing you to fall back","Touching the free foot down on the way up"]}}'::jsonb, true),
    ('Sentadilla con salto', 'Jump Squat', 8, 'reps_only', 'bodyweight', '{"es":{"setup":"De pie con los pies al ancho de hombros, brazos a los lados o manos detrás de la cabeza.","execution":"Baja a una posición de sentadilla parcial o completa y salta explosivamente extendiéndote al máximo. Aterriza suavemente flexionando rodillas y caderas para absorber el impacto.","cues":["Aterrizaje suave, de puntas a talones","Explota desde abajo con fuerza máxima","Mantén el core activado durante el salto"],"mistakes":["Aterrizar con las piernas rígidas","No flexionar suficiente antes de saltar","Aterrizar con excesivo valgo de rodillas"]},"en":{"setup":"Stand with feet shoulder-width, arms at sides or hands behind head.","execution":"Lower into a partial or full squat and jump explosively, extending fully. Land softly by bending knees and hips to absorb the impact.","cues":["Soft landing, toes to heels","Explode from the bottom with maximum force","Keep core braced through the jump"],"mistakes":["Landing with stiff legs","Not squatting deep enough before jumping","Landing with excessive knee valgus"]}}'::jsonb, true),
    ('Curl femoral tumbado en máquina', 'Lying Machine Leg Curl', 9, 'weight_reps', 'machine', '{"es":{"setup":"Túmbate boca abajo en la máquina, rodillas alineadas con el eje de rotación. Rodillo justo por encima de los talones, caderas pegadas a la almohadilla.","execution":"Flexiona las rodillas llevando los talones hacia los glúteos contrayendo los isquiotibiales. Mantén la contracción un instante y baja controladamente sin dejar que el peso descanse.","cues":["Caderas pegadas al banco, no las levantes","Contrae los isquios fuerte arriba","Fase excéntrica lenta y controlada"],"mistakes":["Levantar las caderas del banco para ayudar","Usar impulso para mover el peso","Dejar caer el peso en la fase de bajada"]},"en":{"setup":"Lie face down on the machine, knees aligned with the pivot. Pad just above the heels, hips pressed into the cushion.","execution":"Curl your heels toward your glutes by contracting the hamstrings. Hold the contraction briefly and lower with control without letting the weight rest.","cues":["Hips pinned to the bench, don''t lift them","Squeeze hard at the top","Slow, controlled eccentric"],"mistakes":["Lifting hips off the bench to assist","Using momentum to move the weight","Dropping the weight on the way down"]}}'::jsonb, true),
    ('Curl femoral sentado en máquina', 'Seated Machine Leg Curl', 9, 'weight_reps', 'machine', '{"es":{"setup":"Siéntate con la espalda apoyada, rodillas alineadas con el eje de la máquina. Rodillo sobre la parte trasera de los tobillos, almohadilla del muslo ajustada sobre las rodillas.","execution":"Flexiona las rodillas llevando los talones debajo del asiento. Contrae los isquiotibiales al máximo y vuelve a la posición inicial controladamente.","cues":["Espalda apoyada durante todo el movimiento","Contrae al máximo en la posición más flexionada","No dejes que el peso rebote"],"mistakes":["Despegar la espalda del respaldo","Hacer el movimiento demasiado rápido sin control","No alcanzar el rango completo de flexión"]},"en":{"setup":"Sit with your back supported, knees aligned with the machine pivot. Pad behind the ankles, thigh pad adjusted above the knees.","execution":"Curl your heels under the seat by flexing the knees. Contract the hamstrings fully and return to the start with control.","cues":["Back supported throughout","Maximum contraction at the most flexed position","Don''t let the weight bounce"],"mistakes":["Back coming off the pad","Moving too fast without control","Not reaching full range of flexion"]}}'::jsonb, true),
    ('Curl femoral de pie en máquina', 'Standing Machine Leg Curl', 9, 'weight_reps', 'machine', '{"es":{"setup":"De pie frente a la máquina, apoya el muslo en la almohadilla. Rodillo sobre el tendón de Aquiles, agárrate a las asas.","execution":"Flexiona la rodilla llevando el talón hacia el glúteo. Contrae el isquiotibial en la parte alta y baja controladamente. Completa todas las reps de una pierna antes de cambiar.","cues":["Muslo fijo contra la almohadilla","Contracción completa arriba","No balancees el cuerpo"],"mistakes":["Mover la cadera para ayudar al movimiento","Usar impulso del cuerpo","Rango de movimiento incompleto"]},"en":{"setup":"Stand facing the machine, thigh against the pad. Roller on the Achilles tendon, hold the handles.","execution":"Curl the heel toward the glute by bending the knee. Contract the hamstring at the top and lower with control. Complete all reps on one leg before switching.","cues":["Thigh fixed against the pad","Full contraction at the top","Don''t swing the body"],"mistakes":["Moving the hip to assist the movement","Using body momentum","Incomplete range of motion"]}}'::jsonb, true),
    ('Curl femoral unilateral en máquina', 'Single-Leg Machine Leg Curl', 9, 'weight_reps', 'machine', '{"es":{"setup":"Túmbate en la máquina de curl femoral tumbado. Usa solo una pierna, rodillo sobre el tobillo. La pierna libre descansa al lado sin participar.","execution":"Flexiona la rodilla llevando el talón hacia el glúteo con una sola pierna. Mantén la contracción y baja lentamente. Haz todas las reps de un lado antes de cambiar.","cues":["Cadera pegada al banco","Concéntrate en la conexión con el isquiotibial","Mismo tempo y rango en ambas piernas"],"mistakes":["Compensar con la cadera al usar una sola pierna","Usar más peso del que puedes controlar unilateralmente","Diferente rango de movimiento entre piernas"]},"en":{"setup":"Lie on the lying leg curl machine. Use only one leg, pad on the ankle. The free leg rests to the side without assisting.","execution":"Curl the heel toward the glute with one leg. Hold the contraction and lower slowly. Complete all reps on one side before switching.","cues":["Hips pinned to the bench","Focus on the hamstring connection","Same tempo and range on both legs"],"mistakes":["Compensating with the hip when using one leg","Using more weight than you can control unilaterally","Different range of motion between legs"]}}'::jsonb, true),
    ('Peso muerto rumano con barra', 'Barbell Romanian Deadlift', 9, 'weight_reps', 'barbell', '{"es":{"setup":"De pie con la barra en las manos, agarre prono al ancho de hombros. Rodillas ligeramente flexionadas, pies al ancho de caderas.","execution":"Empuja la cadera hacia atrás manteniendo la barra pegada a las piernas. Baja hasta sentir un estiramiento profundo en los isquiotibiales. Vuelve arriba contrayendo glúteos e isquios, sin hiperextender la espalda.","cues":["Barra pegada al cuerpo en todo momento","Cadera atrás, no abajo","Espalda neutra de principio a fin"],"mistakes":["Redondear la espalda al bajar","Flexionar demasiado las rodillas convirtiéndolo en sentadilla","Hiperextender la lumbar arriba"]},"en":{"setup":"Stand holding the bar with a pronated grip at shoulder width. Knees slightly bent, feet hip-width apart.","execution":"Push hips back while keeping the bar close to your legs. Lower until you feel a deep hamstring stretch. Return by driving hips forward, contracting glutes and hamstrings, without hyperextending the back.","cues":["Bar stays close to the body at all times","Hips back, not down","Neutral spine from start to finish"],"mistakes":["Rounding the back on the way down","Bending knees too much, turning it into a squat","Hyperextending the lower back at the top"]}}'::jsonb, true),
    ('Peso muerto rumano con mancuernas', 'Dumbbell Romanian Deadlift', 9, 'weight_reps', 'dumbbell', '{"es":{"setup":"De pie con una mancuerna en cada mano, agarre neutro frente a los muslos. Rodillas ligeramente flexionadas.","execution":"Empuja la cadera atrás deslizando las mancuernas por la parte frontal de las piernas. Baja hasta sentir un estiramiento fuerte en los isquiotibiales. Sube contrayendo glúteos e isquios.","cues":["Mancuernas pegadas a las piernas","Espalda neutra, no redondear","Siente el estiramiento en los isquiotibiales antes de subir"],"mistakes":["Separar las mancuernas de las piernas","Bajar más de lo que la flexibilidad permite, redondeando","Flexionar demasiado las rodillas"]},"en":{"setup":"Stand with a dumbbell in each hand, neutral grip in front of your thighs. Knees slightly bent.","execution":"Push hips back, sliding the dumbbells down the front of your legs. Lower until you feel a strong hamstring stretch. Drive up by contracting glutes and hamstrings.","cues":["Dumbbells close to the legs","Neutral spine, don''t round","Feel the hamstring stretch before ascending"],"mistakes":["Letting dumbbells drift away from the legs","Going lower than flexibility allows and rounding","Bending knees too much"]}}'::jsonb, true),
    ('Peso muerto rumano unilateral', 'Single-Leg Romanian Deadlift', 9, 'weight_reps', 'dumbbell', '{"es":{"setup":"De pie sobre una pierna, mancuerna en la mano contraria (o en ambas). Rodilla de apoyo ligeramente flexionada.","execution":"Inclina el torso hacia delante mientras la pierna libre sube hacia atrás, formando una T con el cuerpo. Baja hasta sentir el estiramiento del isquiotibial y sube contrayendo glúteo e isquio de la pierna de apoyo.","cues":["Cadera cuadrada, no la abras hacia un lado","Pierna trasera y torso se mueven como un bloque","Mira un punto fijo para el equilibrio"],"mistakes":["Abrir la cadera del lado de la pierna libre","Redondear la espalda para llegar más abajo","Perder el equilibrio por ir demasiado rápido"]},"en":{"setup":"Stand on one leg, dumbbell in the opposite hand (or both hands). Supporting knee slightly bent.","execution":"Hinge forward while the free leg rises behind, forming a T with the body. Lower until you feel the hamstring stretch and drive up by contracting the glute and hamstring of the standing leg.","cues":["Hips square, don''t open to the side","Rear leg and torso move as one unit","Fix your gaze on a point for balance"],"mistakes":["Opening the hip on the free leg side","Rounding the back to reach lower","Losing balance by moving too fast"]}}'::jsonb, true),
    ('Peso muerto piernas rígidas', 'Stiff-Leg Deadlift', 9, 'weight_reps', 'barbell', '{"es":{"setup":"De pie con la barra, agarre prono al ancho de hombros. Piernas con mínima flexión de rodilla (casi rectas). Pies al ancho de caderas.","execution":"Inclina el torso hacia delante manteniendo las piernas prácticamente rectas y la barra cerca del cuerpo. Baja hasta donde la flexibilidad lo permita sin redondear la espalda. Sube contrayendo isquios y glúteos.","cues":["Piernas casi rectas durante todo el movimiento","Barra pegada al cuerpo","Baja solo hasta donde puedas mantener la espalda neutra"],"mistakes":["Flexionar las rodillas convirtiéndolo en peso muerto rumano","Redondear la espalda para bajar más","Hiperextender arriba"]},"en":{"setup":"Stand holding the bar, pronated grip at shoulder width. Legs with minimal knee bend (almost straight). Feet hip-width.","execution":"Hinge forward keeping legs nearly straight and the bar close to the body. Lower as far as flexibility allows without rounding the back. Drive up by contracting hamstrings and glutes.","cues":["Legs almost straight throughout","Bar close to the body","Only go as low as you can maintain a neutral spine"],"mistakes":["Bending knees too much, turning it into an RDL","Rounding the back to go lower","Hyperextending at the top"]}}'::jsonb, true),
    ('Buenos días con barra', 'Barbell Good Morning', 9, 'weight_reps', 'barbell', '{"es":{"setup":"Barra sobre los trapecios como en una sentadilla. Pies al ancho de hombros, rodillas ligeramente flexionadas.","execution":"Inclina el torso hacia delante empujando la cadera atrás, manteniendo la espalda neutra. Baja hasta que el torso esté casi paralelo al suelo. Sube contrayendo isquiotibiales y glúteos.","cues":["Cadera atrás, como si hicieras una reverencia","Espalda neutra siempre","El movimiento viene de la cadera, no de la espalda"],"mistakes":["Redondear la espalda al bajar","Flexionar demasiado las rodillas","Usar demasiado peso antes de dominar el patrón de movimiento"]},"en":{"setup":"Bar on your upper traps as in a squat. Feet shoulder-width, knees slightly bent.","execution":"Hinge forward by pushing hips back, keeping a neutral spine. Lower until your torso is nearly parallel to the floor. Rise by contracting hamstrings and glutes.","cues":["Hips back, like taking a bow","Neutral spine always","Movement comes from the hips, not the back"],"mistakes":["Rounding the back on the descent","Bending knees too much","Using too much weight before mastering the movement pattern"]}}'::jsonb, true),
    ('Buenos días sentado con barra', 'Seated Barbell Good Morning', 9, 'weight_reps', 'barbell', '{"es":{"setup":"Sentado en un banco con la barra sobre los trapecios. Pies firmes en el suelo, más abiertos que los hombros para que el torso baje entre las piernas.","execution":"Inclina el torso hacia delante entre las piernas manteniendo la espalda neutra. Baja hasta sentir el estiramiento y sube contrayendo los erectores espinales e isquiotibiales.","cues":["Torso entre las piernas, no sobre ellas","Espalda neutra, pecho fuera","Movimiento controlado, sin impulso"],"mistakes":["Redondear la espalda excesivamente","No bajar lo suficiente para activar los isquiotibiales","Usar impulso para subir"]},"en":{"setup":"Sit on a bench with the bar on your upper traps. Feet firm on the floor, wider than shoulders so the torso can lower between the legs.","execution":"Hinge the torso forward between the legs while keeping a neutral spine. Lower until you feel the stretch, then rise by contracting the spinal erectors and hamstrings.","cues":["Torso between the legs, not over them","Neutral spine, chest out","Controlled movement, no momentum"],"mistakes":["Excessive rounding of the back","Not going low enough to engage the hamstrings","Using momentum to come up"]}}'::jsonb, true),
    ('Curl nórdico', 'Nordic Curl', 9, 'reps_only', 'bodyweight', '{"es":{"setup":"De rodillas con los tobillos fijados (por un compañero o una barra baja). Cuerpo recto desde las rodillas hasta la cabeza.","execution":"Desciende lentamente hacia el suelo manteniendo la cadera extendida, resistiendo la caída con los isquiotibiales. Baja lo más lento posible y usa las manos para amortiguar al final si es necesario. Sube con ayuda de las manos o contrayendo los isquios.","cues":["Cadera extendida, no te sientes hacia atrás","Resiste la bajada lo más que puedas","Cuerpo recto como una tabla"],"mistakes":["Romper en la cadera al bajar","Dejarse caer sin resistir la excéntrica","Intentar la concéntrica completa sin tener fuerza suficiente"]},"en":{"setup":"Kneel with your ankles secured (by a partner or a low bar). Body straight from knees to head.","execution":"Lower yourself slowly toward the floor keeping hips extended, resisting the fall with your hamstrings. Go as slow as possible and use your hands to catch yourself if needed. Push up with hands or contract the hamstrings to return.","cues":["Hips extended, don''t sit back","Resist the descent as long as possible","Body straight like a plank"],"mistakes":["Breaking at the hips on the way down","Falling without resisting the eccentric","Attempting the full concentric without sufficient strength"]}}'::jsonb, true),
    ('Curl nórdico asistido', 'Assisted Nordic Curl', 9, 'reps_only', 'bodyweight', '{"es":{"setup":"Misma posición que el curl nórdico pero con una banda elástica enganchada a un punto alto y sujeta al pecho, o con las manos apoyadas en un cajón para asistir.","execution":"Desciende controladamente con la banda o el apoyo reduciendo la carga. Resiste la bajada activamente. La asistencia te ayuda a completar la fase concéntrica.","cues":["Usa la asistencia mínima necesaria","Sigue manteniendo la cadera extendida","Intenta depender menos de la ayuda con el tiempo"],"mistakes":["Depender demasiado de la asistencia sin esforzar los isquios","Romper en la cadera como en el curl nórdico regular","No progresar reduciendo la asistencia"]},"en":{"setup":"Same position as the Nordic curl but with a resistance band attached to a high point and held at the chest, or hands on a box for assistance.","execution":"Descend with control while the band or support reduces the load. Actively resist the descent. The assistance helps you complete the concentric phase.","cues":["Use the minimum assistance needed","Keep hips extended","Try to rely less on the aid over time"],"mistakes":["Relying too much on assistance without engaging the hamstrings","Breaking at the hips as in the regular Nordic curl","Not progressing by reducing assistance"]}}'::jsonb, true),
    ('Hiperextensión inversa', 'Reverse Hyperextension', 9, 'weight_reps', 'bodyweight', '{"es":{"setup":"Túmbate boca abajo en la máquina de hiperextensión inversa con la cadera en el borde. Agárrate a las asas, piernas colgando.","execution":"Eleva las piernas hacia atrás y arriba contrayendo glúteos, isquiotibiales y espalda baja. Sube hasta que las piernas estén alineadas con el torso o ligeramente por encima. Baja controladamente.","cues":["Contrae glúteos e isquios para subir las piernas","No uses impulso","Movimiento desde la cadera, no la lumbar"],"mistakes":["Usar impulso balanceando las piernas","Hiperextender la zona lumbar excesivamente","No controlar la fase de bajada"]},"en":{"setup":"Lie face down on the reverse hyper machine with hips at the edge. Grip the handles, legs hanging.","execution":"Raise your legs back and up by contracting glutes, hamstrings, and lower back. Lift until legs are aligned with the torso or slightly above. Lower with control.","cues":["Contract glutes and hamstrings to lift the legs","Don''t use momentum","Movement from the hips, not the lower back"],"mistakes":["Using momentum by swinging the legs","Excessive lumbar hyperextension","Not controlling the lowering phase"]}}'::jsonb, true),
    ('Curl femoral con pelota suiza', 'Swiss Ball Leg Curl', 9, 'reps_only', 'swiss_ball', '{"es":{"setup":"Tumbado boca arriba, talones sobre una pelota suiza, brazos a los lados en el suelo. Eleva la cadera formando una línea recta.","execution":"Flexiona las rodillas rodando la pelota hacia los glúteos mientras mantienes la cadera elevada. Extiende las piernas de vuelta con control sin dejar caer la cadera.","cues":["Cadera elevada durante todo el movimiento","Rueda la pelota con los talones, no con las puntas","Core activado para estabilizar"],"mistakes":["Dejar caer la cadera entre repeticiones","No mantener la estabilidad sobre la pelota","Hacer el movimiento demasiado rápido"]},"en":{"setup":"Lie on your back, heels on a Swiss ball, arms at your sides on the floor. Raise hips to form a straight line.","execution":"Bend your knees, rolling the ball toward your glutes while keeping hips elevated. Extend legs back with control without dropping the hips.","cues":["Hips elevated throughout","Roll the ball with heels, not toes","Core engaged for stability"],"mistakes":["Dropping the hips between reps","Losing stability on the ball","Moving too fast"]}}'::jsonb, true),
    ('Curl femoral deslizante', 'Sliding Leg Curl', 9, 'reps_only', 'bodyweight', '{"es":{"setup":"Tumbado boca arriba, talones sobre discos deslizantes (o toallas en suelo liso). Brazos a los lados, cadera elevada.","execution":"Desliza los talones hacia los glúteos flexionando las rodillas mientras mantienes la cadera arriba. Extiende las piernas deslizando de vuelta con control.","cues":["Cadera alta durante todo el movimiento","Presiona los talones contra el suelo al deslizar","Contrae glúteos e isquios activamente"],"mistakes":["Cadera cayendo al extender las piernas","No presionar los talones suficiente contra el suelo","Perder el control en la fase excéntrica"]},"en":{"setup":"Lie on your back, heels on sliders (or towels on a smooth floor). Arms at sides, hips elevated.","execution":"Slide your heels toward your glutes by bending the knees while keeping hips up. Extend legs by sliding back with control.","cues":["Hips high throughout","Press heels into the floor while sliding","Actively contract glutes and hamstrings"],"mistakes":["Hips dropping when extending the legs","Not pressing heels enough into the floor","Losing control on the eccentric phase"]}}'::jsonb, true),
    ('Curl femoral en polea', 'Cable Leg Curl', 9, 'weight_reps', 'cable', '{"es":{"setup":"De pie frente a una polea baja, engancha la tobillera al cable. Sujétate a la máquina para mantener el equilibrio.","execution":"Flexiona la rodilla llevando el talón hacia el glúteo contra la resistencia del cable. Contrae el isquiotibial arriba y baja controladamente. Haz todas las reps de un lado antes de cambiar.","cues":["Muslo fijo y vertical","Contracción completa arriba","Resiste la bajada, no dejes que el cable tire"],"mistakes":["Mover la cadera o el muslo para ayudar","Soltar el peso de golpe en la bajada","Inclinarse hacia delante"]},"en":{"setup":"Stand facing a low cable, ankle strap attached. Hold the machine for balance.","execution":"Curl the heel toward the glute against cable resistance. Contract the hamstring at the top and lower with control. Complete all reps on one side before switching.","cues":["Thigh fixed and vertical","Full contraction at the top","Resist the descent, don''t let the cable pull"],"mistakes":["Moving the hip or thigh to assist","Letting the weight drop on the way down","Leaning forward"]}}'::jsonb, true),
    ('Glute ham raise', 'Glute-Ham Raise', 9, 'reps_only', 'bodyweight', '{"es":{"setup":"Colócate en la máquina GHD con las rodillas en la almohadilla y los pies enganchados. Empieza con el torso vertical.","execution":"Desciende controladamente extendiendo las rodillas mientras mantienes la cadera neutra. Baja hasta quedar casi paralelo al suelo. Sube contrayendo los isquiotibiales para flexionar las rodillas y volver a la posición vertical.","cues":["La cadera no se flexiona, el movimiento es de rodilla","Resiste la excéntrica, no te dejes caer","Contrae los isquios fuerte para subir"],"mistakes":["Flexionar la cadera en vez de mantenerla neutra","Dejarse caer sin control en la excéntrica","No tener fuerza suficiente y caer sin resistencia"]},"en":{"setup":"Set up on the GHD machine with knees on the pad and feet hooked in. Start with torso vertical.","execution":"Lower with control by extending the knees while keeping hips neutral. Descend until nearly parallel to the floor. Rise by contracting the hamstrings to flex the knees back to vertical.","cues":["Hips don''t flex, the movement is at the knees","Resist the eccentric, don''t fall","Squeeze the hamstrings hard to ascend"],"mistakes":["Flexing the hips instead of keeping them neutral","Falling without control on the eccentric","Insufficient strength causing an uncontrolled descent"]}}'::jsonb, true),
    ('Hip thrust con barra', 'Barbell Hip Thrust', 10, 'weight_reps', 'barbell', '{"es":{"setup":"Apoya la parte media-alta de la espalda en un banco y coloca la barra sobre el pliegue de la cadera con un pad. Pies a la anchura de los hombros, rodillas a 90° en la posición final.","execution":"Empuja la cadera hacia arriba apretando los glúteos hasta que el torso quede paralelo al suelo. Mantén la barbilla al pecho para evitar hiperextender la lumbar. Baja controladamente hasta que los glúteos casi toquen el suelo.","cues":["Aprieta glúteos arriba con fuerza","Barbilla al pecho todo el movimiento","Rodillas a 90° en la posición final"],"mistakes":["Hiperextender la zona lumbar arriba","Colocar los pies demasiado lejos o demasiado cerca","Empujar con los cuádriceps en vez de los glúteos"]},"en":{"setup":"Rest your upper back on a bench and place the barbell across your hip crease with a pad. Feet shoulder-width apart, knees at 90° at the top.","execution":"Drive your hips upward by squeezing your glutes until your torso is parallel to the floor. Keep your chin tucked to avoid hyperextending your lower back. Lower under control until your glutes nearly touch the ground.","cues":["Hard glute squeeze at the top","Keep chin tucked throughout","Knees at 90° at lockout"],"mistakes":["Hyperextending the lower back at the top","Placing feet too far or too close to the bench","Pushing through quads instead of glutes"]}}'::jsonb, true),
    ('Hip thrust con mancuerna', 'Dumbbell Hip Thrust', 10, 'weight_reps', 'dumbbell', '{"es":{"setup":"Apoya la espalda alta en un banco y sujeta una mancuerna sobre el pliegue de la cadera con ambas manos. Pies a la anchura de los hombros.","execution":"Empuja la cadera hacia arriba contrayendo los glúteos hasta alinear torso y muslos. Haz una pausa breve arriba y baja controladamente. Sujeta la mancuerna firme durante todo el movimiento.","cues":["Presiona talones contra el suelo","Aprieta glúteos 1-2 segundos arriba","Barbilla recogida"],"mistakes":["Dejar que la mancuerna se deslice durante el movimiento","Arquear excesivamente la zona lumbar","Subir demasiado rápido sin control"]},"en":{"setup":"Rest your upper back on a bench and hold a dumbbell on your hip crease with both hands. Feet shoulder-width apart.","execution":"Drive hips up by squeezing your glutes until your torso and thighs align. Pause briefly at the top and lower under control. Keep the dumbbell secure throughout.","cues":["Press heels into the floor","Squeeze glutes 1-2 seconds at top","Chin tucked"],"mistakes":["Letting the dumbbell slide during the movement","Excessive lower back arch","Rising too fast without control"]}}'::jsonb, true),
    ('Hip thrust en máquina', 'Machine Hip Thrust', 10, 'weight_reps', 'machine', '{"es":{"setup":"Ajusta el respaldo y la almohadilla de la cadera de la máquina. Siéntate con la espalda apoyada y los pies firmes en la plataforma, rodillas a 90° arriba.","execution":"Empuja la cadera hacia arriba contra la almohadilla hasta extensión completa. Contrae los glúteos arriba y baja controladamente sin relajar la tensión abajo.","cues":["Empuja a través de los talones","Contracción máxima arriba","No dejes que el peso descanse abajo"],"mistakes":["Empujar con la zona lumbar en lugar de los glúteos","No llegar a extensión completa de cadera","Relajar la tensión entre repeticiones"]},"en":{"setup":"Adjust the back pad and hip pad of the machine. Sit with your back supported and feet firmly on the platform, knees at 90° at the top.","execution":"Drive your hips up against the pad to full extension. Squeeze glutes hard at the top and lower under control without letting the weight rest at the bottom.","cues":["Push through your heels","Maximum contraction at the top","Don''t let the weight rest at the bottom"],"mistakes":["Pushing with the lower back instead of glutes","Not reaching full hip extension","Releasing tension between reps"]}}'::jsonb, true),
    ('Hip thrust unilateral', 'Single-Leg Hip Thrust', 10, 'weight_reps', 'bodyweight', '{"es":{"setup":"Apoya la espalda alta en un banco con un pie en el suelo y la otra pierna elevada (rodilla al pecho o extendida). Puedes añadir peso sobre la cadera del lado de trabajo.","execution":"Empuja la cadera hacia arriba con una sola pierna hasta alinear el torso. Mantén la pelvis nivelada sin rotar hacia ningún lado. Baja controladamente.","cues":["Pelvis nivelada, sin rotación","Contrae glúteo y core al subir","Controla el descenso"],"mistakes":["Rotar la cadera hacia el lado de la pierna elevada","Compensar empujando con la zona lumbar","Perder el equilibrio por falta de tensión en el core"]},"en":{"setup":"Rest your upper back on a bench with one foot on the floor and the other leg raised (knee to chest or extended). You may add weight on the working hip.","execution":"Drive your hips up on one leg until your torso is aligned. Keep your pelvis level without rotating to either side. Lower under control.","cues":["Level pelvis, no rotation","Engage glute and core on the way up","Control the descent"],"mistakes":["Rotating the hip toward the raised leg side","Compensating by pushing with the lower back","Losing balance due to lack of core tension"]}}'::jsonb, true),
    ('Puente de glúteos', 'Glute Bridge', 10, 'reps_only', 'bodyweight', '{"es":{"setup":"Túmbate boca arriba con las rodillas flexionadas, pies apoyados en el suelo a la anchura de la cadera. Brazos a los lados con las palmas hacia abajo.","execution":"Empuja los talones contra el suelo y eleva la cadera contrayendo los glúteos hasta formar una línea recta de hombros a rodillas. Mantén arriba 1-2 segundos y baja controladamente.","cues":["Empuja con los talones","Aprieta glúteos arriba","No arquees la zona lumbar"],"mistakes":["Hiperextender la lumbar en la parte alta","Elevar la cadera empujando con isquiotibiales","Colocar los pies demasiado lejos del cuerpo"]},"en":{"setup":"Lie face up with knees bent, feet flat on the floor at hip width. Arms at your sides, palms down.","execution":"Press heels into the floor and lift your hips by squeezing your glutes until you form a straight line from shoulders to knees. Hold 1-2 seconds at the top and lower under control.","cues":["Drive through heels","Squeeze glutes at the top","Don''t arch the lower back"],"mistakes":["Hyperextending the lower back at the top","Lifting hips by pushing with hamstrings","Placing feet too far from the body"]}}'::jsonb, true),
    ('Puente de glúteos con barra', 'Barbell Glute Bridge', 10, 'weight_reps', 'barbell', '{"es":{"setup":"Túmbate boca arriba con la barra sobre el pliegue de la cadera (usa pad). Rodillas flexionadas, pies a la anchura de la cadera. Sujeta la barra con ambas manos.","execution":"Empuja la cadera hacia arriba apretando los glúteos hasta extensión completa. Mantén 1-2 segundos arriba y baja de forma controlada sin dejar que la barra rebote en el suelo.","cues":["Talones clavados en el suelo","Bloquea glúteos arriba","Baja sin soltar tensión"],"mistakes":["Rebotar la barra en el suelo entre reps","Hiperextender la espalda baja","Mover los pies durante la serie"]},"en":{"setup":"Lie face up with the barbell over your hip crease (use a pad). Knees bent, feet hip-width apart. Hold the bar with both hands.","execution":"Drive hips up by squeezing glutes to full extension. Hold 1-2 seconds at the top and lower under control without bouncing the bar off the floor.","cues":["Heels firmly on the floor","Lock out glutes at the top","Lower without releasing tension"],"mistakes":["Bouncing the bar off the floor between reps","Hyperextending the lower back","Shifting feet during the set"]}}'::jsonb, true),
    ('Puente de glúteos unilateral', 'Single-Leg Glute Bridge', 10, 'reps_only', 'bodyweight', '{"es":{"setup":"Túmbate boca arriba con una rodilla flexionada y el pie apoyado. Eleva la otra pierna con la rodilla al pecho o extendida hacia el techo.","execution":"Empuja el talón de la pierna de apoyo contra el suelo y eleva la cadera contrayendo el glúteo. Mantén la pelvis nivelada sin rotar. Baja controladamente.","cues":["Pelvis estable y nivelada","Toda la fuerza desde el glúteo de apoyo","Core activado"],"mistakes":["Rotar la cadera hacia un lado","Usar impulso en lugar de control","No mantener la pierna elevada estable"]},"en":{"setup":"Lie face up with one knee bent and foot flat. Raise the other leg with knee to chest or extended toward the ceiling.","execution":"Press the support foot''s heel into the floor and raise your hips by squeezing the working glute. Keep your pelvis level without rotating. Lower under control.","cues":["Stable and level pelvis","All force from the working glute","Core engaged"],"mistakes":["Rotating the hip to one side","Using momentum instead of control","Not keeping the raised leg stable"]}}'::jsonb, true),
    ('Patada de glúteo en polea', 'Cable Glute Kickback', 10, 'weight_reps', 'cable', '{"es":{"setup":"Coloca una tobillera en la polea baja y engánchala al tobillo. De pie frente a la máquina, agárrate a la estructura para mantener el equilibrio. Inclina ligeramente el torso hacia delante.","execution":"Extiende la pierna de trabajo hacia atrás manteniendo la rodilla ligeramente flexionada. Aprieta el glúteo en la extensión máxima y vuelve controladamente sin dejar que el peso tire de la pierna.","cues":["Movimiento desde la cadera, no la espalda","Aprieta el glúteo al final","Mantén el core firme"],"mistakes":["Arquear la espalda baja para subir más la pierna","Usar impulso en lugar de contracción del glúteo","Balancear todo el cuerpo"]},"en":{"setup":"Attach an ankle strap to the low pulley and hook it to your ankle. Stand facing the machine, hold the frame for balance. Lean your torso slightly forward.","execution":"Extend the working leg back keeping a slight knee bend. Squeeze the glute at full extension and return under control without letting the weight pull your leg.","cues":["Movement from the hip, not the back","Squeeze the glute at the end","Keep core tight"],"mistakes":["Arching the lower back to raise the leg higher","Using momentum instead of glute contraction","Swinging the entire body"]}}'::jsonb, true),
    ('Patada de glúteo en máquina', 'Machine Glute Kickback', 10, 'weight_reps', 'machine', '{"es":{"setup":"Ajusta la máquina y coloca el pie en la plataforma. Apóyate en los agarres con el pecho contra el soporte y la espalda en posición neutra.","execution":"Empuja la plataforma hacia atrás y arriba extendiendo la cadera. Contrae el glúteo al máximo arriba y vuelve controladamente sin soltar la tensión.","cues":["Empuja con el talón","Contracción consciente del glúteo arriba","Sin arquear la espalda"],"mistakes":["Hiperextender la zona lumbar","Usar impulso para mover el peso","No completar el rango de movimiento"]},"en":{"setup":"Adjust the machine and place your foot on the platform. Hold the handles with your chest against the pad, back in neutral position.","execution":"Push the platform back and up by extending the hip. Squeeze the glute hard at the top and return under control without releasing tension.","cues":["Push through the heel","Conscious glute contraction at top","No back arching"],"mistakes":["Hyperextending the lower back","Using momentum to move the weight","Not completing full range of motion"]}}'::jsonb, true),
    ('Abducción de cadera en máquina', 'Machine Hip Abduction', 10, 'weight_reps', 'machine', '{"es":{"setup":"Siéntate en la máquina con la espalda apoyada y las almohadillas en la parte externa de las rodillas o muslos. Pies en los apoyos.","execution":"Abre las piernas empujando contra las almohadillas hasta la máxima apertura. Mantén 1 segundo y cierra controladamente sin dejar que el peso golpee.","cues":["Empuja con la parte externa del muslo","Mantén la espalda contra el respaldo","Control en la fase de cierre"],"mistakes":["Inclinarse hacia delante para hacer trampa","Cerrar las piernas demasiado rápido","Usar un peso excesivo que impida el rango completo"]},"en":{"setup":"Sit on the machine with back supported and pads against the outer knees or thighs. Feet on the foot rests.","execution":"Open your legs by pushing against the pads to maximum abduction. Hold 1 second and close under control without letting the weight slam.","cues":["Push with the outer thigh","Keep your back against the pad","Control the closing phase"],"mistakes":["Leaning forward to cheat","Closing legs too fast","Using excessive weight that limits full range"]}}'::jsonb, true),
    ('Abducción de cadera en polea', 'Cable Hip Abduction', 10, 'weight_reps', 'cable', '{"es":{"setup":"Coloca una tobillera en la polea baja y engánchala al tobillo de la pierna de trabajo. De pie de lado a la máquina, agárrate a la estructura.","execution":"Separa la pierna de trabajo hacia el exterior manteniendo el torso erguido. Lleva hasta la abducción máxima controlada y vuelve lentamente sin cruzar la pierna de apoyo.","cues":["Torso recto, sin inclinarte al lado opuesto","Movimiento controlado y lento","Contrae el glúteo medio al abrir"],"mistakes":["Inclinar el cuerpo para compensar el peso","Usar impulso para abrir la pierna","Rotar la cadera hacia fuera en lugar de abducir"]},"en":{"setup":"Attach an ankle strap to the low pulley and hook it to the working ankle. Stand sideways to the machine, hold the frame for balance.","execution":"Move the working leg outward keeping your torso upright. Reach maximum controlled abduction and return slowly without crossing past the support leg.","cues":["Torso straight, don''t lean to the opposite side","Slow and controlled movement","Engage the glute medius as you open"],"mistakes":["Leaning the body to compensate for the weight","Using momentum to open the leg","Externally rotating the hip instead of abducting"]}}'::jsonb, true),
    ('Abducción de cadera con banda', 'Banded Hip Abduction', 10, 'weight_reps', 'band', '{"es":{"setup":"Coloca una banda elástica por encima de las rodillas. Puedes hacerlo de pie, sentado o en posición de sentadilla parcial.","execution":"Separa las rodillas contra la resistencia de la banda, manteniendo los pies firmes. Contrae los glúteos al máximo en la apertura y vuelve controladamente.","cues":["Empuja las rodillas hacia fuera","Mantén tensión constante en la banda","Contracción al final de cada rep"],"mistakes":["Dejar que la banda cierre las rodillas sin control","Mover los pies en lugar de las rodillas","Perder la postura del torso"]},"en":{"setup":"Place a resistance band above your knees. You can perform this standing, seated, or in a partial squat position.","execution":"Push your knees apart against band resistance, keeping feet planted. Squeeze glutes at maximum opening and return under control.","cues":["Drive knees outward","Maintain constant band tension","Squeeze at the end of each rep"],"mistakes":["Letting the band snap knees closed uncontrolled","Moving feet instead of knees","Losing torso posture"]}}'::jsonb, true),
    ('Sentadilla sumo con mancuerna', 'Dumbbell Sumo Squat', 10, 'weight_reps', 'dumbbell', '{"es":{"setup":"De pie con los pies más abiertos que los hombros, puntas hacia fuera a 45°. Sujeta una mancuerna verticalmente entre las piernas con ambas manos.","execution":"Baja flexionando caderas y rodillas manteniendo la espalda recta y el pecho alto. Baja hasta que los muslos estén paralelos al suelo o más. Sube empujando con los talones y apretando los glúteos arriba.","cues":["Rodillas en la dirección de las puntas de los pies","Pecho alto y espalda neutra","Aprieta glúteos al subir"],"mistakes":["Dejar que las rodillas colapsen hacia dentro","Inclinarse demasiado hacia delante","No bajar lo suficiente"]},"en":{"setup":"Stand with feet wider than shoulders, toes pointed out at 45°. Hold a dumbbell vertically between your legs with both hands.","execution":"Lower by bending hips and knees while keeping your back straight and chest up. Descend until thighs are parallel or below. Push through heels and squeeze glutes at the top.","cues":["Knees track over toes","Chest up, neutral back","Squeeze glutes on the way up"],"mistakes":["Letting knees cave inward","Leaning too far forward","Not descending deep enough"]}}'::jsonb, true),
    ('Sentadilla sumo con barra', 'Barbell Sumo Squat', 10, 'weight_reps', 'barbell', '{"es":{"setup":"Coloca la barra en la espalda alta (posición de sentadilla). Pies más abiertos que los hombros con las puntas hacia fuera a 45°.","execution":"Baja controladamente manteniendo el torso lo más vertical posible. Las rodillas siguen la línea de los pies. Sube empujando desde los talones contrayendo glúteos y aductores.","cues":["Torso vertical","Rodillas hacia fuera siguiendo los pies","Empuja el suelo con los talones"],"mistakes":["Inclinarse excesivamente hacia delante","Rodillas colapsando hacia dentro","Subir con la espalda baja en lugar de las piernas"]},"en":{"setup":"Place the bar on your upper back (squat position). Feet wider than shoulders with toes pointed out at 45°.","execution":"Descend in a controlled manner keeping your torso as upright as possible. Knees track over your toes. Push up from the heels, engaging glutes and adductors.","cues":["Upright torso","Knees out following the feet","Push the floor away with heels"],"mistakes":["Excessive forward lean","Knees caving inward","Rising with the lower back instead of the legs"]}}'::jsonb, true),
    ('Aducción de cadera en máquina', 'Machine Hip Adduction', 10, 'weight_reps', 'machine', '{"es":{"setup":"Siéntate en la máquina con la espalda apoyada y las almohadillas en la parte interna de las rodillas o muslos. Comienza con las piernas abiertas.","execution":"Cierra las piernas apretando contra las almohadillas hasta que se junten. Mantén 1 segundo y abre controladamente sin dejar que el peso tire.","cues":["Aprieta los aductores al cerrar","Espalda pegada al respaldo","Fase excéntrica lenta y controlada"],"mistakes":["Inclinarse hacia delante","Abrir las piernas demasiado rápido (fase excéntrica descontrolada)","Usar impulso con el cuerpo"]},"en":{"setup":"Sit on the machine with back supported and pads against the inner knees or thighs. Start with legs open.","execution":"Squeeze legs together by pressing against the pads until they meet. Hold 1 second and open under control without letting the weight pull.","cues":["Squeeze adductors as you close","Back against the pad","Slow and controlled eccentric phase"],"mistakes":["Leaning forward","Opening legs too fast (uncontrolled eccentric)","Using body momentum"]}}'::jsonb, true),
    ('Aducción de cadera en polea', 'Cable Hip Adduction', 10, 'weight_reps', 'cable', '{"es":{"setup":"Coloca una tobillera en la polea baja y engánchala al tobillo de la pierna de trabajo. De pie de lado a la máquina, la pierna de trabajo es la más cercana a la polea.","execution":"Cruza la pierna de trabajo por delante de la pierna de apoyo apretando los aductores. Vuelve controladamente a la posición inicial sin perder el equilibrio.","cues":["Torso erguido y estable","Movimiento lento y controlado","Contrae los aductores al cruzar"],"mistakes":["Balancear el cuerpo para generar impulso","Rotar la cadera durante el cruce","No controlar la vuelta a la posición inicial"]},"en":{"setup":"Attach an ankle strap to the low pulley and hook it to the working ankle. Stand sideways to the machine; the working leg is closest to the pulley.","execution":"Cross the working leg in front of the support leg by squeezing the adductors. Return under control to the starting position without losing balance.","cues":["Upright and stable torso","Slow and controlled movement","Squeeze adductors as you cross"],"mistakes":["Swinging the body to generate momentum","Rotating the hip during the crossover","Not controlling the return to start position"]}}'::jsonb, true),
    ('Clamshell con banda', 'Banded Clamshell', 10, 'weight_reps', 'band', '{"es":{"setup":"Túmbate de lado con una banda elástica por encima de las rodillas. Rodillas flexionadas a 90°, pies juntos y caderas apiladas.","execution":"Abre la rodilla superior como una almeja, manteniendo los pies juntos y las caderas fijas. Contrae el glúteo arriba y cierra controladamente.","cues":["Caderas apiladas, no rotar hacia atrás","Pies siempre en contacto","Contracción consciente del glúteo medio"],"mistakes":["Rotar la cadera hacia atrás para abrir más","Separar los pies en lugar de las rodillas","Movimiento demasiado rápido sin contracción"]},"en":{"setup":"Lie on your side with a band above your knees. Knees bent at 90°, feet together and hips stacked.","execution":"Open the top knee like a clamshell, keeping feet together and hips stacked. Squeeze the glute at the top and close under control.","cues":["Hips stacked, don''t roll backward","Feet always in contact","Conscious glute medius contraction"],"mistakes":["Rolling the hip backward to open more","Separating feet instead of knees","Moving too fast without contracting"]}}'::jsonb, true),
    ('Elevación lateral de cadera', 'Side-Lying Hip Raise', 10, 'reps_only', 'bodyweight', '{"es":{"setup":"Túmbate de lado con las piernas extendidas y apiladas. Apoya la cabeza en el brazo inferior y coloca la mano superior delante del cuerpo para estabilizarte.","execution":"Eleva la pierna superior manteniéndola recta, sin rotar la cadera. Sube hasta unos 45° y baja controladamente sin apoyar la pierna entre reps.","cues":["Pierna recta sin flexionar rodilla","Cadera estable, no rotar","Movimiento desde el glúteo medio"],"mistakes":["Rotar la cadera hacia atrás para elevar más","Flexionar la rodilla de la pierna de trabajo","Balancear la pierna con impulso"]},"en":{"setup":"Lie on your side with legs extended and stacked. Rest your head on the lower arm and place the top hand in front for stability.","execution":"Raise the top leg keeping it straight, without rotating the hip. Lift to about 45° and lower under control without resting the leg between reps.","cues":["Straight leg, no knee bending","Stable hip, no rotation","Movement from the glute medius"],"mistakes":["Rolling the hip backward to lift higher","Bending the knee of the working leg","Swinging the leg with momentum"]}}'::jsonb, true),
    ('Frog pump', 'Frog Pump', 10, 'reps_only', 'bodyweight', '{"es":{"setup":"Túmbate boca arriba con las plantas de los pies juntas y las rodillas abiertas (posición de mariposa). Los talones deben estar cerca de los glúteos.","execution":"Empuja la cadera hacia arriba apretando los glúteos con fuerza. Mantén las plantas de los pies juntas durante todo el movimiento. Baja controladamente y repite con ritmo constante.","cues":["Aprieta glúteos con fuerza arriba","Plantas de los pies siempre juntas","Movimiento corto y controlado"],"mistakes":["Separar los pies durante el movimiento","Empujar con la zona lumbar","No contraer los glúteos arriba"]},"en":{"setup":"Lie face up with the soles of your feet together and knees open (butterfly position). Heels should be close to your glutes.","execution":"Drive your hips up by squeezing your glutes hard. Keep the soles of your feet together throughout. Lower under control and repeat at a steady pace.","cues":["Hard glute squeeze at the top","Soles of feet always together","Short and controlled movement"],"mistakes":["Separating feet during the movement","Pushing with the lower back","Not contracting glutes at the top"]}}'::jsonb, true),
    ('Elevación de talones de pie en máquina', 'Standing Machine Calf Raise', 11, 'weight_reps', 'machine', '{"es":{"setup":"Colócate bajo las almohadillas de la máquina con las puntas de los pies en el borde de la plataforma. Los talones quedan en el aire. Piernas casi extendidas.","execution":"Sube elevando los talones lo más alto posible contrayendo las pantorrillas. Mantén arriba 1 segundo y baja estirando bien al final, dejando que los talones desciendan por debajo de la plataforma.","cues":["Sube hasta ponerte de puntillas completamente","Estira bien abajo para rango completo","Mantén las rodillas casi bloqueadas"],"mistakes":["No usar rango completo (subir o bajar poco)","Flexionar las rodillas para hacer trampa","Rebotar abajo sin control"]},"en":{"setup":"Stand under the shoulder pads with the balls of your feet on the platform edge. Heels hang off. Legs nearly straight.","execution":"Rise by lifting heels as high as possible, contracting the calves. Hold 1 second at the top and lower fully, letting heels drop below the platform for a full stretch.","cues":["Rise to full tiptoe","Full stretch at the bottom","Keep knees nearly locked"],"mistakes":["Not using full range of motion","Bending knees to cheat","Bouncing at the bottom without control"]}}'::jsonb, true),
    ('Elevación de talones sentado en máquina', 'Seated Machine Calf Raise', 11, 'weight_reps', 'machine', '{"es":{"setup":"Siéntate con las almohadillas sobre los muslos (cerca de las rodillas) y las puntas de los pies en el borde de la plataforma. Rodillas a 90°.","execution":"Eleva los talones lo más alto posible contrayendo los sóleos. Mantén 1 segundo arriba y baja estirando completamente por debajo de la plataforma.","cues":["Contracción máxima arriba","Estiramiento completo abajo","Movimiento desde el tobillo, no la rodilla"],"mistakes":["Rebotar abajo para usar impulso","Reducir el rango de movimiento con peso excesivo","Mover las rodillas arriba y abajo"]},"en":{"setup":"Sit with the pads over your thighs (near the knees) and balls of your feet on the platform edge. Knees at 90°.","execution":"Raise your heels as high as possible by contracting the soleus. Hold 1 second at the top and lower fully, stretching below the platform.","cues":["Maximum contraction at top","Full stretch at bottom","Movement from the ankle, not the knee"],"mistakes":["Bouncing at the bottom for momentum","Reducing range of motion with excessive weight","Moving knees up and down"]}}'::jsonb, true),
    ('Elevación de talones en prensa de piernas', 'Leg Press Calf Raise', 11, 'weight_reps', 'machine', '{"es":{"setup":"Siéntate en la prensa de piernas y coloca solo las puntas de los pies en la parte baja de la plataforma. Piernas casi extendidas, desbloquea los seguros.","execution":"Empuja la plataforma extendiendo los tobillos (poniéndote de puntillas). Mantén 1 segundo y baja flexionando los tobillos para un estiramiento completo.","cues":["Solo mover los tobillos","Rodillas fijas, casi extendidas","Rango completo en cada rep"],"mistakes":["Flexionar las rodillas durante el movimiento","Colocar demasiado pie en la plataforma","No desbloquear los seguros correctamente"]},"en":{"setup":"Sit in the leg press and place only the balls of your feet on the lower part of the platform. Legs nearly extended, release the safety catches.","execution":"Push the platform by extending your ankles (rising onto tiptoes). Hold 1 second and lower by dorsiflexing ankles for a full stretch.","cues":["Only move at the ankles","Knees fixed, nearly extended","Full range on every rep"],"mistakes":["Bending knees during the movement","Placing too much foot on the platform","Not properly releasing the safety catches"]}}'::jsonb, true),
    ('Elevación de talones de pie con mancuerna', 'Dumbbell Standing Calf Raise', 11, 'weight_reps', 'dumbbell', '{"es":{"setup":"De pie sobre un escalón o disco con las puntas de los pies en el borde. Sujeta una mancuerna en una mano y agárrate a algo para equilibrarte.","execution":"Eleva los talones lo más alto posible contrayendo las pantorrillas. Mantén arriba 1 segundo y baja dejando que los talones desciendan por debajo del borde para estirar bien.","cues":["Sube hasta la punta de los pies","Estira completamente abajo","Movimiento lento y controlado"],"mistakes":["Usar impulso y rebotar","No aprovechar el rango completo del escalón","Inclinarse demasiado hacia delante"]},"en":{"setup":"Stand on a step or plate with the balls of your feet on the edge. Hold a dumbbell in one hand and hold something for balance.","execution":"Raise heels as high as possible, contracting calves. Hold 1 second at the top and lower, letting heels drop below the edge for a full stretch.","cues":["Rise to full tiptoe","Full stretch at the bottom","Slow and controlled movement"],"mistakes":["Using momentum and bouncing","Not using the full range from the step","Leaning too far forward"]}}'::jsonb, true),
    ('Elevación de talones de pie con barra', 'Barbell Standing Calf Raise', 11, 'weight_reps', 'barbell', '{"es":{"setup":"Coloca la barra en la espalda alta como en una sentadilla. Puntas de los pies en el borde de un escalón o disco, talones en el aire.","execution":"Eleva los talones subiendo de puntillas lo más alto posible. Mantén 1 segundo y baja controladamente estirando las pantorrillas por debajo del borde.","cues":["Core activado para estabilizar la barra","Rodillas casi bloqueadas","Rango completo arriba y abajo"],"mistakes":["Flexionar las rodillas para compensar","Perder el equilibrio por falta de core","Rebotar abajo sin pausa"]},"en":{"setup":"Place the bar on your upper back as in a squat. Balls of your feet on the edge of a step or plate, heels hanging off.","execution":"Raise heels by rising onto tiptoes as high as possible. Hold 1 second and lower under control, stretching calves below the edge.","cues":["Core engaged to stabilize the bar","Knees nearly locked","Full range up and down"],"mistakes":["Bending knees to compensate","Losing balance due to weak core","Bouncing at the bottom without pause"]}}'::jsonb, true),
    ('Elevación de talones en máquina Smith', 'Smith Machine Calf Raise', 11, 'weight_reps', 'smith_machine', '{"es":{"setup":"Coloca la barra de la Smith en los hombros. Puntas de los pies en el borde de un escalón o disco debajo de la barra, talones en el aire.","execution":"Eleva los talones contrayendo las pantorrillas al máximo. La guía de la Smith te da estabilidad para concentrarte en la contracción. Baja estirando bien.","cues":["Aprovecha la estabilidad de la Smith para enfocarte en el músculo","Estiramiento completo abajo","Contracción máxima arriba"],"mistakes":["No bajar lo suficiente por debajo del escalón","Ir demasiado rápido sin contracción","Bloquear las rodillas con tensión excesiva"]},"en":{"setup":"Place the Smith bar on your shoulders. Balls of your feet on a step or plate edge beneath the bar, heels hanging off.","execution":"Raise heels by fully contracting your calves. The Smith guide rail provides stability so you can focus on the contraction. Lower with a full stretch.","cues":["Use the Smith''s stability to focus on the muscle","Full stretch at the bottom","Maximum contraction at the top"],"mistakes":["Not lowering enough below the step","Going too fast without contraction","Locking knees with excessive tension"]}}'::jsonb, true),
    ('Elevación de talones a una pierna', 'Single-Leg Calf Raise', 11, 'weight_reps', 'dumbbell', '{"es":{"setup":"De pie sobre un escalón con la punta de un pie en el borde. La otra pierna queda en el aire. Agárrate a algo para equilibrarte. Puedes sujetar una mancuerna.","execution":"Eleva el talón lo más alto posible contrayendo la pantorrilla. Mantén 1 segundo y baja lentamente dejando que el talón descienda por debajo del borde.","cues":["Contracción máxima arriba","Estiramiento profundo abajo","Sin impulso ni rebote"],"mistakes":["Apoyarse demasiado en la mano de equilibrio","Rebotar abajo","No completar el rango de movimiento"]},"en":{"setup":"Stand on a step with the ball of one foot on the edge. The other leg hangs free. Hold something for balance. You may hold a dumbbell.","execution":"Raise the heel as high as possible, contracting the calf. Hold 1 second and lower slowly, letting the heel drop below the edge.","cues":["Maximum contraction at top","Deep stretch at bottom","No momentum or bouncing"],"mistakes":["Relying too much on the balance hand","Bouncing at the bottom","Not completing full range of motion"]}}'::jsonb, true),
    ('Elevación de talones tipo burro', 'Donkey Calf Raise', 11, 'weight_reps', 'machine', '{"es":{"setup":"Inclínate hacia delante apoyando los antebrazos en un soporte alto (máquina, banco alto). Puntas de los pies en el borde de un escalón, talones en el aire. La cadera queda flexionada a 90°.","execution":"Eleva los talones contrayendo las pantorrillas al máximo. La posición inclinada estira más los gemelos en la fase baja. Baja controladamente estirando completamente.","cues":["Cadera flexionada a 90°, espalda recta","Estiramiento profundo abajo por la posición","Contracción fuerte arriba"],"mistakes":["Redondear la espalda","No aprovechar el estiramiento extra de la posición","Usar impulso con la cadera"]},"en":{"setup":"Lean forward resting your forearms on a high support (machine, high bench). Balls of your feet on a step edge, heels hanging. Hips bent at 90°.","execution":"Raise heels by fully contracting your calves. The bent-over position increases the stretch at the bottom. Lower under control for a full stretch.","cues":["Hips at 90°, back straight","Deep stretch at bottom from the position","Strong contraction at top"],"mistakes":["Rounding the back","Not taking advantage of the extra stretch from the position","Using hip momentum"]}}'::jsonb, true),
    ('Saltos de pantorrilla', 'Calf Jumps', 11, 'reps_only', 'bodyweight', '{"es":{"setup":"De pie con los pies a la anchura de la cadera, rodillas casi extendidas. Brazos a los lados o en la cintura.","execution":"Salta verticalmente usando solo la extensión de los tobillos, sin flexionar las rodillas. Aterriza en las puntas de los pies y rebota inmediatamente. Mantén un ritmo constante.","cues":["Solo mover los tobillos, rodillas fijas","Aterrizaje suave en las puntas","Ritmo constante y rápido"],"mistakes":["Flexionar las rodillas para saltar más alto","Aterrizar con los talones","Pausar demasiado entre saltos"]},"en":{"setup":"Stand with feet hip-width apart, knees nearly straight. Arms at your sides or on your hips.","execution":"Jump vertically using only ankle extension, without bending your knees. Land on the balls of your feet and bounce immediately. Keep a steady rhythm.","cues":["Only move at the ankles, knees fixed","Soft landing on the balls of the feet","Steady and quick rhythm"],"mistakes":["Bending knees to jump higher","Landing on the heels","Pausing too long between jumps"]}}'::jsonb, true),
    ('Elevación de talones en hack squat', 'Hack Squat Calf Raise', 11, 'weight_reps', 'machine', '{"es":{"setup":"Colócate en la máquina de hack squat con la espalda en el respaldo. Solo las puntas de los pies en la parte baja de la plataforma, piernas casi extendidas.","execution":"Empuja la plataforma extendiendo los tobillos al máximo. Mantén 1 segundo arriba y baja controladamente, dejando que los talones desciendan para un estiramiento completo.","cues":["Espalda pegada al respaldo","Solo mover los tobillos","Rango completo en cada rep"],"mistakes":["Flexionar las rodillas durante el movimiento","No usar rango completo","Colocar demasiado pie en la plataforma"]},"en":{"setup":"Position yourself in the hack squat with your back against the pad. Only the balls of your feet on the lower platform, legs nearly extended.","execution":"Push the platform by extending your ankles fully. Hold 1 second at the top and lower under control, letting heels drop for a full stretch.","cues":["Back against the pad","Only move at the ankles","Full range on every rep"],"mistakes":["Bending knees during the movement","Not using full range of motion","Placing too much foot on the platform"]}}'::jsonb, true),
    ('Tibialis raise', 'Tibialis Raise', 11, 'reps_only', 'bodyweight', '{"es":{"setup":"De pie con la espalda apoyada en una pared y los talones a unos 30 cm de la base. Puedes hacerlo también al borde de un escalón con los talones en el borde.","execution":"Levanta las puntas de los pies hacia las espinillas contrayendo el tibial anterior. Mantén 1-2 segundos arriba y baja controladamente.","cues":["Contrae el músculo de la espinilla","Movimiento lento y controlado","Mantén la contracción arriba"],"mistakes":["Ir demasiado rápido sin contracción","No levantar las puntas lo suficiente","Perder el equilibrio por no apoyarse"]},"en":{"setup":"Stand with your back against a wall, heels about 30 cm from the base. You can also do this on a step edge with heels on the edge.","execution":"Lift your toes toward your shins by contracting the tibialis anterior. Hold 1-2 seconds at the top and lower under control.","cues":["Contract the shin muscle","Slow and controlled movement","Hold the contraction at the top"],"mistakes":["Going too fast without contraction","Not lifting toes high enough","Losing balance from not bracing"]}}'::jsonb, true),
    ('Crunch en suelo', 'Floor Crunch', 1, 'reps_only', 'bodyweight', '{"es":{"setup":"Tumbado boca arriba con rodillas flexionadas y pies apoyados en el suelo. Manos detrás de las orejas sin entrelazar los dedos.","execution":"Eleva los hombros del suelo contrayendo el abdomen, acercando las costillas a la pelvis. Baja de forma controlada sin apoyar completamente la cabeza.","cues":["Exhala al subir, imagina aplastar una naranja entre las costillas y la cadera","No tires del cuello con las manos","Mantén la zona lumbar pegada al suelo"],"mistakes":["Tirar del cuello con las manos","Usar impulso para subir","Elevar toda la espalda en vez de solo los hombros"]},"en":{"setup":"Lie on your back with knees bent and feet flat on the floor. Hands behind ears, fingers unclasped.","execution":"Curl your shoulders off the floor by contracting your abs, bringing ribs toward your pelvis. Lower back down with control without fully resting your head.","cues":["Exhale on the way up, crush an orange between ribs and hips","Don''t pull on your neck","Keep lower back pressed into the floor"],"mistakes":["Pulling the neck with hands","Using momentum to come up","Lifting the entire back instead of just the shoulders"]}}'::jsonb, true),
    ('Crunch en polea alta', 'Kneeling Cable Crunch', 1, 'weight_reps', 'cable', '{"es":{"setup":"De rodillas frente a la polea alta, sujeta la cuerda por detrás de la cabeza. Caderas fijas ligeramente detrás de las rodillas.","execution":"Flexiona el tronco hacia abajo llevando los codos hacia los muslos. Contrae el abdomen al máximo abajo y vuelve arriba de forma controlada sin dejar que el peso tire de ti.","cues":["Curva la columna, no flexiones la cadera","Los codos van hacia las rodillas, no hacia el suelo","Aprieta el abdomen abajo durante un segundo"],"mistakes":["Sentarse sobre los talones en vez de flexionar el tronco","Mover solo los brazos sin curvar la espalda","Usar demasiado peso y perder el control"]},"en":{"setup":"Kneel facing the cable machine, hold the rope behind your head. Hips fixed slightly behind your knees.","execution":"Crunch your torso down bringing elbows toward your thighs. Squeeze your abs hard at the bottom and return up with control without letting the weight pull you.","cues":["Round the spine, don''t just hip hinge","Elbows toward knees, not toward the floor","Squeeze abs at the bottom for a second"],"mistakes":["Sitting back on heels instead of crunching the torso","Moving only the arms without rounding the back","Using too much weight and losing control"]}}'::jsonb, true),
    ('Crunch en máquina de polea', 'Cable Crunch Machine', 1, 'weight_reps', 'machine', '{"es":{"setup":"Siéntate en la máquina con la espalda apoyada en el respaldo y los pies sujetos. Agarra las asas a la altura del pecho o detrás de la cabeza según el diseño.","execution":"Flexiona el tronco hacia adelante contrayendo el abdomen. Mantén la contracción un instante abajo y vuelve arriba con control.","cues":["Redondea la espalda al bajar, no empujes con los brazos","Exhala fuerte al contraer","Controla la fase de vuelta"],"mistakes":["Empujar con los brazos en vez de usar el abdomen","Ir demasiado rápido sin controlar el movimiento","No recorrer el rango completo"]},"en":{"setup":"Sit in the machine with your back against the pad and feet secured. Grip the handles at chest height or behind the head depending on the design.","execution":"Crunch your torso forward contracting your abs. Hold the contraction briefly at the bottom and return up with control.","cues":["Round the back as you crunch, don''t push with arms","Exhale hard as you contract","Control the return phase"],"mistakes":["Pushing with arms instead of using the abs","Going too fast without controlling the movement","Not using full range of motion"]}}'::jsonb, true),
    ('Crunch en máquina', 'Machine Crunch', 1, 'weight_reps', 'machine', '{"es":{"setup":"Siéntate en la máquina, ajusta la almohadilla al pecho y sujeta bien los pies. Espalda apoyada en el respaldo.","execution":"Flexiona el tronco hacia delante empujando con el abdomen contra la resistencia. Mantén la contracción abajo y regresa lentamente.","cues":["Piensa en acercar el esternón al ombligo","Exhala al bajar, inhala al subir","Movimiento lento y controlado"],"mistakes":["Usar el peso de los brazos para bajar","Rebotar abajo para subir más fácil","Arquear la espalda en la vuelta"]},"en":{"setup":"Sit in the machine, adjust the chest pad and secure your feet. Back against the backrest.","execution":"Crunch your torso forward pushing with your abs against the resistance. Hold the contraction at the bottom and return slowly.","cues":["Think about bringing your sternum toward your belly button","Exhale going down, inhale going up","Slow and controlled movement"],"mistakes":["Using arm weight to push down","Bouncing at the bottom to come up easier","Arching the back on the return"]}}'::jsonb, true),
    ('Crunch inverso', 'Reverse Crunch', 1, 'reps_only', 'bodyweight', '{"es":{"setup":"Tumbado boca arriba con brazos a los lados. Eleva las piernas con rodillas flexionadas a 90 grados.","execution":"Lleva las rodillas hacia el pecho elevando la cadera del suelo usando la fuerza abdominal. Baja de forma controlada sin dejar caer las piernas.","cues":["Despega la cadera del suelo, no solo las rodillas","Exhala al elevar, controla al bajar","Lumbar pegada al suelo en todo momento"],"mistakes":["Usar impulso balanceando las piernas","No elevar la cadera del suelo","Dejar caer las piernas de golpe"]},"en":{"setup":"Lie on your back with arms at your sides. Lift legs with knees bent at 90 degrees.","execution":"Bring knees toward your chest lifting your hips off the floor using abdominal strength. Lower with control without dropping the legs.","cues":["Peel hips off the floor, not just the knees","Exhale on the lift, control the descent","Lower back stays glued to the floor"],"mistakes":["Using momentum by swinging the legs","Not lifting the hips off the floor","Dropping legs back down uncontrolled"]}}'::jsonb, true),
    ('Crunch bicicleta', 'Bicycle Crunch', 1, 'reps_only', 'bodyweight', '{"es":{"setup":"Tumbado boca arriba, manos detrás de las orejas, piernas elevadas con rodillas a 90 grados.","execution":"Lleva el codo derecho hacia la rodilla izquierda mientras extiendes la pierna derecha. Alterna lados con un movimiento fluido de pedaleo. Mantén los hombros elevados del suelo.","cues":["Rota el torso, no solo el codo","Movimiento lento y controlado, no pedalees rápido","Hombros siempre despegados del suelo"],"mistakes":["Mover solo los codos sin rotar el tronco","Ir demasiado rápido perdiendo la contracción","Tirar del cuello con las manos"]},"en":{"setup":"Lie on your back, hands behind ears, legs raised with knees at 90 degrees.","execution":"Bring your right elbow toward your left knee while extending the right leg. Alternate sides with a fluid pedaling motion. Keep shoulders off the floor throughout.","cues":["Rotate the torso, not just the elbow","Slow and controlled, don''t pedal fast","Shoulders stay off the floor the whole time"],"mistakes":["Moving only the elbows without rotating the trunk","Going too fast and losing the contraction","Pulling on the neck with hands"]}}'::jsonb, true),
    ('Crunch con peso', 'Weighted Crunch', 1, 'weight_reps', 'bodyweight', '{"es":{"setup":"Tumbado boca arriba con rodillas flexionadas. Sujeta un disco o mancuerna contra el pecho o con brazos extendidos sobre la cabeza.","execution":"Eleva los hombros del suelo contrayendo el abdomen, manteniendo el peso fijo contra el cuerpo. Baja con control.","cues":["El peso no debe moverse respecto al cuerpo","Exhala fuerte al subir","Lumbar pegada al suelo"],"mistakes":["Usar impulso para subir con el peso","Separar los brazos cambiando la palanca a mitad de repetición","Elevar toda la espalda en vez de curvar"]},"en":{"setup":"Lie on your back with knees bent. Hold a plate or dumbbell against your chest or with arms extended overhead.","execution":"Curl your shoulders off the floor contracting your abs, keeping the weight fixed against your body. Lower with control.","cues":["Weight stays locked relative to your body","Exhale hard on the way up","Lower back stays pressed to the floor"],"mistakes":["Using momentum to come up with the weight","Moving arms and changing leverage mid-rep","Lifting the entire back instead of curling"]}}'::jsonb, true),
    ('Elevación de piernas colgado', 'Hanging Leg Raise', 1, 'reps_only', 'bodyweight', '{"es":{"setup":"Cuélgate de una barra con agarre prono a la anchura de los hombros. Brazos extendidos, cuerpo inmóvil.","execution":"Eleva las piernas rectas hasta que queden paralelas al suelo o más arriba. Baja de forma controlada sin balancearte. Para mayor activación, curva la pelvis arriba al final.","cues":["Eleva la pelvis al final del movimiento","Sin balanceo: si te balanceas, baja el ritmo","Piernas juntas y rectas"],"mistakes":["Balancearse para usar impulso","Bajar las piernas de golpe","No curvar la pelvis (solo flexionar cadera)"]},"en":{"setup":"Hang from a pull-up bar with a shoulder-width overhand grip. Arms extended, body still.","execution":"Raise your straight legs until parallel to the floor or higher. Lower with control without swinging. For more activation, curl your pelvis up at the top.","cues":["Tilt pelvis up at the top of the movement","No swinging: if you swing, slow down","Legs together and straight"],"mistakes":["Swinging to use momentum","Dropping legs down uncontrolled","Not curling the pelvis (just hip flexion)"]}}'::jsonb, true),
    ('Elevación de piernas en paralelas', 'Parallel Bar Leg Raise', 1, 'reps_only', 'barbell', '{"es":{"setup":"Apóyate en las paralelas o en la estación de dip con los antebrazos en las almohadillas y la espalda contra el respaldo.","execution":"Eleva las piernas rectas hasta la horizontal o más arriba. Baja con control. Para mayor intensidad, mantén arriba un segundo.","cues":["Espalda pegada al respaldo","No dejes caer las piernas, controla la bajada","Curva la pelvis al final para activar más"],"mistakes":["Usar impulso balanceando las piernas","Separar la espalda del respaldo","Flexionar demasiado las rodillas para hacerlo más fácil"]},"en":{"setup":"Support yourself on the parallel bars or captain''s chair with forearms on the pads and back against the backrest.","execution":"Raise your straight legs to horizontal or higher. Lower with control. For more intensity, hold at the top for a second.","cues":["Back stays against the pad","Don''t drop the legs, control the descent","Curl the pelvis at the top for more activation"],"mistakes":["Swinging legs for momentum","Pulling back away from the pad","Bending knees too much to make it easier"]}}'::jsonb, true),
    ('Elevación de piernas tumbado', 'Lying Leg Raise', 1, 'reps_only', 'bodyweight', '{"es":{"setup":"Tumbado boca arriba con las manos debajo de los glúteos o a los lados. Piernas juntas y extendidas.","execution":"Eleva las piernas juntas y rectas hasta la vertical. Baja lentamente sin que toquen el suelo y repite.","cues":["Lumbar pegada al suelo en todo momento","Baja las piernas lo más lento que puedas","Si la lumbar se despega, no bajes tanto"],"mistakes":["Arquear la zona lumbar al bajar las piernas","Dejar caer las piernas de golpe","Doblar las rodillas para facilitar el ejercicio"]},"en":{"setup":"Lie face up with hands under your glutes or at your sides. Legs together and extended.","execution":"Raise both legs together and straight up to vertical. Lower slowly without touching the floor and repeat.","cues":["Lower back stays pressed to the floor at all times","Lower legs as slowly as you can","If your lower back lifts, don''t go as low"],"mistakes":["Arching the lower back when lowering legs","Dropping legs down uncontrolled","Bending the knees to make it easier"]}}'::jsonb, true),
    ('Elevación de rodillas colgado', 'Hanging Knee Raise', 1, 'reps_only', 'bodyweight', '{"es":{"setup":"Cuélgate de una barra con agarre a la anchura de los hombros. Brazos extendidos, cuerpo recto.","execution":"Eleva las rodillas hacia el pecho flexionando las caderas y curvando la pelvis. Baja con control hasta la posición inicial sin balancearte.","cues":["Curva la pelvis hacia arriba al final","Sin balanceo: para el movimiento entre repeticiones si hace falta","Rodillas lo más arriba que puedas"],"mistakes":["Balancearse para generar impulso","Subir las rodillas solo hasta 90 grados sin curvar la pelvis","Bajar las piernas sin control"]},"en":{"setup":"Hang from a bar with shoulder-width grip. Arms extended, body straight.","execution":"Raise your knees toward your chest by flexing the hips and curling the pelvis. Lower with control to the starting position without swinging.","cues":["Curl pelvis up at the top","No swinging: pause between reps if needed","Knees as high as possible"],"mistakes":["Swinging to generate momentum","Only raising knees to 90 degrees without pelvic curl","Lowering legs without control"]}}'::jsonb, true),
    ('Plancha frontal', 'Front Plank', 1, 'time', 'bodyweight', '{"es":{"setup":"Apoya los antebrazos y las puntas de los pies en el suelo. Codos directamente debajo de los hombros.","execution":"Mantén el cuerpo en línea recta desde la cabeza hasta los talones. Contrae abdomen y glúteos durante todo el tiempo. Respira de forma constante sin dejar caer la cadera.","cues":["Aprieta glúteos y abdomen como si fueras a recibir un golpe","Cuerpo recto como una tabla: ni cadera arriba ni abajo","Empuja el suelo con los antebrazos"],"mistakes":["Dejar caer la cadera hacia el suelo","Subir la cadera en pico formando una V invertida","Aguantar la respiración"]},"en":{"setup":"Rest on your forearms and toes on the floor. Elbows directly under shoulders.","execution":"Hold your body in a straight line from head to heels. Brace abs and glutes throughout. Breathe steadily without letting your hips sag.","cues":["Squeeze glutes and abs as if bracing for a punch","Straight body like a board: no sagging or piking","Push the floor away with your forearms"],"mistakes":["Letting hips sag toward the floor","Piking hips up into an inverted V","Holding your breath"]}}'::jsonb, true),
    ('Plancha lateral', 'Side Plank', 1, 'time', 'bodyweight', '{"es":{"setup":"Apóyate sobre un antebrazo con el codo debajo del hombro. Pies apilados o uno delante del otro. Cuerpo de lado.","execution":"Eleva la cadera hasta formar una línea recta de cabeza a pies. Mantén la posición contrayendo los oblicuos. Repite del otro lado.","cues":["Cadera arriba, no dejes que se hunda","Cuerpo en un mismo plano, no te inclines adelante ni atrás","Respira de forma constante"],"mistakes":["Dejar caer la cadera hacia el suelo","Rotar el tronco hacia delante o atrás","Colocar el codo demasiado lejos del hombro"]},"en":{"setup":"Support yourself on one forearm with elbow under shoulder. Feet stacked or staggered. Body sideways.","execution":"Raise your hips to form a straight line from head to feet. Hold the position by bracing your obliques. Repeat on the other side.","cues":["Hips up, don''t let them sag","Body in one plane, don''t lean forward or back","Breathe steadily"],"mistakes":["Letting hips drop toward the floor","Rotating torso forward or backward","Placing elbow too far from shoulder"]}}'::jsonb, true),
    ('Plancha con peso', 'Weighted Plank', 1, 'weight_time', 'bodyweight', '{"es":{"setup":"Posición de plancha frontal con un disco o peso colocado en la zona media de la espalda. Pide a alguien que te lo coloque o deslízalo desde un banco.","execution":"Mantén el cuerpo en línea recta con abdomen y glúteos contraídos. El peso debe quedar estable en la espalda. Respira de forma constante.","cues":["Mismas claves que la plancha normal: línea recta, glúteos apretados","No dejes que el peso te hunda la cadera","Empieza con poco peso y progresa gradualmente"],"mistakes":["Dejar caer la cadera por el peso extra","Colocar el peso demasiado arriba (zona cervical) o abajo (lumbar)","Usar demasiado peso y perder la posición"]},"en":{"setup":"Front plank position with a plate or weight placed on your mid-back. Have someone place it or slide it from a bench.","execution":"Hold your body in a straight line with abs and glutes braced. The weight should stay stable on your back. Breathe steadily.","cues":["Same cues as regular plank: straight line, glutes tight","Don''t let the weight make your hips sag","Start light and progress gradually"],"mistakes":["Letting hips sag due to the extra weight","Placing weight too high (neck area) or too low (lower back)","Using too much weight and losing position"]}}'::jsonb, true),
    ('Rueda abdominal', 'Ab Wheel Rollout', 1, 'reps_only', 'bodyweight', '{"es":{"setup":"De rodillas sobre una colchoneta, sujeta la rueda abdominal con ambas manos en el suelo frente a ti.","execution":"Rueda hacia delante extendiendo el cuerpo lo más lejos que puedas manteniendo el core activo. Tira con el abdomen para volver a la posición inicial. No dejes que la cadera se hunda.","cues":["Aprieta el abdomen ANTES de empezar a rodar","Curva ligeramente la pelvis (retroversión) durante todo el movimiento","Ve solo tan lejos como puedas volver con control"],"mistakes":["Dejar que la cadera se hunda y arquear la lumbar","Extenderse demasiado y no poder volver","Tirar con los brazos en vez de con el abdomen"]},"en":{"setup":"Kneel on a mat, grip the ab wheel with both hands on the floor in front of you.","execution":"Roll forward extending your body as far as you can while keeping your core braced. Pull back to the starting position using your abs. Don''t let hips sag.","cues":["Brace your abs BEFORE you start rolling","Slight posterior pelvic tilt throughout the movement","Only go as far as you can return with control"],"mistakes":["Letting hips sag and arching the lower back","Extending too far and collapsing","Pulling back with arms instead of abs"]}}'::jsonb, true),
    ('Leñador en polea alta', 'High Cable Woodchop', 1, 'weight_reps', 'cable', '{"es":{"setup":"De pie de lado a la polea alta, pies a la anchura de los hombros. Sujeta el asa con ambas manos con los brazos extendidos arriba hacia la polea.","execution":"Tira del cable en diagonal hacia abajo y al lado opuesto rotando el tronco. Los brazos se mantienen extendidos y la fuerza viene de la rotación del core. Vuelve arriba con control.","cues":["Rota desde el tronco, no desde los brazos","Caderas miran al frente, solo rota el torso","Brazos extendidos como una palanca larga"],"mistakes":["Rotar las caderas en vez del tronco","Flexionar y extender los brazos tirando con ellos","Usar demasiado peso y perder el control de la rotación"]},"en":{"setup":"Stand sideways to a high cable, feet shoulder-width apart. Grip the handle with both hands with arms extended up toward the pulley.","execution":"Pull the cable diagonally down and across your body by rotating your trunk. Arms stay extended and the force comes from core rotation. Return up with control.","cues":["Rotate from the trunk, not the arms","Hips face forward, only rotate the torso","Arms extended like a long lever"],"mistakes":["Rotating the hips instead of the trunk","Bending and extending the arms to pull","Using too much weight and losing rotation control"]}}'::jsonb, true),
    ('Leñador en polea baja', 'Low Cable Woodchop', 1, 'weight_reps', 'cable', '{"es":{"setup":"De pie de lado a la polea baja, pies a la anchura de los hombros. Sujeta el asa con ambas manos abajo hacia la polea.","execution":"Tira del cable en diagonal hacia arriba y al lado opuesto rotando el tronco. Los brazos se mantienen extendidos. Vuelve abajo con control.","cues":["La fuerza sale del core, los brazos solo transmiten","Caderas estables mirando al frente","Controla la vuelta abajo, no dejes que el peso te arrastre"],"mistakes":["Rotar las caderas junto con el tronco","Tirar con los brazos flexionándolos","Dejar que el peso te arrastre de vuelta sin control"]},"en":{"setup":"Stand sideways to a low cable, feet shoulder-width apart. Grip the handle with both hands down toward the pulley.","execution":"Pull the cable diagonally up and across your body by rotating your trunk. Arms stay extended. Return down with control.","cues":["Force comes from the core, arms just transmit","Hips stay stable facing forward","Control the return, don''t let the weight pull you back"],"mistakes":["Rotating hips along with the trunk","Pulling with bent arms","Letting the weight yank you back without control"]}}'::jsonb, true),
    ('Giro ruso con peso', 'Weighted Russian Twist', 1, 'weight_reps', 'plate', '{"es":{"setup":"Sentado en el suelo con rodillas flexionadas y pies ligeramente elevados. Inclina el tronco hacia atrás unos 45 grados. Sujeta un disco o mancuerna con ambas manos frente al pecho.","execution":"Rota el tronco llevando el peso hacia un lado y luego al otro. Cada giro completo (izquierda-derecha) es una repetición. Mantén el pecho alto.","cues":["Rota el torso completo, no solo los brazos","Pecho alto y espalda recta","Movimiento controlado, sin prisa"],"mistakes":["Mover solo los brazos sin rotar el tronco","Redondear la espalda perdiendo la posición","Ir demasiado rápido perdiendo el control"]},"en":{"setup":"Sit on the floor with knees bent and feet slightly elevated. Lean torso back about 45 degrees. Hold a plate or dumbbell with both hands in front of your chest.","execution":"Rotate your torso bringing the weight to one side then the other. Each full twist (left-right) counts as one rep. Keep your chest up.","cues":["Rotate the whole torso, not just the arms","Chest up and back straight","Controlled movement, no rushing"],"mistakes":["Moving only the arms without rotating the trunk","Rounding the back and losing position","Going too fast and losing control"]}}'::jsonb, true),
    ('Pallof press en polea', 'Cable Pallof Press', 1, 'weight_reps', 'cable', '{"es":{"setup":"De pie de lado a la polea a la altura del pecho. Sujeta el asa con ambas manos pegadas al esternón. Pies a la anchura de los hombros.","execution":"Extiende los brazos al frente empujando el asa lejos del pecho. Mantén un instante con los brazos extendidos resistiendo la rotación. Vuelve al pecho y repite.","cues":["Resiste la rotación: el tronco NO se mueve","Aprieta el core al extender los brazos","Brazos a la altura del pecho, no arriba ni abajo"],"mistakes":["Permitir que el cable rote el tronco","No extender los brazos completamente","Estar demasiado cerca de la polea (poca tensión)"]},"en":{"setup":"Stand sideways to a cable set at chest height. Hold the handle with both hands against your sternum. Feet shoulder-width apart.","execution":"Extend your arms forward pushing the handle away from your chest. Hold briefly with arms extended resisting the rotation. Return to chest and repeat.","cues":["Resist the rotation: your trunk does NOT move","Brace the core as you extend your arms","Arms at chest height, not up or down"],"mistakes":["Allowing the cable to rotate your trunk","Not fully extending the arms","Standing too close to the cable (not enough tension)"]}}'::jsonb, true),
    ('Sit-up', 'Sit-Up', 1, 'reps_only', 'bodyweight', '{"es":{"setup":"Tumbado boca arriba con rodillas flexionadas y pies apoyados en el suelo (o sujetos). Brazos cruzados sobre el pecho o manos detrás de las orejas.","execution":"Eleva todo el torso hasta quedar sentado. Baja de forma controlada hasta apoyar completamente la espalda.","cues":["Inicia con el abdomen, no tirando del cuello","Exhala al subir, inhala al bajar","Movimiento fluido sin tirones"],"mistakes":["Tirar del cuello con las manos","Usar el impulso rebotando en el suelo","Arquear excesivamente la lumbar al bajar"]},"en":{"setup":"Lie face up with knees bent and feet on the floor (or anchored). Arms crossed over chest or hands behind ears.","execution":"Lift your entire torso up until seated. Lower back down with control until your back is fully on the floor.","cues":["Initiate with your abs, not by pulling the neck","Exhale going up, inhale going down","Fluid movement without jerking"],"mistakes":["Pulling the neck with hands","Using momentum by bouncing off the floor","Excessively arching the lower back on the descent"]}}'::jsonb, true),
    ('Sit-up con peso', 'Weighted Sit-Up', 1, 'weight_reps', 'bodyweight', '{"es":{"setup":"Tumbado boca arriba con rodillas flexionadas y pies sujetos. Sujeta un disco contra el pecho o por encima de la cabeza con brazos extendidos.","execution":"Eleva todo el torso hasta quedar sentado manteniendo el peso fijo. Baja con control. El peso por encima de la cabeza es más difícil que contra el pecho.","cues":["El peso no se mueve respecto al cuerpo","Exhala fuerte al subir","Controla la bajada, no te dejes caer"],"mistakes":["Dejar que el peso caiga hacia delante al subir","Usar impulso para completar la repetición","Redondear excesivamente la espalda"]},"en":{"setup":"Lie face up with knees bent and feet anchored. Hold a plate against your chest or overhead with arms extended.","execution":"Lift your entire torso up to seated while keeping the weight fixed. Lower with control. Overhead is harder than chest position.","cues":["Weight stays locked relative to your body","Exhale hard on the way up","Control the descent, don''t just drop"],"mistakes":["Letting the weight fall forward on the way up","Using momentum to complete the rep","Excessively rounding the back"]}}'::jsonb, true),
    ('V-up', 'V-Up', 1, 'reps_only', 'bodyweight', '{"es":{"setup":"Tumbado boca arriba con piernas extendidas y brazos extendidos por encima de la cabeza.","execution":"Eleva simultáneamente las piernas rectas y el tronco, intentando tocar los pies con las manos formando una V. Baja con control a la posición inicial.","cues":["Piernas y tronco suben a la vez","Intenta tocar las puntas de los pies","Baja lento, no te dejes caer"],"mistakes":["Doblar las rodillas para llegar a los pies","Redondear excesivamente la espalda","Dejar caer el cuerpo de golpe al bajar"]},"en":{"setup":"Lie face up with legs extended and arms extended overhead.","execution":"Simultaneously raise your straight legs and torso, reaching your hands toward your feet to form a V shape. Lower back down with control.","cues":["Legs and torso rise together","Try to touch your toes","Lower slowly, don''t just drop"],"mistakes":["Bending knees to reach the feet","Excessively rounding the back","Dropping the body uncontrolled on the way down"]}}'::jsonb, true),
    ('Mountain climbers', 'Mountain Climbers', 1, 'reps_only', 'bodyweight', '{"es":{"setup":"En posición de flexión de brazos (push-up) con brazos extendidos, manos debajo de los hombros. Cuerpo en línea recta.","execution":"Lleva una rodilla hacia el pecho de forma explosiva y alterna rápidamente con la otra pierna como si corrieras en el sitio. Mantén las caderas a la misma altura.","cues":["Caderas bajas y estables, no subas el trasero","Rodilla lo más cerca del pecho posible","Manos firmes empujando el suelo"],"mistakes":["Subir las caderas en pico","No llevar las rodillas lo suficientemente cerca del pecho","Rebotar en los pies sin activar el core"]},"en":{"setup":"Start in a push-up position with arms extended, hands under shoulders. Body in a straight line.","execution":"Drive one knee toward your chest explosively and quickly alternate with the other leg as if running in place. Keep hips level throughout.","cues":["Hips low and stable, don''t pike up","Knee as close to chest as possible","Hands firm, pushing the floor away"],"mistakes":["Piking the hips up","Not driving knees close enough to the chest","Bouncing on feet without engaging the core"]}}'::jsonb, true),
    ('Dragon flag', 'Dragon Flag', 1, 'reps_only', 'bodyweight', '{"es":{"setup":"Tumbado en un banco, agarra el borde por detrás de la cabeza con ambas manos. Solo los hombros y la parte alta de la espalda tocan el banco.","execution":"Con el cuerpo rígido como una tabla, baja lentamente desde la vertical hasta casi tocar el banco. Sube de nuevo con el core activado. Solo los omóplatos mantienen contacto con el banco.","cues":["Cuerpo recto como una tabla desde hombros a pies","Baja tan lento como puedas","Si no puedes recto, flexiona ligeramente las rodillas para progresar"],"mistakes":["Dejar caer la cadera rompiendo la línea del cuerpo","Bajar demasiado rápido sin control","Doblar excesivamente por la cadera"]},"en":{"setup":"Lie on a bench, grab the edge behind your head with both hands. Only shoulders and upper back touch the bench.","execution":"With your body rigid like a board, lower slowly from vertical until nearly touching the bench. Raise back up with core engaged. Only shoulder blades maintain bench contact.","cues":["Body straight like a board from shoulders to feet","Lower as slowly as you can","If you can''t go straight, slightly bend knees to progress"],"mistakes":["Letting hips drop and breaking the body line","Lowering too fast without control","Excessive bending at the hips"]}}'::jsonb, true),
    ('Hollow hold', 'Hollow Hold', 1, 'time', 'bodyweight', '{"es":{"setup":"Tumbado boca arriba con brazos extendidos por encima de la cabeza y piernas juntas extendidas.","execution":"Eleva ligeramente los brazos, la cabeza, los hombros y las piernas del suelo. Mantén la zona lumbar completamente pegada al suelo formando una C con el cuerpo. Aguanta la posición.","cues":["Lumbar pegada al suelo: es la clave de todo el ejercicio","Aprieta el abdomen como si te fueran a golpear","Si pierdes la posición, eleva más las piernas"],"mistakes":["Despegar la lumbar del suelo (signo de que las piernas están demasiado bajas)","Aguantar la respiración","Elevar demasiado piernas o brazos (reduce la dificultad)"]},"en":{"setup":"Lie face up with arms extended overhead and legs together extended.","execution":"Slightly lift arms, head, shoulders, and legs off the floor. Keep lower back completely pressed to the floor forming a C-shape with your body. Hold the position.","cues":["Lower back glued to the floor: this is the key to the whole exercise","Brace abs as if about to take a punch","If you lose position, raise legs higher"],"mistakes":["Lower back coming off the floor (sign legs are too low)","Holding your breath","Raising legs or arms too high (reduces difficulty)"]}}'::jsonb, true),
    ('Dead bug', 'Dead Bug', 1, 'reps_only', 'bodyweight', '{"es":{"setup":"Tumbado boca arriba con brazos extendidos hacia el techo y rodillas flexionadas a 90 grados (espinillas paralelas al suelo).","execution":"Extiende simultáneamente un brazo hacia atrás y la pierna opuesta hacia delante, bajándolos hasta casi tocar el suelo. Vuelve al centro y repite con el otro lado.","cues":["Lumbar pegada al suelo en TODO momento","Exhala al extender, inhala al volver","Movimiento lento y controlado"],"mistakes":["Despegar la zona lumbar del suelo","Mover brazo y pierna del mismo lado en vez de opuestos","Ir demasiado rápido perdiendo la estabilidad"]},"en":{"setup":"Lie face up with arms extended toward the ceiling and knees bent at 90 degrees (shins parallel to the floor).","execution":"Simultaneously extend one arm back and the opposite leg forward, lowering them until just above the floor. Return to center and repeat on the other side.","cues":["Lower back pressed to the floor at ALL times","Exhale as you extend, inhale as you return","Slow and controlled movement"],"mistakes":["Lower back coming off the floor","Moving same-side arm and leg instead of opposites","Going too fast and losing stability"]}}'::jsonb, true),
    ('Perro-pájaro', 'Bird Dog', 1, 'reps_only', 'bodyweight', '{"es":{"setup":"En cuadrupedia: manos debajo de los hombros, rodillas debajo de las caderas. Espalda neutra.","execution":"Extiende simultáneamente un brazo hacia delante y la pierna opuesta hacia atrás hasta que queden paralelos al suelo. Mantén un segundo y vuelve. Alterna lados.","cues":["Sin rotación de cadera: imagina un vaso de agua en la lumbar","Extiende hasta la horizontal, no más arriba","Movimiento lento y deliberado"],"mistakes":["Rotar las caderas al extender la pierna","Arquear la espalda baja","Mover brazo y pierna del mismo lado"]},"en":{"setup":"On all fours: hands under shoulders, knees under hips. Neutral spine.","execution":"Simultaneously extend one arm forward and the opposite leg back until parallel to the floor. Hold for a second and return. Alternate sides.","cues":["No hip rotation: imagine a glass of water on your lower back","Extend to horizontal, not higher","Slow and deliberate movement"],"mistakes":["Rotating hips when extending the leg","Arching the lower back","Moving same-side arm and leg"]}}'::jsonb, true),
    ('Encogimientos en banco declinado', 'Decline Bench Crunch', 1, 'reps_only', 'bodyweight', '{"es":{"setup":"Tumbado en un banco declinado con los pies sujetos en los rodillos. Manos cruzadas sobre el pecho o detrás de las orejas.","execution":"Eleva el torso contrayendo el abdomen hasta que el tronco quede aproximadamente vertical. Baja con control sin dejarte caer.","cues":["Curva la espalda al subir, no subas con la espalda recta","Exhala al subir, no aguantes la respiración","Controla especialmente la bajada"],"mistakes":["Subir con la espalda recta usando los flexores de cadera","Usar impulso rebotando abajo","Tirar del cuello con las manos"]},"en":{"setup":"Lie on a decline bench with feet secured under the rollers. Hands crossed over chest or behind ears.","execution":"Curl your torso up contracting your abs until roughly vertical. Lower with control without dropping.","cues":["Round your back as you come up, don''t rise with a flat back","Exhale on the way up, don''t hold your breath","Control the descent especially"],"mistakes":["Rising with a flat back using hip flexors","Using momentum by bouncing at the bottom","Pulling on the neck with hands"]}}'::jsonb, true),
    ('L-sit', 'L-Sit', 1, 'time', 'bodyweight', '{"es":{"setup":"Apóyate en paralelas, anillas o el suelo con las manos a los lados de las caderas. Brazos completamente extendidos.","execution":"Eleva las piernas extendidas hasta que queden paralelas al suelo formando una L con el cuerpo. Mantén la posición con los brazos bloqueados y el core contraído.","cues":["Piernas rectas y juntas, puntas de los pies hacia fuera","Empuja fuerte con las manos para mantener los hombros abajo","Si no puedes con piernas rectas, empieza con rodillas flexionadas"],"mistakes":["Flexionar las rodillas para hacer trampa","Dejar que los hombros suban hacia las orejas","Inclinar el tronco hacia atrás en exceso"]},"en":{"setup":"Support yourself on parallettes, rings, or the floor with hands beside your hips. Arms fully extended.","execution":"Raise your extended legs until parallel to the floor forming an L-shape. Hold the position with arms locked and core braced.","cues":["Legs straight and together, toes pointed","Push hard with hands to keep shoulders down","If you can''t go straight-legged, start with bent knees"],"mistakes":["Bending knees to cheat","Letting shoulders shrug up toward ears","Leaning the torso too far back"]}}'::jsonb, true),
    ('Toes to bar', 'Toes to Bar', 1, 'reps_only', 'bodyweight', '{"es":{"setup":"Cuélgate de una barra con agarre prono a la anchura de los hombros. Brazos extendidos, cuerpo inmóvil.","execution":"Eleva las piernas rectas hasta tocar la barra con los pies. Baja de forma controlada. Requiere fuerza abdominal y flexibilidad de isquiotibiales.","cues":["Activa los dorsales al inicio para estabilizar el cuerpo","Piernas rectas: lleva los pies a la barra","Controla la bajada para evitar balanceo"],"mistakes":["Usar kipping excesivo en vez de fuerza estricta","Bajar las piernas sin control y balancearse","Doblar las rodillas en vez de mantener piernas rectas"]},"en":{"setup":"Hang from a bar with shoulder-width overhand grip. Arms extended, body still.","execution":"Raise your straight legs until your feet touch the bar. Lower with control. Requires abdominal strength and hamstring flexibility.","cues":["Engage lats at the start to stabilize your body","Straight legs: bring feet to the bar","Control the descent to avoid swinging"],"mistakes":["Excessive kipping instead of strict strength","Dropping legs without control and swinging","Bending knees instead of keeping legs straight"]}}'::jsonb, true),
    ('Oblicuos en polea', 'Cable Oblique Twist', 1, 'weight_reps', 'cable', '{"es":{"setup":"De pie de lado a la polea a la altura del pecho. Sujeta el asa con ambas manos y brazos extendidos frente a ti. Pies a la anchura de los hombros.","execution":"Rota el tronco alejándote de la polea manteniendo los brazos extendidos. Vuelve de forma controlada. Los brazos no se flexionan, toda la fuerza viene de la rotación del core.","cues":["Brazos extendidos y fijos: rota el torso, no los brazos","Caderas estables mirando al frente","Controla la vuelta, no dejes que el peso te arrastre"],"mistakes":["Flexionar los brazos y tirar con ellos","Rotar las caderas junto con el tronco","Usar demasiado peso perdiendo el control de la rotación"]},"en":{"setup":"Stand sideways to a cable at chest height. Hold the handle with both hands and arms extended in front of you. Feet shoulder-width apart.","execution":"Rotate your trunk away from the cable keeping arms extended. Return with control. Arms don''t bend, all force comes from core rotation.","cues":["Arms extended and fixed: rotate the torso, not the arms","Hips stable facing forward","Control the return, don''t let the weight pull you back"],"mistakes":["Bending arms and pulling with them","Rotating hips along with the trunk","Using too much weight and losing rotation control"]}}'::jsonb, true),
    ('Crunch lateral con mancuerna', 'Dumbbell Side Crunch', 1, 'weight_reps', 'dumbbell', '{"es":{"setup":"De pie con una mancuerna en una mano y el brazo extendido a lo largo del cuerpo. El otro brazo detrás de la cabeza o en la cadera.","execution":"Inclina el tronco hacia el lado de la mancuerna dejando que baje por la pierna. Vuelve a la posición vertical contrayendo el oblicuo del lado opuesto. Completa todas las repeticiones de un lado antes de cambiar.","cues":["Movimiento estrictamente lateral, no te inclines adelante ni atrás","Contrae el oblicuo opuesto para volver arriba","Movimiento controlado y lento"],"mistakes":["Inclinarse hacia delante o atrás en vez de lateralmente","Usar demasiado peso y perder el plano lateral","Mover las caderas en vez de flexionar solo el tronco"]},"en":{"setup":"Stand holding a dumbbell in one hand with arm extended along your body. Other arm behind your head or on your hip.","execution":"Lean your torso toward the dumbbell side letting it slide down your leg. Return to vertical by contracting the opposite oblique. Complete all reps on one side before switching.","cues":["Strictly lateral movement, don''t lean forward or back","Contract the opposite oblique to return up","Controlled and slow movement"],"mistakes":["Leaning forward or backward instead of laterally","Using too much weight and losing the lateral plane","Moving hips instead of only flexing the trunk"]}}'::jsonb, true);

