    ('Side Plank', 'Glúteos'),
    ('Weighted Plank', 'Hombros'),
    ('Weighted Plank', 'Glúteos'),
    ('Ab Wheel Rollout', 'Hombros'),
    ('Ab Wheel Rollout', 'Espalda'),
    ('High Cable Woodchop', 'Hombros'),
    ('Low Cable Woodchop', 'Hombros'),
    ('Cable Pallof Press', 'Hombros'),
    ('Mountain Climbers', 'Hombros'),
    ('Mountain Climbers', 'Cuádriceps'),
    ('Dragon Flag', 'Espalda'),
    ('Bird Dog', 'Glúteos'),
    ('Bird Dog', 'Espalda'),
    ('L-Sit', 'Cuádriceps'),
    ('Toes to Bar', 'Antebrazo')
) AS v(exercise_name, muscle_group_name)
JOIN exercises e ON e.name_en = v.exercise_name AND e.is_system = true
JOIN muscle_groups mg ON mg.name = v.muscle_group_name;